function togglePayCard(pid) {
  const detail = document.getElementById('pay-detail-'+pid);
  const chevron = document.getElementById('pay-chevron-'+pid);
  if(!detail) return;
  const open = detail.style.display !== 'none';
  detail.style.display = open ? 'none' : 'block';
  if(chevron) chevron.innerHTML = open ? '&#8964;' : '&#8963;';
}

function collectPayment(reqId, pid) {
  // Set mode from UI selector, then delegate to markPaid
  const modeEl = document.getElementById('pay-mode-'+pid);
  const mode = modeEl ? modeEl.value : 'Cash';
  const req = PAY_REQUESTS.find(r=>r.id===reqId);
  if(req) req.mode = mode;
  if (req && isInsuranceLikeMode(mode)) {
    req.mode = 'Insurance/TPA';
    req.ins = req.ins || 'Insurance/TPA';
    req.status = 'pending';
    req.claimedAmount = Math.max(Number(req.claimedAmount || 0), Number(req.amount || 0));
    req.approvedAmount = Math.max(Number(req.approvedAmount || 0), Number(req.amount || 0));
    req.cashlessApprovedAmount = Math.max(Number(req.cashlessApprovedAmount || 0), Number(req.amount || 0));
    req.updatedAt = new Date().toISOString();
    fbUpdate && fbUpdate('payRequests/' + req.id, {
      mode: req.mode,
      ins: req.ins,
      status: 'pending',
      claimedAmount: req.claimedAmount,
      approvedAmount: req.approvedAmount,
      cashlessApprovedAmount: req.cashlessApprovedAmount,
      updatedAt: req.updatedAt
    }).catch(function(){});
    showToast('TPA / cashless claim moved to the TPA module ✓', 's');
    renderReceptionPage && renderReceptionPage();
    renderTpaPage && renderTpaPage();
    renderDashboard && renderDashboard();
    renderBillingPageIfActive && renderBillingPageIfActive();
    return;
  }
  markPaid(reqId);
  // After small delay, offer receipt
  setTimeout(()=>{
    if(req && confirm(`✅ ₹${req.amount.toLocaleString('en-IN')} collected from ${req.patient}\n\nPrint receipt?`)) {
      printPaymentReceipt(req);
    }
  }, 300);
}

function cancelPayReq(reqId) {
  const idx = PAY_REQUESTS.findIndex(r=>r.id===reqId);
  if(idx>-1) PAY_REQUESTS.splice(idx,1);
  showToast('Pay request cancelled','i');
  renderReceptionPage();
}

function getSavedHospitalSettings() {
  try {
    const raw = JSON.parse(localStorage.getItem('bmh_hospital_settings') || '{}') || {};
    // New format: { values: {...}, _savedAt: ... }; old format: flat key-value map
    return raw.values || raw;
  } catch (e) {
    return {};
  }
}
function getHospitalDetailValue(label, fallback) {
  const settings = getSavedHospitalSettings();
  return String(settings[label] || fallback || '').trim();
}
function bmhAmountToWords(num) {
  const n = Math.round(Math.max(0, Number(num) || 0));
  if (!n) return 'Zero Rupees Only';
  const ones = ['', 'One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven', 'Eight', 'Nine', 'Ten', 'Eleven', 'Twelve', 'Thirteen', 'Fourteen', 'Fifteen', 'Sixteen', 'Seventeen', 'Eighteen', 'Nineteen'];
  const tens = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety'];
  const twoDigits = function (x) {
    x = Number(x) || 0;
    if (x < 20) return ones[x];
    return (tens[Math.floor(x / 10)] + (x % 10 ? ' ' + ones[x % 10] : '')).trim();
  };
  const threeDigits = function (x) {
    x = Number(x) || 0;
    const hundred = Math.floor(x / 100);
    const rem = x % 100;
    return [hundred ? ones[hundred] + ' Hundred' : '', rem ? twoDigits(rem) : ''].filter(Boolean).join(' ').trim();
  };
  let value = n;
  const crore = Math.floor(value / 10000000); value %= 10000000;
  const lakh = Math.floor(value / 100000); value %= 100000;
  const thousand = Math.floor(value / 1000); value %= 1000;
  const hundred = value;
  const parts = [];
  if (crore) parts.push(twoDigits(crore) + ' Crore');
  if (lakh) parts.push(twoDigits(lakh) + ' Lakh');
  if (thousand) parts.push(twoDigits(thousand) + ' Thousand');
  if (hundred) parts.push(threeDigits(hundred));
  return parts.join(' ').replace(/\s+/g, ' ').trim() + ' Rupees Only';
}
function buildRelationPrintText(pt) {
  return String(pt?.relation || pt?.rel || '').trim();
}
