function ipdMonitoringSlots(freqKey, fromIso) {
  const hours = { '1h':1, '2h':2, '4h':4, '6h':6 }[freqKey] || 6;
  const start = new Date(fromIso || Date.now());
  const slots = [];
  for (let i = 0; i < Math.max(4, Math.floor(24 / hours)); i += 1) {
    const due = new Date(start.getTime() + (hours * (i + 1) * 60 * 60 * 1000));
    slots.push({ id:'slot-' + i + '-' + due.getTime(), dueAt: due.toISOString(), recordedAt:'', status:'pending' });
  }
  return slots;
}
function ipdDeptTemplate(deptKey, context) {
  const ctx = context || {};
  const typeText = String(ctx.type || ctx.admissionType || '').toLowerCase();
  const surgText = String(ctx.surgery || ctx.procedure || '').toLowerCase();
  const row = function(label, options, placeholder) {
    return { label, value:'', checked:false, options: Array.isArray(options) ? options : null, placeholder: placeholder || '' };
  };
  const map = {
    ophtho:[
      row('Baseline BP / pulse / sugar reviewed', ['Normal', 'High BP', 'Low sugar', 'Abnormal - review doctor'], 'Observation'),
      row('Investigations / fitness complete', ['Complete', 'Pending', 'Abnormal - review before OT'], 'Remark'),
      row('Consent signed / file complete', ['Done', 'Pending', 'Relative counselled'], 'Remark'),
      row('Eye marked and confirmed', ['Right eye marked', 'Left eye marked', 'Both eyes confirmed', 'Pending'], 'Remark'),
      row('Dilating drops given', ['Not needed', '1 cycle done', '2 cycles done', '3 cycles done', 'Pending'], 'Drug / timing'),
      row('Antibiotic / NSAID drops given', ['Given', 'Not yet', 'Not advised'], 'Drug / timing'),
      row('IOL / implant verified', ['Verified', 'Pending', 'Mismatch - alert doctor'], 'Model / power'),
      row('Test dose / allergy check', ['Not required', 'Done', 'Reaction noted'], 'Remark'),
      row('NBM / escort / OT checklist', ['Complete', 'Pending', 'Escort absent'], 'Remark'),
      row('Post-op patch / shield / pain', ['Comfortable', 'Mild pain', 'Severe pain - review'], 'Patch / pain'),
      row('Post-op drops and red flags explained', ['Explained', 'Pending'], 'Remark'),
      row('Discharge timing / review explained', ['Explained', 'Pending'], 'Next review')
    ],
    psych:[row('Mood / behaviour', null, 'Observation'),row('Sleep', null, 'Observation'),row('Medication compliance', ['Good', 'Partial', 'Poor'], 'Remark'),row('Risk / supervision', ['Low', 'Moderate', 'High'], 'Remark'),row('Doctor instructions', null, 'Instruction')],
    skin:[row('Rash / lesion change', null, 'Observation'),row('Itching / pain', ['Better', 'Same', 'Worse'], 'Remark'),row('Dressing / topical therapy', ['Done', 'Pending'], 'Remark'),row('Drug reaction watch', ['No reaction', 'Mild reaction', 'Urgent review'], 'Remark'),row('Doctor instructions', null, 'Instruction')],
    general:[row('Pain / comfort', ['Comfortable', 'Mild pain', 'Severe pain'], 'Remark'),row('Fluids / diet', ['Taking orally', 'IV fluids', 'NBM'], 'Remark'),row('Urine / stool', ['Normal', 'Reduced', 'Absent', 'Needs review'], 'Remark'),row('Mobility / fall risk', ['Walking', 'Assisted', 'Bed rest'], 'Remark'),row('Doctor instructions', null, 'Instruction')]
  };
  let labels = map[deptKey] || map.general;
  if (deptKey === 'obg') {
    if (/normal delivery|assisted delivery|labour room|maternity/.test(typeText + ' ' + surgText)) {
      labels = [
        row('Baseline BP / pulse / FHR', ['Stable', 'High BP', 'FHR concern', 'Urgent review'], 'Vitals / FHR'),
        row('Hb / blood group / investigations reviewed', ['Complete', 'Pending', 'Abnormal - alert doctor'], 'Remark'),
        row('Labour consent / labour room checklist', ['Done', 'Pending'], 'Remark'),
        row('IV line / hydration / bladder care', ['Done', 'Ongoing', 'Needs review'], 'Remark'),
        row('Labour progress / contraction charting', ['Progressing', 'Slow progress', 'Needs doctor review'], 'Remark'),
        row('Liquor / membranes / bleeding monitored', ['Normal', 'Meconium', 'Heavy bleeding', 'Leakage'], 'Remark'),
        row('Delivery details / placenta / PPH watch', ['Normal', 'PPH watch', 'PPH suspected', 'Retained placenta concern'], 'Remark'),
        row('Baby status / APGAR / cry / NICU need', ['Baby well', 'Poor cry', 'NICU review', 'Needs paediatrician'], 'Remark'),
        row('Breastfeeding initiation / newborn advice', ['Started', 'Counselled', 'Difficulty feeding'], 'Remark'),
        row('Postnatal monitoring / danger signs', ['Stable', 'Need close watch', 'Urgent review'], 'Remark')
      ];
    } else if (/mtp|suction|evac|painless abortion/.test(typeText + ' ' + surgText)) {
      labels = [
        row('Vitals / pain score', ['Stable', 'Pain controlled', 'Heavy pain / review'], 'Remark'),
        row('Consent / Rh status / investigations reviewed', ['Complete', 'Pending', 'Abnormal - review'], 'Remark'),
        row('IV line / sedation / anaesthesia clearance', ['Done', 'Pending'], 'Remark'),
        row('Procedure checklist complete', ['Complete', 'Pending'], 'Remark'),
        row('Bleeding / cramps monitored', ['Mild', 'Moderate', 'Heavy bleeding', 'Urgent review'], 'Remark'),
        row('Products complete / specimen noted', ['Complete', 'Sent', 'Review needed'], 'Remark'),
        row('Antibiotics / analgesia given', ['Given', 'Pending'], 'Drugs'),
        row('Contraception counselling', ['Done', 'Deferred'], 'Plan'),
        row('Warning signs explained', ['Explained', 'Pending'], 'Remark'),
        row('Follow-up date given', ['Given', 'Pending'], 'Date / note')
      ];
    } else {
      labels = [
        row('BP / pulse / fetal status', ['Stable', 'High BP', 'Fetal concern', 'Urgent review'], 'Remark'),
        row('Hb / blood group / investigations reviewed', ['Complete', 'Pending', 'Abnormal - alert doctor'], 'Remark'),
        row('Consent / anaesthesia / blood arranged', ['Complete', 'Blood pending', 'Anaesthesia review pending'], 'Remark'),
        row('Shaving / catheter / NBM complete', ['Done', 'Partially done', 'Pending'], 'Remark'),
        row('OT checklist / prophylaxis complete', ['Complete', 'Pending'], 'Remark'),
        row('Bleeding / lochia monitored', ['Normal', 'Moderate', 'Heavy bleeding', 'Urgent review'], 'Remark'),
        row('Uterine tone / fundal height', ['Well contracted', 'Needs monitoring', 'Atony concern'], 'Remark'),
        row('Urine output / bowel sounds', ['Normal', 'Low output', 'Catheter issue', 'Needs review'], 'Remark'),
        row('Baby status / breastfeeding', ['Baby well', 'Feeding started', 'NICU review', 'Feeding issue'], 'Remark'),
        row('IV fluids / antibiotics / analgesia', ['Given as advised', 'Partially given', 'Pending'], 'Drugs / timing'),
        row('LSCS wound / dressing / mobilisation', ['Clean', 'Oozing', 'Painful', 'Review wound'], 'Remark'),
        row('Bathing / hygiene / discharge advice', ['Counselled', 'Pending', 'Needs repeat explanation'], 'Remark')
      ];
    }
  }
  return labels.map(function (item) {
    return typeof item === 'string' ? row(item, null, 'Remark') : item;
  });
}
window.PATIENT_VISIT_CACHE = window.PATIENT_VISIT_CACHE || {};
function cachePatientVisits(bmhId, visitsObj) {
  if(!bmhId) return {};
  const safe = visitsObj && typeof visitsObj === 'object' ? JSON.parse(JSON.stringify(visitsObj)) : {};
  window.PATIENT_VISIT_CACHE[bmhId] = safe;
  return safe;
}
function getCachedPatientVisits(bmhId) {
  return (window.PATIENT_VISIT_CACHE && window.PATIENT_VISIT_CACHE[bmhId]) || {};
}
function loadPatientVisitsForRail(bmhId, dept, onReady) {
  const cached = getCachedPatientVisits(bmhId);
  const hasCached = cached && Object.keys(cached).length;
  const deliver = function(obj) {
    const all = cachePatientVisits(bmhId, obj);
    const visits = Object.values(all || {})
      .filter(v => v && (!dept || v.dept === dept))
      .sort((a,b) => String(b.date || '').localeCompare(String(a.date || '')));
    onReady(visits, all);
  };
  if(hasCached) deliver(cached);
  if(typeof fbOnce === 'function' && bmhId) fbOnce(`visits/${bmhId}`).then(deliver).catch(() => { if(!hasCached) deliver({}); });
  else if(!hasCached) deliver({});
}
function buildVisitSummaryCards(visits, dept) {
  const labelMap = { ophtho:'ophthalmology', obg:'OBG', psych:'neuropsychiatry', skin:'skin' };
  if(!visits || !visits.length) {
    return `<div style="padding:10px;border:1px dashed var(--g4);border-radius:10px;background:#fff;color:var(--g1);font-size:11px">No previous ${labelMap[dept] || 'clinic'} visits saved yet.</div>`;
  }
  return visits.slice(0,5).map(v => {
    const when = v.dateLabel || new Date(v.date || Date.now()).toLocaleDateString('en-IN');
    let line1 = 'No diagnosis recorded';
    let line2 = 'No prescription recorded';
    let line3 = '';
    if(dept === 'ophtho') {
      line1 = (Array.isArray(v.diagnoses) && v.diagnoses.length ? v.diagnoses.slice(0,2).map(formatDxLineForPrint).filter(Boolean).join(', ') : (v.diagnosisText || v.dx || 'No diagnosis recorded'));
      line2 = Array.isArray(v.rx) && v.rx.length ? v.rx.slice(0,2).map(d => rxDrugTradeName(d) || d.trade || d.name || 'Drug').join(', ') : 'No prescription';
      line3 = [v.hxSpectacles, v.hxLastSpec].filter(Boolean).join(' · ') || '';
    } else if(dept === 'obg') {
      line1 = Array.isArray(v.presumptiveDx) && v.presumptiveDx.length ? v.presumptiveDx.join(', ') : (v.dx || v.clinicalImpression || 'No diagnosis recorded');
      line2 = [v.ancVisitType, v.ga, v.gravida].filter(Boolean).join(' · ') || 'No ANC summary';
      line3 = [v.nextReview, v.followupPlan].filter(Boolean).join(' · ') || '';
    } else if(dept === 'psych') {
      line1 = Array.isArray(v.psychPresumptive) && v.psychPresumptive.length ? v.psychPresumptive.join(', ') : (v.dx || v.chiefComplaint || 'No diagnosis recorded');
      line2 = Array.isArray(v.rx) && v.rx.length ? v.rx.slice(0,2).map(d => rxDrugTradeName(d) || d.trade || d.name || 'Drug').join(', ') : (v.psychPlan || []).slice(0,2).join(', ') || 'No treatment recorded';
      line3 = [v.mse, v.psychTherapy && v.psychTherapy[0]].filter(Boolean).join(' · ');
    } else if(dept === 'skin') {
      line1 = v['skin-primary-dx'] || v.dx || 'No diagnosis recorded';
      line2 = Array.isArray(v.rx) && v.rx.length ? v.rx.slice(0,2).map(d => rxDrugTradeName(d) || d.trade || d.name || 'Drug').join(', ') : 'No prescription';
      line3 = [v['skin-fit'], v['skin-chief']].filter(Boolean).join(' · ');
    }
    return `<div style="padding:9px 10px;border:1px solid var(--g5);border-radius:10px;background:#fff;margin-bottom:7px">
      <div style="display:flex;justify-content:space-between;gap:6px;align-items:flex-start;margin-bottom:4px">
        <div style="font-size:11px;font-weight:800;color:var(--bmh-blue)">${when}</div>
        <div style="font-size:10px;color:var(--g1)">${v.doctor || ''}</div>
      </div>
      <div style="font-size:10.5px;line-height:1.42"><b>Summary:</b> ${line1}</div>
      <div style="font-size:10.5px;line-height:1.42;margin-top:3px"><b>Plan / Rx:</b> ${line2}</div>
      ${line3 ? `<div style="font-size:10px;color:var(--g1);line-height:1.36;margin-top:3px">${line3}</div>` : ''}
    </div>`;
  }).join('');
}
function ensureIpdAdmissionFromOTCase(otCase, patient) {
  if (!otCase || !otCase.bmhId || !otCase.admitToIpd) return null;
  const pt = patient || PATIENTS.find(function (p) { return p.bmhId === otCase.bmhId; }) || {};
  const dept = normalizeDeptKeyForQueue(otCase.dept || pt.dept || (String(otCase.procedure || '').toLowerCase().includes('lscs') ? 'obg' : 'ophtho'));
  const monitoringKey = otCase.ipdMonitoring || (dept === 'ophtho' ? '2h' : '6h');
  const existingIdx = (window.IPD_PATIENTS || []).findIndex(function (x) { return x.bmhId === otCase.bmhId; });
  const base = existingIdx >= 0 ? (window.IPD_PATIENTS[existingIdx] || {}) : {};
  const entry = Object.assign({}, base, {
    id: base.id || ('IPD' + Date.now()),
    bmhId: otCase.bmhId,
    name: pt.name || otCase.patient || 'Patient',
    age: pt.age || otCase.age || '',
    sex: pt.sex || otCase.sex || '',
    dept,
    ward: otCase.ipdWard || base.ward || (dept === 'ophtho' ? 'Eye Day Care' : dept === 'obg' ? 'OBG Ward' : 'Ward'),
    type: otCase.ipdType || base.type || (dept === 'ophtho' ? 'Day Care' : dept === 'obg' ? 'Obstetric' : 'Surgical'),
    doctor: otCase.surgeon || pt.doctor || base.doctor || CURRENT_USER?.name || '—',
    centre: otCase.centre || pt.centre || base.centre || getEffectiveCentre() || CURRENT_USER?.centre || 'CHD',
    room: otCase.ipdRoom || base.room || '',
    dx: otCase.dx || pt.dx || base.dx || '',
    color: pt.color || base.color || '#1A3C6E',
    initials: pt.initials || base.initials || (String(pt.name || otCase.patient || '?').split(' ').map(function (n) { return n[0] || ''; }).join('').substring(0,2).toUpperCase()),
    admittedDate: base.admittedDate || new Date().toLocaleDateString('en-IN',{day:'2-digit',month:'short',year:'numeric'}),
    admittedAt: base.admittedAt || new Date().toISOString(),
    admittedBy: base.admittedBy || CURRENT_USER?.name || 'System',
    status: 'admitted',
    allergies: base.allergies || pt.drugAllergy || '',
    diet: base.diet || '',
    monitoringKey,
    monitoringLabel: ({'1h':'Hourly','2h':'Every 2 hours','4h':'Every 4 hours','6h':'Every 6 hours'})[monitoringKey] || 'Every 6 hours',
    monitoringPlan: (base.monitoringPlan && base.monitoringPlan.length) ? base.monitoringPlan : ipdMonitoringSlots(monitoringKey, new Date().toISOString()),
    vitalSigns: Array.isArray(base.vitalSigns) ? base.vitalSigns : [],
    vitals: base.vitals || { bp:'', pulse:'', temp:'', spo2:'', rr:'', weight:pt.weight || '' },
    chartRows: Array.isArray(base.chartRows) && base.chartRows.length ? base.chartRows : ipdDeptTemplate(dept, { type: otCase.ipdType || otCase.obgCaseType, procedure: otCase.procedure, surgery: otCase.procedure }),
    notes: Array.isArray(base.notes) ? base.notes : [],
    progressNotes: Array.isArray(base.progressNotes) ? base.progressNotes : [],
    otCaseId: otCase.id,
    surgery: otCase.procedure || '',
    surgeryEye: otCase.site || '',
    ipdSource: 'ot',
    otAdmissionNotes: otCase.ipdNotes || ''
  });
  if(!window.IPD_PATIENTS) window.IPD_PATIENTS = [];
  if (existingIdx >= 0) window.IPD_PATIENTS[existingIdx] = entry;
  else window.IPD_PATIENTS.push(entry);
  pt.ipdAdmitted = true;
  pt.status = 'ipd';
  pt.dept = dept;
  fbSet && fbSet('ipdPatients/' + entry.id, entry).catch(function (e) { console.warn('OT→IPD save error:', e); });
  fbUpdate && fbUpdate('patients/' + otCase.bmhId, { ipdAdmitted:true, status:'ipd', dept }).catch(function () {});
  return entry;
}
function autoDischargeCurrentIpdPatientFromSurgery() {
  const bmhId = document.getElementById('dc-pt-id')?.textContent?.trim() || activeOTCase?.bmhId || window.CURRENT_PATIENT?.bmhId;
  const list = window.IPD_PATIENTS || IPD_PATIENTS || [];
  if (!bmhId || !list.length) return;
  const match = list.find(function (p) {
    return p.bmhId === bmhId || (activeOTCase?.id && p.otCaseId === activeOTCase.id);
  });
  if (!match) return;
  dischargeIPDPatientById(match.id);
}
function dischargeIPDPatientById(id, opts) {
  opts = opts || {};
  const list = window.IPD_PATIENTS || IPD_PATIENTS || [];
  const idx = list.findIndex(function (p) { return p.id === id; });
  if (idx < 0) return false;
  const ipd = list[idx];
  const bmhId = ipd.bmhId;
  ipd.status = 'discharged';
  ipd.dischargedAt = new Date().toISOString();
  ipd.dischargedBy = CURRENT_USER?.name || 'System';
  fbUpdate && fbUpdate('ipdPatients/' + ipd.id, { status:'discharged', dischargedAt:ipd.dischargedAt, dischargedBy:ipd.dischargedBy }).catch(function(){});
  list.splice(idx, 1);
  const pt = PATIENTS.find(function (p) { return p.bmhId === bmhId; });
  if (pt) {
    pt.ipdAdmitted = false;
    pt.status = 'seen';
    fbUpdate && fbUpdate('patients/' + bmhId, { ipdAdmitted:false, status:'seen' }).catch(function(){});
  }
  renderIPD && renderIPD();
  renderDocQueue && renderDocQueue();
  if (!opts.silentToast) showToast('Patient discharged from IPD ✓', 's');
  return true;
}
function dischargeActiveIPDPatient() {
  if (!activeIPDPatient?.id) return;
  dischargeIPDPatientById(activeIPDPatient.id);
}
function otCaseNeedsObgFlow(procText, patientId) {
  const proc = String(procText || '').toLowerCase();
  const pt = patientId ? PATIENTS.find(function (p) { return p.bmhId === patientId; }) : null;
  return /lscs|caes|cesare|delivery|mtp|iucd|obg|gynae|hyster|lapar/i.test(proc) || normalizeDeptKeyForQueue(pt?.dept || '') === 'obg';
}
function getSelectedOTCaseKind() {
  if(document.getElementById('ot-case-kind-obg')?.checked) return 'obg';
  if(document.getElementById('ot-case-kind-eye')?.checked) return 'ophtho';
  return 'ophtho';
}
function otProcedureLooksLikeLaserOrMinor(procText) {
  const proc = String(procText || '').toLowerCase();
  return /laser|yag|capsulotomy|iridotomy|prp|ivt|injection|minor procedure|iucd|cu-t/.test(proc);
}
function otProcedureNeedsMinimalObgFlow(procText, obgType) {
  const text = (String(procText || '') + ' ' + String(obgType || '')).toLowerCase();
  return /mtp|suction|evacuat|abortion|iucd|cu-t/.test(text);
}
function toggleOTProcedureSpecificFields() {
  const proc = document.getElementById('ot-add-proc')?.value || '';
  const obgType = document.getElementById('ot-add-obg-type')?.value || '';
  const laserMinor = otProcedureLooksLikeLaserOrMinor(proc);
  const minimalObg = otProcedureNeedsMinimalObgFlow(proc, obgType);
  ['ot-eye-fields', 'ot-eye-iol-summary', 'ot-icl-config-wrap'].forEach(function (id) {
    const el = document.getElementById(id);
    if (!el) return;
    const disable = laserMinor && getSelectedOTCaseKind() !== 'obg';
    el.style.display = disable ? 'none' : '';
    el.style.opacity = disable ? '0.45' : '';
    el.querySelectorAll('input,select,textarea,button').forEach(function (field) {
      field.disabled = !!disable;
    });
  });
  ['ot-add-preop', 'ot-add-consent', 'ot-add-fasting'].forEach(function (id) {
    const el = document.getElementById(id);
    if (!el) return;
    el.disabled = !!minimalObg;
    el.style.opacity = minimalObg ? '0.6' : '';
  });
  ['ot-add-obg-ga', 'ot-add-obg-fetal', 'ot-add-obg-liquor', 'ot-add-obg-blood', 'ot-add-obg-anaes-note', 'ot-add-obg-baby', 'ot-add-obg-mother', 'ot-add-obg-doc-consent', 'ot-add-obg-doc-anaes', 'ot-add-obg-doc-blood', 'ot-add-obg-doc-newborn'].forEach(function (id) {
    const el = document.getElementById(id);
    if (!el) return;
    el.disabled = !!minimalObg;
    const wrap = el.closest('.form-group') || el.parentElement;
    if (wrap) wrap.style.opacity = minimalObg ? '0.6' : '';
  });
}
function toggleOTOBGFields() {
  const block = document.getElementById('ot-add-obg-block');
  const eyeFields = document.getElementById('ot-eye-fields');
  const eyeSummary = document.getElementById('ot-eye-iol-summary');
  const siteWrap = document.getElementById('ot-site-wrap');
  if(!block) return;
  const ptId = document.getElementById('ot-bmsh-id')?.value || document.getElementById('ot-pt-sel')?.value || '';
  const proc = document.getElementById('ot-add-proc')?.value || '';
  const visible = getSelectedOTCaseKind() === 'obg' || otCaseNeedsObgFlow(proc, ptId);
  block.style.display = visible ? '' : 'none';
  if (eyeFields) eyeFields.style.display = visible ? 'none' : '';
  if (eyeSummary) eyeSummary.style.display = visible ? 'none' : '';
  if (siteWrap) siteWrap.style.display = visible ? 'none' : '';
  if(!visible) {
    toggleOTProcedureSpecificFields();
    return;
  }
  const admitEl = document.getElementById('ot-add-admit');
  const admitBlock = document.getElementById('ot-add-admit-block');
  if(admitEl && !admitEl.checked) admitEl.checked = true;
  if(admitBlock) admitBlock.style.display = 'grid';
  const typeEl = document.getElementById('ot-add-admit-type');
  const wardEl = document.getElementById('ot-add-admit-ward');
  const notesEl = document.getElementById('ot-add-admit-notes');
  const roomEl = document.getElementById('ot-add-room');
  if(typeEl) typeEl.value = 'Obstetric';
  if(wardEl && !wardEl.value) wardEl.value = 'OBG Ward / Bed';
  if(roomEl && (!roomEl.value || /^OT-/.test(roomEl.value) || roomEl.value === 'Eye OT')) roomEl.value = 'Labour Room';
  if(notesEl && !notesEl.value) notesEl.value = 'Pre-op vitals, fetal status, consent checked, labour / OT checklist, medicines and post-op monitoring.';
  toggleOtIclFields();
  toggleOTProcedureSpecificFields();
}
function ipdVitalsStatus(vitals) {
  const flags = [];
  const pulse = Number(vitals?.pulse || 0);
  const temp = Number(vitals?.temp || 0);
  const spo2 = Number(vitals?.spo2 || 0);
  const rr = Number(vitals?.rr || 0);
  if (pulse && (pulse < 50 || pulse > 110)) flags.push({ label:'Pulse out of range', tone:'var(--red)' });
  if (temp && temp >= 38) flags.push({ label:'Fever', tone:'var(--orange)' });
  if (spo2 && spo2 < 94) flags.push({ label:'Low SpO2', tone:'var(--red)' });
  if (rr && (rr < 10 || rr > 24)) flags.push({ label:'Respiratory rate abnormal', tone:'var(--orange)' });
  return flags;
}
function ipdEvaluateAlerts(p) {
  const alerts = [];
  const lastVitals = (p.vitalSigns || [])[0];
  ipdVitalsStatus(lastVitals || {}).forEach(f => alerts.push({ tone:f.tone, text:f.label + (lastVitals?.recordedAt ? ' · ' + new Date(lastVitals.recordedAt).toLocaleString('en-IN') : '') }));
  (p.monitoringPlan || []).forEach(slot => {
    if (slot.status !== 'done' && new Date(slot.dueAt).getTime() < Date.now()) alerts.push({ tone:'var(--red)', text:'Observation overdue since ' + new Date(slot.dueAt).toLocaleString('en-IN') });
  });
  if (!alerts.length) alerts.push({ tone:'var(--green)', text:'No active IPD alerts right now' });
  return alerts;
}
function renderIPDAlerts(p) {
  const el = document.getElementById('ipd-alerts-panel');
  if (!el) return;
  if (!p) {
    el.innerHTML = 'Select a patient to load alerts.';
    return;
  }
  const alerts = ipdEvaluateAlerts(p);
  el.innerHTML = alerts.map(a => `<div style="padding:9px 10px;border-radius:8px;margin-bottom:7px;background:${a.tone === 'var(--green)' ? 'var(--green-lt)' : a.tone === 'var(--orange)' ? 'var(--orange-lt)' : 'var(--red-lt)'};color:${a.tone};font-weight:${a.tone === 'var(--green)' ? '700' : '900'}">${a.text}</div>`).join('');
}
function ipdChartSummary(p) {
  const chart = p.chartRows || [];
  if (!chart.length) return '<div style="color:var(--g1);font-size:12px">No structured chart items yet.</div>';
  return chart.map(function (row, idx) {
    const control = Array.isArray(row.options) && row.options.length
      ? `<select onchange="updateIPDChartRow(${idx},'value',this.value)" style="width:100%;border:1px solid var(--g4);border-radius:8px;padding:6px 8px;font-size:11px;background:#fff">
          <option value="">— Select —</option>
          ${row.options.map(function (opt) { return '<option value="' + escapeHtmlConsent(opt) + '"' + (String(row.value || '') === String(opt) ? ' selected' : '') + '>' + escapeHtmlConsent(opt) + '</option>'; }).join('')}
        </select>`
      : `<input type="text" value="${escapeHtmlConsent(row.value || '')}" placeholder="${escapeHtmlConsent(row.placeholder || (row.checked ? 'Completed / remark' : 'Remark / value'))}" oninput="updateIPDChartRow(${idx},'value',this.value)" style="width:100%;border:1px solid var(--g4);border-radius:8px;padding:6px 8px;font-size:11px;background:#fff">`;
    return `<div style="display:grid;grid-template-columns:auto 1fr minmax(120px,180px);gap:8px;align-items:center;padding:8px 0;border-bottom:1px solid var(--g5);font-size:12px">
      <label style="display:flex;align-items:center;justify-content:center"><input type="checkbox" ${row.checked ? 'checked' : ''} onchange="updateIPDChartRow(${idx},'checked',this.checked)"></label>
      <div style="font-weight:700;color:var(--tx1)">${row.label}</div>
      ${control}
    </div>`;
  }).join('');
}

function updateIPDChartRow(idx, field, value) {
  if (!activeIPDPatient || !Array.isArray(activeIPDPatient.chartRows) || !activeIPDPatient.chartRows[idx]) return;
  activeIPDPatient.chartRows[idx][field] = field === 'checked' ? !!value : value;
  if (field === 'checked' && value && !activeIPDPatient.chartRows[idx].value) activeIPDPatient.chartRows[idx].value = 'Done';
  if (fbUpdate) fbUpdate('ipdPatients/' + activeIPDPatient.id, { chartRows: activeIPDPatient.chartRows }).catch(()=>{});
}

