  if (!name || !String(name).trim()) return;
  const n = String(name).trim();
  if (!(window.BMH_OFFICE_BILL_CATEGORIES || []).includes(n)) window.BMH_OFFICE_BILL_CATEGORIES.push(n);
  saveBmhFinancials();
