  if (idx < 0) return;
  const bill = window.BMH_VENDOR_BILLS[idx];
  if (!confirm('Delete vendor bill ' + (bill.invoiceNo || bill.uploadedName || bill.vendor || '') + '?')) return;
  window.BMH_VENDOR_BILLS.splice(idx, 1);
