function bmhRecordPatientPayment() {
  if (window._bmhPaymentSaveInFlight) {
    showToast('Payment is already being saved…', 'i');
    return;
  }
  const bmhId = document.getElementById('bmh-bill-pt-select')?.value;
  if (!bmhId) { showToast('Select a patient', 'w'); return; }
  const amt = parseFloat(document.getElementById('bmh-pay-amt')?.value || '0');
  const mode = document.getElementById('bmh-pay-mode')?.value || 'Cash';
  const allowZeroForInsurance = isInsuranceLikeMode(mode);
  if (amt < 0 || (!allowZeroForInsurance && !(amt > 0))) { showToast(allowZeroForInsurance ? 'Amount cannot be negative' : 'Enter amount', 'w'); return; }
  bmhSetPaymentSaveBusy(true);
  try {
  const ref = document.getElementById('bmh-pay-ref')?.value?.trim() || '';
  const insName = document.getElementById('bmh-pay-insurer')?.value?.trim() || '';
  const policy = document.getElementById('bmh-pay-policy')?.value?.trim() || '';
  const insurerDue = Math.max(0, Number(document.getElementById('bmh-pay-insurer-due')?.value || 0));
  const cashlessApr = Math.max(0, Number(document.getElementById('bmh-pay-cashless-approved')?.value || 0));
  const netBill = Number(bmhTotalsForPatient(bmhId).total) || 0;
  const pt = PATIENTS.find(p => p.bmhId === bmhId);
  const billCtx = bmhGetEffectiveBillContext(bmhId);
  const txnId = 'TXN' + Date.now();
  const splitLabel = cashlessApr > 0
    ? ('Patient share · bill ₹' + netBill.toLocaleString('en-IN') + ' · cashless ₹' + cashlessApr.toLocaleString('en-IN'))
    : '';
  const txn = {
    id: txnId,
    patient: pt?.name || bmhId,
    bmhId,
    service: cashlessApr > 0 && !isInsuranceLikeMode(mode) ? ('Billing — ' + splitLabel) : (cashlessApr > 0 && isInsuranceLikeMode(mode) ? ('TPA / cashless receipt — ' + splitLabel) : 'Billing payment'),
    amount: amt,
    mode,
    collected: true,
    paymentRef: ref,
    ins: insName,
    policy,
    dept: pt?.dept || 'ophtho',
    time: new Date().toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' }),
    date: new Date().toISOString(),
    centre: pt?.centre || CURRENT_USER?.centre || 'CHD',
    createdBy: CURRENT_USER?.name || 'Billing',
    source: 'billing',
    type: 'billing-payment',
    billCats: (billCtx.activeCats || []).slice(),
    cashlessApprovedAmount: cashlessApr > 0 ? cashlessApr : undefined,
    hospitalBillTotal: cashlessApr > 0 ? netBill : undefined
  };
  txn.chargeAllocations = bmhAllocatePaymentToChargeLines(bmhId, amt, {
    txnId: txnId,
    date: txn.date,
    mode: mode,
    by: txn.createdBy,
    categories: (billCtx.activeCats || []).slice()
  });
  if (amt > 0) {
    TRANSACTIONS.push(txn);
    saveTransactionToFirebase && saveTransactionToFirebase(txn);
  }
  const advAdj = Number(bmhTotalsForPatient(bmhId).advanceApplied || 0);
  if (pt && advAdj > 0) {
    pt.advance = Math.max(0, (Number(pt.advance) || 0) - advAdj);
    fbUpdate && fbUpdate('patients/' + bmhId, { advance: pt.advance });
  }
  const updatedDue = bmhSyncPatientRunningBalance(bmhId);
  if (pt) pt.balance = updatedDue;
  const insReceivedTotal = (TRANSACTIONS || []).filter(function (t) {
    return t.bmhId === bmhId && isInsuranceLikeMode(t.mode || t.ins || '');
  }).reduce(function (s, t) { return s + (Number(t.amount) || 0); }, 0);
  if (cashlessApr > 0 && pt) {
    const lines = window.BMH_PATIENT_CHARGES[bmhId] || [];
    const topLine = lines.find(function (x) { return x && !x.isConcession; }) || lines[0];
    const proc = String(topLine?.desc || topLine?.name || 'Hospital bill / cashless').slice(0, 120);
    const pendingTpa = Math.max(0, cashlessApr - insReceivedTotal);
    let existing = (PAY_REQUESTS || []).find(function (r) {
      return r.bmhId === bmhId && r.status === 'pending' && isInsuranceLikeMode(r.mode || r.ins || '');
    });
    const prPayload = {
      patient: pt.name || bmhId,
      bmhId: bmhId,
      for: proc,
      procedure: proc,
      diagnosis: String(pt.diagnosis || pt.purpose || '').slice(0, 120),
      claimedAmount: cashlessApr,
      approvedAmount: cashlessApr,
      cashlessApprovedAmount: cashlessApr,
      hospitalBillTotal: netBill,
      patientShareCollected: !isInsuranceLikeMode(mode) ? Math.max(0, amt) : 0,
      amount: pendingTpa,
      status: pendingTpa > 0 ? 'pending' : 'paid',
      from: 'Billing',
      dept: pt.dept || 'ophtho',
      centre: pt.centre || CURRENT_USER?.centre || 'CHD',
      mode: 'Insurance/TPA',
      ins: insName || 'Insurance/TPA',
      policy: policy || '',
      date: new Date().toISOString(),
      lastPaymentRef: ref,
      lastPaymentAmt: amt
    };
    if (existing) {
      Object.assign(existing, prPayload, { id: existing.id });
      try { fbUpdate && fbUpdate('payRequests/' + existing.id, Object.assign({}, existing)); } catch (e) {}
    } else {
      const prIns = Object.assign({ id: 'PR' + Date.now() }, prPayload);
      PAY_REQUESTS.push(prIns);
      try { fbSet && fbSet('payRequests/' + prIns.id, prIns); } catch (e) {}
    }
  } else if (isInsuranceLikeMode(mode) && pt) {
    const lines = window.BMH_PATIENT_CHARGES[bmhId] || [];
    const topLine = lines.find(function (x) { return x && !x.isConcession; }) || lines[0];
    const proc = String(topLine?.desc || topLine?.name || 'Hospital bill / cashless').slice(0, 120);
    const claimedAmt = Math.max(Number(bmhBillPreviewTotal(bmhId)) || 0, amt + (insurerDue || 0));
    const hospitalDue = Math.max(0, insurerDue > 0 ? insurerDue : updatedDue);
    let existing = (PAY_REQUESTS || []).find(function (r) {
      return r.bmhId === bmhId && r.status === 'pending' && isInsuranceLikeMode(r.mode || r.ins || '');
    });
    const prPayload = {
      patient: pt.name || bmhId,
      bmhId: bmhId,
      for: proc,
      procedure: proc,
      diagnosis: String(pt.diagnosis || pt.purpose || '').slice(0, 120),
      amount: hospitalDue,
      claimedAmount: claimedAmt,
      approvedAmount: Math.max(Number(existing?.approvedAmount) || 0, claimedAmt),
      status: 'pending',
      from: 'Billing',
      dept: pt.dept || 'ophtho',
      centre: pt.centre || CURRENT_USER?.centre || 'CHD',
      mode: mode,
      ins: insName || mode,
      policy: policy || '',
      date: new Date().toISOString(),
      lastPaymentRef: ref,
      lastPaymentAmt: amt
    };
    if (existing) {
      Object.assign(existing, prPayload, { id: existing.id });
      try { fbUpdate && fbUpdate('payRequests/' + existing.id, Object.assign({}, existing)); } catch (e) {}
    } else {
      const prIns = Object.assign({ id: 'PR' + Date.now() }, prPayload);
      PAY_REQUESTS.push(prIns);
      try { fbSet && fbSet('payRequests/' + prIns.id, prIns); } catch (e) {}
    }
  }
  const pendingNonInsurance = (PAY_REQUESTS || []).filter(function (r) {
    return r.bmhId === bmhId && r.status === 'pending' && !isInsuranceLikeMode(r.mode || r.ins || '');
  }).sort(function (a, b) { return new Date(a.date || 0) - new Date(b.date || 0); });
  if (pendingNonInsurance.length) {
    let remaining = Math.max(0, updatedDue);
    pendingNonInsurance.forEach(function (pr) {
      if (remaining <= 0) {
        pr.status = 'paid';
        pr.amount = 0;
      } else {
        const amtDue = Math.max(0, Number(pr.amount || 0));
        const nextAmt = Math.min(amtDue, remaining);
        pr.amount = nextAmt;
        pr.status = nextAmt > 0 ? 'pending' : 'paid';
        remaining = Math.max(0, remaining - nextAmt);
      }
      try {
        if (window.firebase && firebase.database) {
          firebase.database().ref('payRequests/' + pr.id).update({
            amount: Number(pr.amount || 0),
            status: pr.status,
            updatedAt: new Date().toISOString()
          });
        }
      } catch (e) {}
    });
  }
  if (amt > 0) {
    bmhAppendLedger({ date: new Date().toISOString(), type: 'Receipt', narration: 'Patient payment (' + mode + ')', dr: 0, cr: amt, party: pt?.name || bmhId, ref: ref || mode });
  } else {
    saveBmhFinancials();
  }
  bmhClearPaymentDraft();
  const addToQ = !!document.getElementById('bmh-bill-add-to-queue')?.checked;
  if (addToQ) bmhAddPatientToDoctorQueue(bmhId, { silentToast: true });
  const savedMsg = amt > 0
    ? (addToQ ? 'Payment saved — patient added to doctor queue ✓' : 'Payment saved ✓')
    : (addToQ ? 'TPA / cashless claim saved — patient added to doctor queue ✓' : 'TPA / cashless claim saved ✓');
  showToast(savedMsg, 's');
  renderBillingPage();
  renderDashboard && renderDashboard();
  try { renderTpaPage && renderTpaPage(); } catch (e) {}
  } finally {
    bmhSetPaymentSaveBusy(false);
  }
}
