async function extractInventoryTextFromImageDataUrl(dataUrl) {
  await ensureInventoryTesseract();
  if (!window.Tesseract) throw new Error('OCR engine not loaded');
  const result = await window.Tesseract.recognize(dataUrl, 'eng', {
    logger: function (m) {
      const prog = Math.round((Number(m.progress || 0) || 0) * 100);
      if (m.status) setInventoryImportStatus(window._inventoryImportMode || 'ocr', m.status + (prog ? ' ' + prog + '%' : ''), 'var(--bmh-blue)');
    }
  });
  return String(result?.data?.text || '').trim();
}
async function extractInventoryTextFromCanvasRegions(canvas) {
  const cropToDataUrl = function (sx, sy, sw, sh) {
    const out = document.createElement('canvas');
    out.width = Math.max(1, Math.round(sw));
    out.height = Math.max(1, Math.round(sh));
    const ctx = out.getContext('2d');
    ctx.drawImage(canvas, sx, sy, sw, sh, 0, 0, out.width, out.height);
    return out.toDataURL('image/jpeg', 0.96);
  };
  const w = canvas.width || 1;
  const h = canvas.height || 1;
  const regions = [
    cropToDataUrl(0, 0, w, h * 0.18),
    cropToDataUrl(w * 0.02, h * 0.14, w * 0.96, h * 0.24),
    cropToDataUrl(w * 0.02, h * 0.18, w * 0.96, h * 0.32),
    cropToDataUrl(w * 0.02, h * 0.10, w * 0.96, h * 0.62)
  ];
  const texts = [];
  for (let i = 0; i < regions.length; i += 1) {
    const txt = await extractInventoryTextFromImageDataUrl(regions[i]);
    if (txt) texts.push(txt);
  }
  return texts.join('\n');
}
async function extractStructuredTextFromPdfPage(page) {
  const content = await page.getTextContent();
  const items = Array.isArray(content?.items) ? content.items : [];
  const lines = [];
  items.forEach(function (item) {
    const str = String(item?.str || '').trim();
    if (!str) return;
    const y = Math.round(Number(item?.transform?.[5] || 0));
    let row = lines.find(function (line) { return Math.abs(line.y - y) <= 3; });
    if (!row) {
      row = { y: y, parts: [] };
      lines.push(row);
    }
    row.parts.push({ x: Number(item?.transform?.[4] || 0), str: str });
  });
  return lines
    .sort(function (a, b) { return b.y - a.y; })
    .map(function (line) {
      return line.parts.sort(function (a, b) { return a.x - b.x; }).map(function (part) { return part.str; }).join(' ').replace(/\s+/g, ' ').trim();
    })
    .filter(Boolean)
    .join('\n');
}
async function extractInventoryTextFromImageFile(file) {
  const dataUrl = await new Promise(function (resolve, reject) {
    const fr = new FileReader();
    fr.onload = function (e) { resolve(String(e.target?.result || '')); };
    fr.onerror = reject;
    fr.readAsDataURL(file);
  });
  const img = await new Promise(function (resolve, reject) {
    const image = new Image();
    image.onload = function () { resolve(image); };
    image.onerror = reject;
    image.src = dataUrl;
  });
  const canvas = document.createElement('canvas');
  canvas.width = img.width;
  canvas.height = img.height;
  canvas.getContext('2d').drawImage(img, 0, 0);
  return extractInventoryTextFromCanvasRegions(canvas);
}
async function extractInventoryTextFromPdfFile(file) {
  await ensureInventoryPdfJs();
  await ensureInventoryTesseract();
  if (!window.pdfjsLib) throw new Error('PDF reader not loaded');
  const arr = await file.arrayBuffer();
  const pdf = await window.pdfjsLib.getDocument({ data: arr }).promise;
  const page = await pdf.getPage(1);
  let directText = '';
  try {
    directText = await extractStructuredTextFromPdfPage(page);
  } catch (_) { /* fallback to OCR below */ }
  const viewport = page.getViewport({ scale: 2 });
  const canvas = document.createElement('canvas');
  canvas.width = viewport.width;
  canvas.height = viewport.height;
  await page.render({ canvasContext: canvas.getContext('2d'), viewport: viewport }).promise;
  const ocrText = await extractInventoryTextFromCanvasRegions(canvas);
  const cleanedDirect = cleanInventoryImportText(directText);
  const cleanedOcr = cleanInventoryImportText(ocrText);
  if (cleanedDirect && cleanedDirect.split('\n').length >= 3) {
    return [cleanedDirect, cleanedOcr].filter(Boolean).join('\n');
  }
  return cleanedOcr || cleanedDirect || '';
}
async function handleInventoryImportFile(mode, inp) {
  const file = inp?.files?.[0];
  if (!file) return;
  window._inventoryImportMode = mode;
  window._inventoryImportAssets = window._inventoryImportAssets || {};
  setInventoryImportStatus(mode, 'Preparing file…', 'var(--bmh-blue)');
  setInventoryImportPreview(mode, '');
  try {
    let text = '';
    const fileNameHint = String(file.name || '').replace(/\.[a-z0-9]+$/i, '').replace(/[_-]+/g, ' ');
    const fileData = await new Promise(function (resolve, reject) {
      const fr = new FileReader();
      fr.onload = function (e) { resolve(String(e.target?.result || '')); };
      fr.onerror = reject;
      fr.readAsDataURL(file);
    });
    window._inventoryImportAssets[mode] = { name: file.name || '', type: file.type || '', data: fileData };
    if (/pdf/i.test(file.type || '') || /\.pdf$/i.test(file.name || '')) {
      text = await extractInventoryTextFromPdfFile(file);
    } else {
      text = await extractInventoryTextFromImageFile(file);
    }
    const combinedText = cleanInventoryImportText((text + '\n' + fileNameHint).trim());
    const parsed = parseInventoryImportText(combinedText);
    parsed.reviewText = combinedText;
    window._inventoryParsedImports = window._inventoryParsedImports || {};
    window._inventoryParsedImports[mode] = parsed;
    if (!parsed.itemName) {
      const topMatch = findInventoryCandidatesFromText(combinedText, 1)[0];
      if (topMatch) parsed.itemName = topMatch.name;
    }
    if (mode === 'in') inventoryRememberBillMeta(parsed.vendor || '', document.getElementById('inv-in-dept')?.value || '', window._inventoryImportAssets[mode] || null);
    applyInventoryParsedData(parsed, mode);

    // ── IOL bills: run the dedicated IOL parser for accurate power-grid population ──
    const parsedIsIol = String(parsed.category || '').toLowerCase() === 'iol'
      || (Array.isArray(parsed.lineItems) && parsed.lineItems.some(function (it) { return !!it.power; }))
      || /\b(?:iol|intraocular|trusmart|tru\s*smart|vivinex|impress|acrysof|tecnis|auroflex|aurovue)\b/i.test(combinedText);
    if (mode === 'in' && parsedIsIol) {
      const iolParsed = parseIolBillOcrText(combinedText);
      if (iolParsed && Object.keys(iolParsed.rows || {}).length) {
        // Store brand groups so review can show per-brand buttons
        parsed.iolBrandGroups = iolParsed.brandGroups || null;

        // Fill form for the first brand group
        function _fillIolGroup(group) {
          const pwQtyMap = {};
          const serialParts = [];
          Object.keys(group.rows).forEach(function (power) {
            const row = group.rows[power];
            pwQtyMap[power] = { qty: row.qty };
            const serials = (row.serials || [])
              .map(function (s) { return [s.serialNo || '', s.batchNo || ''].filter(Boolean).join(','); })
              .filter(Boolean);
            if (serials.length) serialParts.push(power + ': ' + serials.join('; '));
          });
          if (typeof renderIolInventoryPowerGrid === 'function') renderIolInventoryPowerGrid(pwQtyMap);
          const smEl = document.getElementById('inv-iol-serial-map');
          if (smEl && serialParts.length && !smEl.value) smEl.value = serialParts.join(' | ');
          if (group.expiry) { const el = document.getElementById('inv-iol-expiry'); if (el && !el.value) el.value = group.expiry; }
          if (group.company) { const el = document.getElementById('inv-iol-company'); if (el && !el.value) el.value = group.company; }
          if (group.brand) { const el = document.getElementById('inv-iol-brand'); if (el && !el.value) el.value = group.brand; }
        }

        const firstGroup = (iolParsed.brandGroups || [])[0] || { brand: iolParsed.brand, company: iolParsed.company, rows: iolParsed.rows, expiry: iolParsed.expiry };
        _fillIolGroup(firstGroup);

        // Status message
        const multiInfo = iolParsed.brandGroups && iolParsed.brandGroups.length > 1
          ? iolParsed.brandGroups.length + ' IOL brands: ' + iolParsed.brandGroups.map(function (g) { return g.brand || 'IOL'; }).join(', ') + '. Use buttons in the review to fill each brand separately.'
          : Object.keys(iolParsed.rows).length + ' power(s) detected.';
        const perPowerExpiries = Object.entries(iolParsed.rows)
          .filter(function (kv) { return kv[1].expiry && kv[1].expiry !== iolParsed.expiry; })
          .map(function (kv) { return kv[0] + '→' + kv[1].expiry; });
        setInventoryImportStatus(mode,
          'IOL bill parsed — ' + multiInfo + (perPowerExpiries.length ? ' Mixed expiries: ' + perPowerExpiries.join(', ') + '.' : '') + ' Review and save each brand.',
          (iolParsed.brandGroups && iolParsed.brandGroups.length > 1) ? '#8a4200' : '#1a8c3c');
      }
    }

    bmhMaybeRegisterVendorBillFromParsedImport(parsed, window._inventoryImportAssets[mode], mode);
    renderInventoryImportReview(parsed, mode, combinedText);
    if (!parsedIsIol) setInventoryImportStatus(mode, 'OCR complete. Please review the populated fields before saving.', '#1a8c3c');
    openInventoryBillReviewModal(mode);
    if (mode === 'ocr') {
      const tabBtn = Array.from(document.querySelectorAll('#pg-inventory .ptab')).find(function (el) { return String(el.textContent || '').includes('Photo / OCR'); });
      if (tabBtn) ptab(tabBtn, 'inv-ocr');
    }
  } catch (err) {
    console.warn('Inventory OCR failed:', err);
    setInventoryImportStatus(mode, 'Could not auto-read this file. You can still review the upload and fill the fields manually.', 'var(--orange)');
    setInventoryImportPreview(mode, 'Automatic extraction failed for this file.');
  } finally {
    if (inp) inp.value = '';
  }
}
window.handleInventoryImportFile = handleInventoryImportFile;

// Fill the IOL stock-in form with data from a specific brand group in a multi-brand bill
function fillIolBrandGroup(mode, groupIdx) {
  const parsed = window._inventoryParsedImports && window._inventoryParsedImports[mode];
  if (!parsed || !Array.isArray(parsed.iolBrandGroups)) { showToast('No brand groups detected', 'w'); return; }
  const group = parsed.iolBrandGroups[groupIdx];
  if (!group) return;

  const pwQtyMap = {};
  const serialParts = [];
  Object.keys(group.rows).forEach(function (power) {
    const row = group.rows[power];
    pwQtyMap[power] = { qty: row.qty };
    const serials = (row.serials || [])
      .map(function (s) { return [s.serialNo || '', s.batchNo || ''].filter(Boolean).join(','); })
      .filter(Boolean);
    if (serials.length) serialParts.push(power + ': ' + serials.join('; '));
  });

  if (typeof renderIolInventoryPowerGrid === 'function') renderIolInventoryPowerGrid(pwQtyMap);
  const smEl = document.getElementById('inv-iol-serial-map');
  if (smEl) smEl.value = serialParts.join(' | ');
  if (group.expiry) { const el = document.getElementById('inv-iol-expiry'); if (el) el.value = group.expiry; }
  if (group.company) { const el = document.getElementById('inv-iol-company'); if (el) el.value = group.company; }
  if (group.brand) { const el = document.getElementById('inv-iol-brand'); if (el) el.value = group.brand; }

  const remaining = parsed.iolBrandGroups.length - 1 - groupIdx;
  showToast('Form filled for ' + (group.brand || 'IOL brand ' + (groupIdx + 1)) + '. Save this, then click the next brand.' + (remaining > 0 ? ' (' + remaining + ' remaining)' : ''), 's');
}
window.fillIolBrandGroup = fillIolBrandGroup;

