function calcPend(inp){const row=inp.closest('tr');if(!row)return;const inputs=row.querySelectorAll('input[type=number]');const approved=parseFloat(inputs[1]?.value||0),received=parseFloat(inputs[2]?.value||0);const cell=row.querySelector('.tpa-p');if(cell){const pend=Math.max(0,approved-received);cell.innerHTML=`<span style="font-weight:900;color:${pend<=0?'var(--green)':'var(--orange)'}">₹${pend.toLocaleString('en-IN')}</span>`;}}

// ═══════════════════════════════════════
// CENTRES CHARGES
// ═══════════════════════════════════════
function renderCentresView() {
  const dateEl = document.getElementById('centres-date');
  const today = localDateKey(new Date());
  if (dateEl && !dateEl.value) dateEl.value = today;
  const selectedDate = dateEl?.value || today;
  const centreCodes = (CURRENT_USER?.isAdmin || CURRENT_USER?.canSeeAllCentres) ? ['RPR', 'CHD'] : [normalizeAppointmentCentreValue(CURRENT_USER?.centre || 'CHD')];
  const centreMeta = {
    CHD: { label: 'Chandigarh Centre', tone: 'var(--bmh-blue)' },
    RPR: { label: 'Ropar Centre', tone: '#8a4200' }
  };
  const deptMeta = [
    { key: 'ophtho', label: 'Eye' },
    { key: 'obg', label: 'OBG' },
    { key: 'psych', label: 'Neuropsychiatry' },
    { key: 'skin', label: 'Skin' }
  ];
  const isSameDay = function (value) { return localDateKey(value) === selectedDate; };
  const esc = function (v) { return escapeHtmlConsent(String(v || '')); };
  const fmt = function (n) { return '₹' + Number(n || 0).toLocaleString('en-IN'); };
  const visiblePatients = (PATIENTS || []).filter(function (p) {
    return centreCodes.includes(normalizeAppointmentCentreValue(p.centre || 'CHD')) && isSameDay(p.checkinAt || p.createdAt || p.updatedAt || p.date || p.registeredAt);
  });
  const selectedTxn = (TRANSACTIONS || []).filter(function (t) {
    return centreCodes.includes(normalizeAppointmentCentreValue(t.centre || 'CHD')) && isSameDay(t.date) && isCollectedTxn(t);
  });
  const selectedClaims = getDisplayTpaClaims().filter(function (r) {
    return centreCodes.includes(normalizeAppointmentCentreValue(r.centre || 'CHD')) && String(r.status || '').toLowerCase() !== 'paid';
  });
  const surgeriesOnDate = (OT_CASES || []).filter(function (c) {
    return centreCodes.includes(normalizeAppointmentCentreValue(c.centre || 'CHD')) && isSameDay(c.date || c.otDate || c.surgeryDate || c.createdAt);
  });

  const classifyVisitKind = function (patient) {
    const purpose = String(patient.purpose || '').toLowerCase();
    if (/follow/.test(purpose)) return 'followup';
    if ((Number(patient.visitCount || 1) || 1) > 1) return 'followup';
    return 'new';
  };
  const summarizeServiceGroup = function (rows) {
    const grouped = {};
    rows.forEach(function (row) {
      const key = String(row.service || row.for || row.desc || 'Miscellaneous').trim() || 'Miscellaneous';
      if (!grouped[key]) grouped[key] = { label: key, count: 0, amount: 0 };
      grouped[key].count += 1;
      grouped[key].amount += getNetTransactionAmount(row);
    });
    return Object.values(grouped).sort(function (a, b) { return b.amount - a.amount || a.label.localeCompare(b.label); });
  };
  const isConsultationPurpose = function (purpose) {
    return /consult|follow|post\s*-?\s*op|opd|review|registration|new consultation/.test(String(purpose || '').toLowerCase());
  };
  const getConsultationCounter = function (deptPatients, consultPatients, deptConsultTxns) {
    const ids = new Set();
    const pushId = function (value) {
      const key = String(value || '').trim();
      if (key) ids.add(key);
    };
    deptConsultTxns.forEach(function (txn) {
      pushId(txn.bmhId || txn.patientId || txn.pid || txn.patient || '');
    });
    deptPatients.forEach(function (patient) {
      if (!isConsultationPurpose(patient.purpose || '')) return;
      if (!patient.consultationNoFee) return;
      pushId(patient.bmhId || patient.id || patient.mobile || patient.name || '');
    });
    return ids.size || consultPatients.length;
  };
  const centreSheets = centreCodes.map(function (centreCode) {
    const patients = visiblePatients.filter(function (p) { return normalizeAppointmentCentreValue(p.centre || 'CHD') === centreCode; });
    const txns = selectedTxn.filter(function (t) { return normalizeAppointmentCentreValue(t.centre || 'CHD') === centreCode; });
    const claims = selectedClaims.filter(function (r) { return normalizeAppointmentCentreValue(r.centre || 'CHD') === centreCode; });
    const otCases = surgeriesOnDate.filter(function (c) { return normalizeAppointmentCentreValue(c.centre || 'CHD') === centreCode; });
    const centreTotal = txns.reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
    const centreTpaDue = claims.reduce(function (s, r) {
      const claimed = Number(r.claimedAmount || r.amount || 0);
      const received = Number(r.receivedAmount || 0);
      const patientDue = Number(r.patientDue || 0);
      return s + Math.max(0, claimed - received) + patientDue;
    }, 0);
    const deptBlocks = deptMeta.map(function (dept) {
      const deptPatients = patients.filter(function (p) { return normalizeDeptKeyForQueue(p.dept || '') === dept.key; });
      const deptTxns = txns.filter(function (t) { return normalizeDeptKeyForQueue(t.dept || '') === dept.key; });
      const deptClaims = claims.filter(function (r) { return normalizeDeptKeyForQueue(r.dept || '') === dept.key; });
      const deptOt = otCases.filter(function (c) { return normalizeDeptKeyForQueue(c.dept || '') === dept.key; });
      const consultPatients = deptPatients.filter(function (p) {
        return !/diagnostic|investigation|procedure only|lab/i.test(String(p.purpose || ''));
      });
      const newCount = consultPatients.filter(function (p) { return classifyVisitKind(p) === 'new'; }).length;
      const followCount = consultPatients.filter(function (p) { return classifyVisitKind(p) === 'followup'; }).length;
      const noFeeCount = consultPatients.filter(function (p) { return !!p.consultationNoFee; }).length;
      const paidCount = Math.max(0, consultPatients.length - noFeeCount);
      const deptConsultTxns = deptTxns.filter(function (t) {
        return transactionHasChargeCategory(t, 'consultation');
      });
      const totalOpdCount = getConsultationCounter(deptPatients, consultPatients, deptConsultTxns);
      const diagnosticTxns = deptTxns.filter(function (t) {
        return transactionHasChargeCategory(t, 'diagnostic')
          || /oct|hvf|fundus|biometry|topography|specular|cbc|test|scan|profile|blood|urine|ecg/i.test(String(t.service || ''));
      });
      const surgeryTxns = deptTxns.filter(function (t) {
        return transactionHasChargeCategory(t, 'surgery')
          || /surgery|procedure|pmics|phaco|iol|delivery|lscs|laser|capsulotomy|ivt|injection|mtp|laparoscopy/i.test(String(t.service || ''));
      });
      const cashTxns = deptTxns.filter(function (t) { return normalizePaymentMode(t.mode) === 'Cash'; });
      const onlineTxns = deptTxns.filter(function (t) {
        const mode = normalizePaymentMode(t.mode);
        return mode !== 'Cash' && mode !== 'Insurance/TPA' && mode !== 'Credit / Due';
      });
      const cashGroups = summarizeServiceGroup(cashTxns);
      const onlineGroups = summarizeServiceGroup(onlineTxns);
      const claimDue = deptClaims.reduce(function (s, r) {
        const claimed = Number(r.claimedAmount || r.amount || 0);
        const received = Number(r.receivedAmount || 0);
        const patientDue = Number(r.patientDue || 0);
        return s + Math.max(0, claimed - received) + patientDue;
      }, 0);
      return `<div style="border:1px solid var(--g5);border-radius:12px;padding:12px;background:#fff;margin-bottom:10px">
        <div style="display:flex;justify-content:space-between;gap:8px;align-items:flex-start;margin-bottom:8px">
          <div style="font-size:14px;font-weight:900;color:${centreMeta[centreCode].tone}">${dept.label}</div>
          <div style="font-size:13px;font-weight:900;color:${centreMeta[centreCode].tone}">${fmt(deptTxns.reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0))}</div>
        </div>
        <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:10px">
          <div style="background:var(--g6);border-radius:8px;padding:8px"><div style="font-size:10px;color:var(--g1);font-weight:800">Total OPD</div><div style="font-size:16px;font-weight:900">${totalOpdCount}</div><div style="font-size:10px;color:var(--g1)">New ${newCount} · Follow-up ${followCount}</div></div>
          <div style="background:var(--g6);border-radius:8px;padding:8px"><div style="font-size:10px;color:var(--g1);font-weight:800">Consultation</div><div style="font-size:16px;font-weight:900">${fmt(deptConsultTxns.reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0))}</div><div style="font-size:10px;color:var(--g1)">Paid ${paidCount} · No fee ${noFeeCount}</div></div>
          <div style="background:var(--g6);border-radius:8px;padding:8px"><div style="font-size:10px;color:var(--g1);font-weight:800">Investigations / Minor</div><div style="font-size:16px;font-weight:900">${fmt(diagnosticTxns.reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0))}</div><div style="font-size:10px;color:var(--g1)">Entries ${diagnosticTxns.length}</div></div>
          <div style="background:var(--g6);border-radius:8px;padding:8px"><div style="font-size:10px;color:var(--g1);font-weight:800">Surgery Collection</div><div style="font-size:16px;font-weight:900">${fmt(surgeryTxns.reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0))}</div><div style="font-size:10px;color:var(--g1)">Cases ${deptOt.length}</div></div>
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px">
          <div style="border:1px solid var(--g5);border-radius:8px;padding:8px">
            <div style="font-size:10px;font-weight:900;color:#1a8c3c;text-transform:uppercase;margin-bottom:6px">Cash Payments</div>
            ${cashGroups.length ? cashGroups.map(function (row) { return `<div style="display:flex;justify-content:space-between;gap:8px;font-size:11px;padding:4px 0;border-bottom:1px solid var(--g5)"><span>${esc(row.label)} <span style="color:var(--g1)">(${row.count})</span></span><strong>${fmt(row.amount)}</strong></div>`; }).join('') : '<div style="font-size:11px;color:var(--g1)">No cash collection</div>'}
          </div>
          <div style="border:1px solid var(--g5);border-radius:8px;padding:8px">
            <div style="font-size:10px;font-weight:900;color:var(--bmh-blue);text-transform:uppercase;margin-bottom:6px">Online Payments</div>
            ${onlineGroups.length ? onlineGroups.map(function (row) { return `<div style="display:flex;justify-content:space-between;gap:8px;font-size:11px;padding:4px 0;border-bottom:1px solid var(--g5)"><span>${esc(row.label)} <span style="color:var(--g1)">(${row.count})</span></span><strong>${fmt(row.amount)}</strong></div>`; }).join('') : '<div style="font-size:11px;color:var(--g1)">No online collection</div>'}
          </div>
          <div style="border:1px solid var(--g5);border-radius:8px;padding:8px">
            <div style="font-size:10px;font-weight:900;color:#b55a00;text-transform:uppercase;margin-bottom:6px">TPA / Cashless Due</div>
            <div style="font-size:18px;font-weight:900;color:#b55a00;margin-bottom:6px">${fmt(claimDue)}</div>
            ${deptClaims.length ? deptClaims.map(function (r) { const insurerDue = Math.max(0, Number(r.claimedAmount || r.amount || 0) - Number(r.receivedAmount || 0)); const patientDue = Number(r.patientDue || 0); const parts = []; if (insurerDue > 0) parts.push('Insurer ' + fmt(insurerDue)); if (patientDue > 0) parts.push('Patient ' + fmt(patientDue)); return `<div style="font-size:11px;padding:4px 0;border-bottom:1px solid var(--g5)"><strong>${esc(r.patient || 'Patient')}</strong><div style="color:var(--g1)">${esc(r.procedure || r.for || 'Claim')} · ${esc(parts.join(' · ') || fmt(0))}</div></div>`; }).join('') : '<div style="font-size:11px;color:var(--g1)">No cashless due</div>'}
          </div>
        </div>
      </div>`;
    }).join('');
    const centreOpdCount = deptMeta.reduce(function (sum, dept) {
      const deptPatients = patients.filter(function (p) { return normalizeDeptKeyForQueue(p.dept || '') === dept.key; });
      const consultPatients = deptPatients.filter(function (p) {
        return !/diagnostic|investigation|procedure only|lab/i.test(String(p.purpose || ''));
      });
      const deptConsultTxns = txns.filter(function (t) {
        return normalizeDeptKeyForQueue(t.dept || '') === dept.key
          && inferChargeCategoryFromService(t.service || t.for || t.desc || '') === 'consultation';
      });
      return sum + getConsultationCounter(deptPatients, consultPatients, deptConsultTxns);
    }, 0);
    return {
      code: centreCode,
      total: centreTotal,
      tpaDue: centreTpaDue,
      opd: centreOpdCount,
      surgeries: otCases.length,
      html: `<div class="card" style="padding:14px;margin-bottom:12px">
        <div style="display:flex;justify-content:space-between;gap:10px;align-items:flex-start;flex-wrap:wrap;margin-bottom:10px">
          <div>
            <div style="font-size:16px;font-weight:900;color:${centreMeta[centreCode].tone}">${centreMeta[centreCode].label}</div>
            <div style="font-size:11px;color:var(--g1)">Daily statement for ${formatDateIN(selectedDate)}</div>
          </div>
          <div style="display:flex;gap:8px;flex-wrap:wrap">
            <div style="background:var(--g6);border-radius:10px;padding:8px 10px;text-align:center;min-width:110px"><div style="font-size:10px;color:var(--g1);font-weight:800">OPD Entries</div><div style="font-size:18px;font-weight:900">${centreOpdCount}</div></div>
            <div style="background:var(--g6);border-radius:10px;padding:8px 10px;text-align:center;min-width:110px"><div style="font-size:10px;color:var(--g1);font-weight:800">Collected</div><div style="font-size:18px;font-weight:900;color:${centreMeta[centreCode].tone}">${fmt(centreTotal)}</div></div>
            <div style="background:var(--g6);border-radius:10px;padding:8px 10px;text-align:center;min-width:110px"><div style="font-size:10px;color:var(--g1);font-weight:800">TPA Due</div><div style="font-size:18px;font-weight:900;color:#b55a00">${fmt(centreTpaDue)}</div></div>
          </div>
        </div>
        ${deptBlocks}
      </div>`
    };
  });
  const summaryEl = document.getElementById('centres-summary-blocks');
  if (summaryEl) {
    const allTotal = centreSheets.reduce(function (s, c) { return s + c.total; }, 0);
    const allTpa = centreSheets.reduce(function (s, c) { return s + c.tpaDue; }, 0);
    const allOpd = centreSheets.reduce(function (s, c) { return s + c.opd; }, 0);
    summaryEl.innerHTML = `
      <div class="sc green"><div class="sc-lbl">Total Collection</div><div class="sc-val green">${fmt(allTotal)}</div></div>
      <div class="sc blue"><div class="sc-lbl">Total OPD Entries</div><div class="sc-val blue">${allOpd}</div></div>
      <div class="sc orange"><div class="sc-lbl">TPA / Cashless Due</div><div class="sc-val orange">${fmt(allTpa)}</div></div>
      <div class="sc red"><div class="sc-lbl">Centres Covered</div><div class="sc-val red">${centreSheets.length}</div></div>
    `;
  }
  const sheetEl = document.getElementById('centres-daily-sheet');
  if (sheetEl) {
    const sheetsHtml = centreSheets.map(function (c) { return c.html; }).join('');
    sheetEl.innerHTML = sheetsHtml
      ? '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(340px,1fr));gap:12px">' + sheetsHtml + '</div>'
      : '<div class="card" style="padding:16px;color:var(--g1)">No daily data found for this date.</div>';
  }
}
function renderCentresCharges(){
  const el=document.getElementById('centres-charge-list');if(!el)return;
  el.innerHTML=`<div style="display:grid;grid-template-columns:1fr 100px 100px 50px;gap:4px;padding:5px 11px;background:var(--g6);font-size:10px;font-weight:800;color:var(--g1);text-transform:uppercase;border-radius:6px 6px 0 0">
    <span>Procedure / Service</span><span style="text-align:center">CHD (₹)</span><span style="text-align:center">RPR (₹)</span><span></span>
  </div>`+
  Object.entries(CENTRE_CHARGES.CHD).map(([k,v])=>`
    <div style="display:grid;grid-template-columns:1fr 100px 100px 50px;gap:4px;padding:5px 11px;border-bottom:1px solid var(--g5);font-size:12px;align-items:center">
      <span style="font-weight:600">${k}</span>
      <input type="number" value="${v}" style="text-align:right;font-weight:800;color:var(--bmh-blue);font-size:12px;border:1px solid var(--g4);border-radius:4px;padding:2px 5px;width:100%" onchange="CENTRE_CHARGES.CHD['${k}']=+this.value;saveChargesToFirebase().then(function(){showToast('Saved ✓','s');})">
      <input type="number" value="${CENTRE_CHARGES.RPR[k]||v}" style="text-align:right;font-weight:800;color:#8a4200;font-size:12px;border:1px solid var(--g4);border-radius:4px;padding:2px 5px;width:100%" onchange="CENTRE_CHARGES.RPR['${k}']=+this.value;saveChargesToFirebase().then(function(){showToast('Saved ✓','s');})">
      <button onclick="deleteCharge('${k}')" style="background:none;border:none;color:var(--red);font-size:14px;cursor:pointer;padding:0">✕</button>
    </div>`).join('')+
  `<div style="padding:8px 11px;display:flex;gap:6px;flex-wrap:wrap">
    <input type="text" id="new-charge-name" placeholder="New service name…" style="flex:2;min-width:140px;font-size:12px">
    <input type="number" id="new-charge-chd" placeholder="CHD ₹" style="width:90px;font-size:12px">
    <input type="number" id="new-charge-rpr" placeholder="RPR ₹" style="width:90px;font-size:12px">
    <button class="btn btn-gold btn-sm" onclick="addNewCharge()">+ Add</button>
  </div>`;
}
function deleteCharge(name){
  const label = 'Charge — ' + name;
  if (CURRENT_USER?.isAdmin) {
    delete CENTRE_CHARGES.CHD[name]; delete CENTRE_CHARGES.RPR[name];
    const idx = CHARGES_DATA.findIndex(function (c) { return c.name === name; });
    if (idx > -1) CHARGES_DATA.splice(idx, 1);
    saveChargesToFirebase(); renderCentresCharges(); renderChargesList && renderChargesList();
    showToast('Charge deleted ✓', 's');
  } else {
    requestDeletion('charge', name, label);
  }
}
function addNewCharge(){
  const n=document.getElementById('new-charge-name')?.value?.trim();
  const c=parseFloat(document.getElementById('new-charge-chd')?.value||0);
  const r=parseFloat(document.getElementById('new-charge-rpr')?.value||0);
  if(!n){showToast('Enter service name','w');return;}
  CENTRE_CHARGES.CHD[n]=c; CENTRE_CHARGES.RPR[n]=r||c;
  document.getElementById('new-charge-name').value='';
  document.getElementById('new-charge-chd').value='';
  document.getElementById('new-charge-rpr').value='';
  saveChargesToFirebase().then(function(){showToast('Charge added & saved to database ✓','s');renderCentresCharges();renderChargesList&&renderChargesList();});
}
function saveChargesToLocalStorage() {
  try {
    const next = JSON.stringify(CHARGES_DATA);
    const prev = localStorage.getItem('bmh_charges_schedule');
    if (prev && prev !== next) localStorage.setItem('bmh_charges_schedule_archive', prev);
    localStorage.setItem('bmh_charges_schedule', next);
    localStorage.setItem('bmh_charges_schedule_backup', next);
    localStorage.setItem('bmh_centre_charges', JSON.stringify(CENTRE_CHARGES));
    localStorage.setItem('bmh_charges_schedule_updated_at', String(Date.now()));
    window._bmhLastLocalChargesRows = normalizeChargesRows(CHARGES_DATA).slice();
  } catch (e) { /* quota */ }
}
window._bmhLastLocalChargesRows = window._bmhLastLocalChargesRows || [];
window._bmhChargesCloudLoaded = !!window._bmhChargesCloudLoaded;
function normalizeChargesRows(raw) {
  if (Array.isArray(raw)) return raw.filter(Boolean);
  if (raw && typeof raw === 'object') {
    return Object.keys(raw).sort(function (a, b) {
      return String(a).localeCompare(String(b), undefined, { numeric: true, sensitivity: 'base' });
    }).map(function (key) {
      return raw[key];
    }).filter(Boolean);
  }
  return [];
}
function scoreChargesRows(rows) {
  const list = Array.isArray(rows) ? rows : [];
  const parents = new Set();
  const customKinds = new Set();
  list.forEach(function (row) {
    const parent = String(row?.parent || '').trim();
    if (parent) parents.add(parent);
    const kind = String(row?.kind || '').trim();
    if (kind) customKinds.add(kind);
  });
  return (list.length * 10) + (parents.size * 20) + (customKinds.size * 5);
}
function choosePreferredChargesRows(localRows, remoteRows, localTs, remoteTs) {
  const localList = normalizeChargesRows(localRows);
  const remoteList = normalizeChargesRows(remoteRows);
  if (!remoteList.length) return localList;
  if (!localList.length) return remoteList;
  const lts = Number(localTs || 0);
  const rts = Number(remoteTs || 0);
  if (lts && rts && lts !== rts) return lts > rts ? localList : remoteList;
  return scoreChargesRows(localList) > scoreChargesRows(remoteList) ? localList : remoteList;
}
const LEGACY_PMICS_CHARGE_HEADING = 'Pinhole Microincision Cataract Surgery + IOL Implantation';
const PMICS_MAIN_CHARGE_HEADING = 'Pinhole Microincision Cataract Surgery';
function migrateLegacyPmicsChargeParents() {
  if (!Array.isArray(CHARGES_DATA)) return;
  CHARGES_DATA.forEach(function (row) {
    if (!row) return;
    if (String(row.parent || '') === LEGACY_PMICS_CHARGE_HEADING) row.parent = PMICS_MAIN_CHARGE_HEADING;
    if (String(row.name || '') === LEGACY_PMICS_CHARGE_HEADING) row.name = PMICS_MAIN_CHARGE_HEADING;
  });
}
function applyLoadedChargesRows(rows) {
  if (!Array.isArray(rows) || !rows.length) return false;
  CHARGES_DATA.length = 0;
  rows.forEach(function (row) {
    if (!row || typeof row !== 'object') return;
    CHARGES_DATA.push({
      cat: row.cat || '',
      kind: row.kind || row.cat || 'procedure',
      parent: row.parent || '',
      name: row.name || '',
      chd: Number(row.chd || 0),
      rpr: Number(row.rpr || 0)
    });
  });
  migrateLegacyPmicsChargeParents();
  CHARGES_DATA.forEach(function (c) {
    if (!c.name) return;
    CENTRE_CHARGES.CHD[c.name] = c.chd;
    CENTRE_CHARGES.RPR[c.name] = c.rpr;
  });
  ensureCriticalChargesLoaded();
  return CHARGES_DATA.length > 0;
}
function loadChargesFromLocalStorage() {
  try {
    const sch = localStorage.getItem('bmh_charges_schedule') || localStorage.getItem('bmh_charges_schedule_backup') || localStorage.getItem('bmh_charges_schedule_archive');
    if (sch) {
      const arr = normalizeChargesRows(JSON.parse(sch));
      window._bmhLastLocalChargesRows = arr.slice();
      applyLoadedChargesRows(arr);
    }
    window._bmhLastLocalChargesUpdatedAt = Number(localStorage.getItem('bmh_charges_schedule_updated_at') || 0) || 0;
    const cc = localStorage.getItem('bmh_centre_charges');
    if (cc) {
      const d = JSON.parse(cc);
      if (d && d.CHD) Object.assign(CENTRE_CHARGES.CHD, d.CHD);
      if (d && d.RPR) Object.assign(CENTRE_CHARGES.RPR, d.RPR);
    }
    ensureCriticalChargesLoaded();
  } catch (e) { /* noop */ }
}
function saveChargesToFirebase(){
  saveChargesToLocalStorage();
  if(!window.FBDB) { showToast('Saved locally ✓', 's'); return Promise.resolve(); }
  if (!window._bmhChargesCloudLoaded) {
    window._bmhPendingChargesSync = true;
    console.warn('Queueing charge cloud sync until saved charges finish loading');
    showToast('Saved locally ✓ Cloud sync queued', 's');
    return Promise.resolve({ queued: true });
  }
  return Promise.all([
    window.FBDB.ref('centreCharges').set(CENTRE_CHARGES),
    window.FBDB.ref('chargesSchedule').set(CHARGES_DATA),
    window.FBDB.ref('chargesScheduleMeta').set({ updatedAt: Date.now() })
  ]).then(function(res){
    try { populateOTProcedureMainSelect && populateOTProcedureMainSelect(); } catch (e) {}
    try { renderOTProcedureSubheading && renderOTProcedureSubheading(document.getElementById('ot-add-proc-main')?.value || ''); } catch (e) {}
    try { refreshRxTemplateSurgeryDatalist && refreshRxTemplateSurgeryDatalist(); } catch (e) {}
    try { refreshOTFollowupTemplateSelect && refreshOTFollowupTemplateSelect(); } catch (e) {}
    showToast('Saved to database ✓', 's');
    return res;
  }).catch(function(err){
    console.warn('saveChargesToFirebase error:', err);
    throw err;
  });
}
function loadChargesFromFirebase(){
  loadChargesFromLocalStorage();
  renderChargesList && renderChargesList();
  renderCentresCharges && renderCentresCharges();
  syncReceptionConsultationFee && syncReceptionConsultationFee();
  if(!window.FBDB) return;
  window.FBDB.ref('centreCharges').once('value').then(snap=>{
    const d=snap.val(); if(!d) return;
    if(d.CHD) Object.assign(CENTRE_CHARGES.CHD, d.CHD);
    if(d.RPR) Object.assign(CENTRE_CHARGES.RPR, d.RPR);
    ensureCriticalChargesLoaded();
    saveChargesToLocalStorage();
    renderCentresCharges && renderCentresCharges();
    syncReceptionConsultationFee && syncReceptionConsultationFee();
  }).catch(()=>{});
  Promise.all([
    window.FBDB.ref('chargesSchedule').once('value'),
    window.FBDB.ref('chargesScheduleMeta').once('value')
  ]).then(function (pairs) {
    const snap = pairs[0];
    const metaSnap = pairs[1];
    const remoteTs = Number(metaSnap && metaSnap.val && metaSnap.val()?.updatedAt || 0) || 0;
    const arr = choosePreferredChargesRows(window._bmhLastLocalChargesRows, snap.val(), window._bmhLastLocalChargesUpdatedAt, remoteTs);
    window._bmhChargesCloudLoaded = true;
    if (!applyLoadedChargesRows(arr)) return;
    saveChargesToLocalStorage();
    renderChargesList && renderChargesList();
    renderCentresCharges && renderCentresCharges();
    syncReceptionConsultationFee && syncReceptionConsultationFee();
    try { populateOTProcedureMainSelect && populateOTProcedureMainSelect(); } catch (e) {}
    try { renderOTProcedureSubheading && renderOTProcedureSubheading(document.getElementById('ot-add-proc-main')?.value || ''); } catch (e) {}
    try { refreshRxTemplateSurgeryDatalist && refreshRxTemplateSurgeryDatalist(); } catch (e) {}
    try { refreshOTFollowupTemplateSelect && refreshOTFollowupTemplateSelect(); } catch (e) {}
    if (window._bmhPendingChargesSync) {
      window._bmhPendingChargesSync = false;
      saveChargesToFirebase().catch(function () {});
    }
  }).catch(()=>{
    window._bmhChargesCloudLoaded = true;
  });
}

// ── Print letterhead / footer (Settings → Hospital) — used on prescription printouts
function persistPrintLetterheadLocalOnly() {
  try {
    localStorage.setItem('bmh_print_letterhead', JSON.stringify({
      header: window.PRINT_HEADER_SRC || '',
      footer: window.PRINT_FOOTER_SRC || ''
    }));
  } catch (e) { /* quota */ }
}
function updatePrintLetterheadPreviews() {
  const h = document.getElementById('print-header-preview');
  const f = document.getElementById('print-footer-preview');
  if (h) {
    if (window.PRINT_HEADER_SRC) { h.src = window.PRINT_HEADER_SRC; h.style.display = 'block'; }
    else { h.removeAttribute('src'); h.style.display = 'none'; }
  }
  if (f) {
    if (window.PRINT_FOOTER_SRC) { f.src = window.PRINT_FOOTER_SRC; f.style.display = 'block'; }
    else { f.removeAttribute('src'); f.style.display = 'none'; }
  }
}
function onPickPrintHeader(inp) {
  const file = inp.files && inp.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = function (e) {
    window.PRINT_HEADER_SRC = e.target.result;
    persistPrintLetterheadLocalOnly();
    if (window.FBDB) window.FBDB.ref('printLetterhead').set({ header: window.PRINT_HEADER_SRC, footer: window.PRINT_FOOTER_SRC || '' }).catch(function () {});
    updatePrintLetterheadPreviews();
    showToast('Header image saved ✓', 's');
    inp.value = '';
  };
  reader.readAsDataURL(file);
}
function onPickPrintFooter(inp) {
  const file = inp.files && inp.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = function (e) {
    window.PRINT_FOOTER_SRC = e.target.result;
    persistPrintLetterheadLocalOnly();
    if (window.FBDB) window.FBDB.ref('printLetterhead').set({ header: window.PRINT_HEADER_SRC || '', footer: window.PRINT_FOOTER_SRC }).catch(function () {});
    updatePrintLetterheadPreviews();
    showToast('Footer image saved ✓', 's');
    inp.value = '';
  };
  reader.readAsDataURL(file);
}
function clearPrintHeader() {
  window.PRINT_HEADER_SRC = '';
  persistPrintLetterheadLocalOnly();
  if (window.FBDB) window.FBDB.ref('printLetterhead').set({ header: '', footer: window.PRINT_FOOTER_SRC || '' }).catch(function () {});
  updatePrintLetterheadPreviews();
  showToast('Header removed', 'i');
}
function clearPrintFooter() {
  window.PRINT_FOOTER_SRC = '';
  persistPrintLetterheadLocalOnly();
  if (window.FBDB) window.FBDB.ref('printLetterhead').set({ header: window.PRINT_HEADER_SRC || '', footer: '' }).catch(function () {});
  updatePrintLetterheadPreviews();
  showToast('Footer removed', 'i');
}
function loadPrintLetterheadFromStorage() {
  try {
    const ls = localStorage.getItem('bmh_print_letterhead');
    if (ls) {
      const o = JSON.parse(ls);
      if (o.header) window.PRINT_HEADER_SRC = o.header;
      if (o.footer) window.PRINT_FOOTER_SRC = o.footer;
    }
  } catch (e) { /* noop */ }
  if (!window.FBDB) {
    updatePrintLetterheadPreviews();
    return;
  }
  window.FBDB.ref('printLetterhead').once('value').then(function (snap) {
    const v = snap.val();
    if (v) {
      if (v.header) window.PRINT_HEADER_SRC = v.header;
      if (v.footer) window.PRINT_FOOTER_SRC = v.footer;
      persistPrintLetterheadLocalOnly();
    }
    updatePrintLetterheadPreviews();
  }).catch(function () { updatePrintLetterheadPreviews(); });
}

