function lookupByBMHID(val) {
  const el = document.getElementById('rc-bmhid-result'); if(!el) return;
  if(!val || val.length < 3) { el.innerHTML=''; return; }
  const v = val.trim().toUpperCase();
  const vLow = val.trim().toLowerCase();
  const digits = String(val || '').replace(/\D/g, '');
  const byPhoneMatch = function (p) {
    const nums = [p?.mob, p?.mobile, p?.mob2, p?.altMobile].map(function (x) { return String(x || '').replace(/\D/g, ''); }).filter(Boolean);
    return digits.length >= 6 && nums.some(function (n) { return n.includes(digits); });
  };
  // Search by BMSH ID, phone, or name
  const activePatients = (PATIENTS || []).filter(function (p) { return !isMergedPatientRecord(p); });
  const mergedById = (PATIENTS || []).find(function (p) {
    return String(p?.bmhId || '').toUpperCase() === v && p?.mergedInto;
  });
  const byId = (mergedById && activePatients.find(function (p) { return String(p?.bmhId || '') === String(mergedById.mergedInto || ''); }))
    || activePatients.find(p => String(p.bmhId || '').toUpperCase() === v || String(p.bmhId || '').toUpperCase().includes(v.replace('BMSH-','')));
  const phoneMatches = activePatients.filter(byPhoneMatch);
  const byPhone = phoneMatches.length === 1 ? phoneMatches[0] : null;
  const byName = val.length >= 3 ? activePatients.filter(p => p.name?.toLowerCase().includes(vLow)) : [];
  const single = byId || byPhone;
  if(single) {
    el.innerHTML = `<div style="background:var(--green-lt);border-radius:8px;padding:10px;border-left:3px solid var(--green)">
      <div style="display:flex;align-items:center;gap:8px">
        <div style="flex:1">
          <div style="font-size:11px;font-weight:800;color:#1a8c3c;margin-bottom:2px">✅ Found — existing patient</div>
          <div style="font-size:13px;font-weight:900">${single.name} <span style="font-size:10.5px;color:var(--g1);font-weight:500">(${single.age || '—'}Y / ${single.sex || '—'})</span></div>
          <div style="font-family:var(--mono);font-size:10px;color:var(--bmh-teal)">${single.bmhId} · ${single.mob||'—'} · Visits: ${single.visitCount||1}</div>
        </div>
        <div style="display:flex;flex-direction:column;gap:4px">
          <button class="btn btn-xs btn-gold" onclick="prefillExistingPatient('${single.bmhId}')">✏️ Prefill &amp; Register</button>
          <button class="btn btn-xs btn-outline" onclick="openPatient('${single.bmhId}')">👁️ View Record</button>
        </div>
      </div>
    </div>`;
  } else if(phoneMatches.length > 1) {
    const hits = phoneMatches.slice(0, 8);
    el.innerHTML = `<div style="background:#fff;border:1.5px solid var(--orange);border-radius:8px;overflow:hidden">
      <div style="padding:5px 10px;background:var(--orange-lt);font-size:10px;font-weight:800;color:var(--orange);text-transform:uppercase">Same phone — ${phoneMatches.length} patients (pick one or register new)</div>
      ${hits.map(p=>`<div style="display:flex;align-items:center;gap:9px;padding:8px 12px;cursor:pointer;border-bottom:1px solid var(--g5)" onmouseover="this.style.background='var(--g6)'" onmouseout="this.style.background=''">
        <div style="width:30px;height:30px;border-radius:50%;background:${p.color||'#1A3C6E'};color:#fff;display:flex;align-items:center;justify-content:center;font-weight:900;font-size:11px;flex-shrink:0">${p.initials||p.name[0]||'?'}</div>
        <div style="flex:1;min-width:0">
          <div style="font-weight:800;font-size:12.5px">${p.name}</div>
          <div style="font-size:10px;color:var(--g1);font-family:var(--mono)">${p.bmhId} · ${p.age||'?'}Y/${(p.sex||'?')[0]} · ${p.mob||'—'}</div>
        </div>
        <button class="btn btn-xs btn-gold" onclick="prefillExistingPatient('${p.bmhId}')">✏️ Prefill</button>
        <button class="btn btn-xs btn-outline" onclick="openPatient('${p.bmhId}')">👁️</button>
      </div>`).join('')}
    </div>`;
  } else if(byName.length) {
    // Show name search results (up to 5)
    const hits = byName.slice(0,5);
    el.innerHTML = `<div style="background:#fff;border:1.5px solid var(--blue);border-radius:8px;overflow:hidden">
      <div style="padding:5px 10px;background:var(--blue-lt);font-size:10px;font-weight:800;color:var(--blue);text-transform:uppercase">Found ${byName.length} patient${byName.length>1?'s':''} matching "${val}"</div>
      ${hits.map(p=>`<div style="display:flex;align-items:center;gap:9px;padding:8px 12px;cursor:pointer;border-bottom:1px solid var(--g5)" onmouseover="this.style.background='var(--g6)'" onmouseout="this.style.background=''">
        <div style="width:30px;height:30px;border-radius:50%;background:${p.color||'#1A3C6E'};color:#fff;display:flex;align-items:center;justify-content:center;font-weight:900;font-size:11px;flex-shrink:0">${p.initials||p.name[0]||'?'}</div>
        <div style="flex:1;min-width:0">
          <div style="font-weight:800;font-size:12.5px">${p.name}</div>
          <div style="font-size:10px;color:var(--g1);font-family:var(--mono)">${p.bmhId} · ${p.age||'?'}Y/${(p.sex||'?')[0]} · ${p.mob||'—'}</div>
        </div>
        <button class="btn btn-xs btn-gold" onclick="prefillExistingPatient('${p.bmhId}')">✏️ Prefill</button>
        <button class="btn btn-xs btn-outline" onclick="openPatient('${p.bmhId}')">👁️</button>
      </div>`).join('')}
    </div>`;
  } else {
    el.innerHTML = val.length >= 4 ? `<div style="font-size:11px;color:var(--g1);padding:5px 8px;background:var(--g6);border-radius:6px">🆕 No existing patient found — proceed with new registration below</div>` : '';
  }
}

function openQRScanner() {
  const modal = document.getElementById('m-qr-scanner');
  if(modal) { openM('m-qr-scanner'); startQRCamera(); return; }
  const div = document.createElement('div');
  div.id = 'm-qr-scanner';
  div.className = 'modal-ov';
  div.innerHTML = `<div class="modal" style="max-width:440px">
    <div class="modal-hd"><div class="modal-title">📷 Scan Patient QR Code</div><button class="modal-close" onclick="closeQRScanner()">✕</button></div>
    <div style="padding:16px">
      <div style="background:var(--g6);border-radius:8px;padding:12px;margin-bottom:12px;font-size:12px;color:var(--g1)">
        Point camera at the QR code on the patient's prescription. The BMSH ID will be extracted automatically.
      </div>
      <video id="qr-video" style="width:100%;border-radius:8px;background:#000;max-height:280px" autoplay playsinline></video>
      <canvas id="qr-canvas-scan" style="display:none"></canvas>
      <div id="qr-scan-result" style="margin-top:10px;font-size:13px;font-weight:700;text-align:center;min-height:24px"></div>
      <div style="margin-top:10px;display:flex;gap:8px">
        <input type="text" id="qr-manual-id" placeholder="Enter BMSH ID manually if needed" style="flex:1">
        <button class="btn btn-gold btn-sm" onclick="submitManualQrId()">Use ID</button>
      </div>
      <div style="margin-top:10px;display:flex;gap:8px">
        <label class="btn btn-outline btn-sm" style="flex:1;justify-content:center;cursor:pointer">
          📁 Upload Image <input type="file" accept="image/*" style="display:none" onchange="readQRFromFile(this)">
        </label>
        <button class="btn btn-gray btn-sm" onclick="closeQRScanner()">Cancel</button>
      </div>
    </div>
  </div>`;
  document.body.appendChild(div);
  openM('m-qr-scanner');
  startQRCamera();
}

function extractBmhIdFromQr(raw) {
  const text = String(raw || '').trim();
  if (!text) return '';
  const upper = text.toUpperCase();
  const direct = upper.match(/BMSH[-\s]*\d+/i);
  if (direct && direct[0]) return direct[0].replace(/\s+/g, '').replace(/BMSH[-\s]*/i, 'BMSH-');
  try {
    const url = new URL(text);
    const candidates = [
      url.searchParams.get('bmhId'),
      url.searchParams.get('bmshId'),
      url.searchParams.get('id'),
      url.pathname.split('/').filter(Boolean).pop()
    ].filter(Boolean);
    for (const c of candidates) {
      const hit = String(c).toUpperCase().match(/BMSH[-\s]*\d+/i);
      if (hit && hit[0]) return hit[0].replace(/\s+/g, '').replace(/BMSH[-\s]*/i, 'BMSH-');
      if (/^\d{4,}$/.test(String(c).trim())) return 'BMSH-' + String(c).trim();
    }
  } catch (e) {}
  const digits = upper.match(/\b\d{4,}\b/);
  if (digits && digits[0]) return 'BMSH-' + digits[0];
  return upper;
}

function completeQrLookup(rawId) {
  const id = extractBmhIdFromQr(rawId);
  if (!id) return;
  const clean = id.startsWith('BMSH-') ? id : ('BMSH-' + id.replace(/^BMSH[-\s]*/i, ''));
  const search = document.getElementById('rc-bmhid-search');
  if (search) search.value = clean;
  lookupByBMHID(clean);
  const patient = (PATIENTS || []).find(function (p) {
    const pid = String(p?.bmhId || '').toUpperCase();
    return pid === clean || pid === id || pid.includes(clean.replace('BMSH-', ''));
  }) || null;
  const resolvedPatient = patient?.mergedInto
    ? (PATIENTS || []).find(function (p) { return String(p?.bmhId || '') === String(patient.mergedInto || ''); }) || patient
    : patient;
  closeQRScanner();
  if (resolvedPatient && resolvedPatient.bmhId) {
    prefillExistingPatient(resolvedPatient.bmhId);
    showToast('QR scanned and patient loaded ✓', 's');
  } else {
    showToast('QR scanned — review search result below', 's');
  }
}

async function decodeQrFromCanvas(canvas) {
  if (!canvas) return '';
  try {
    if (typeof BarcodeDetector !== 'undefined') {
      const detector = new BarcodeDetector({ formats: ['qr_code'] });
      const codes = await detector.detect(canvas);
      const raw = codes && codes[0] && (codes[0].rawValue || codes[0].rawData || '');
      if (String(raw || '').trim()) return String(raw || '').trim();
    }
  } catch (e) {}
  try {
    const ctx = canvas.getContext('2d', { willReadFrequently: true }) || canvas.getContext('2d');
    const imageData = ctx?.getImageData(0, 0, canvas.width, canvas.height);
    const fallbackRaw = window.BMH_QR_DECODE ? window.BMH_QR_DECODE(imageData) : '';
    return String(fallbackRaw || '').trim();
  } catch (e) {
    return '';
  }
}

function submitManualQrId() {
  const inp = document.getElementById('qr-manual-id');
  const id = inp?.value?.trim();
  if (!id) { showToast('Enter a BMSH ID', 'w'); return; }
  completeQrLookup(id);
}

function startQRCamera() {
  const video = document.getElementById('qr-video');
  if(!video) return;
  const resultEl = document.getElementById('qr-scan-result');
  if (resultEl) resultEl.textContent = 'Opening camera…';
  window._bmhQrScanActive = true;
  navigator.mediaDevices?.getUserMedia({video:{facingMode:'environment'}}).then(stream=>{
    video._stream = stream;
    video.srcObject = stream;
    const loop = async function () {
      if (!window._bmhQrScanActive) return;
      try {
        if (video.readyState >= 2 && typeof BarcodeDetector !== 'undefined') {
          const canvas = document.getElementById('qr-canvas-scan');
          if (canvas) {
            canvas.width = video.videoWidth || 640;
            canvas.height = video.videoHeight || 480;
            const ctx = canvas.getContext('2d');
            ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
            const raw = await decodeQrFromCanvas(canvas);
            if (raw) {
              if (resultEl) resultEl.textContent = 'QR detected: ' + raw;
              completeQrLookup(raw);
              return;
            }
          }
        }
      } catch (e) {}
      requestAnimationFrame(loop);
    };
    requestAnimationFrame(loop);
  }).catch(()=>{ if(resultEl) resultEl.textContent = 'Camera not available — use Upload Image or enter BMSH ID manually.'; });
}

function closeQRScanner() {
  window._bmhQrScanActive = false;
  const video = document.getElementById('qr-video');
  if(video?._stream) video._stream.getTracks().forEach(t=>t.stop());
  closeM('m-qr-scanner');
}

function readQRFromFile(input) {
  const file = input.files[0]; if(!file) return;
  const reader = new FileReader();
  reader.onload = async e => {
    const img = new Image();
    img.onload = async () => {
      const canvas = document.createElement('canvas');
      canvas.width=img.width; canvas.height=img.height;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(img,0,0);
      const el = document.getElementById('qr-scan-result');
      if(el) el.textContent = 'Processing image…';
      const decoded = await decodeQrFromCanvas(canvas);
      if (decoded) {
        if (el) el.textContent = 'QR detected: ' + decoded;
        completeQrLookup(decoded);
        return;
      }
      if(el) el.textContent = 'QR not detected — enter the BMSH ID manually below.';
    };
    img.src = e.target.result;
  };
  reader.readAsDataURL(file);
}

function lookupByPhone(val) {
  const matchEl = document.getElementById('rc-phone-match'); if(!matchEl) return;
  if(val.length < 7) { matchEl.innerHTML=''; return; }
  const dig = val.replace(/\s/g,'').replace(/\D/g,'');
  const tail = dig.slice(-10) || dig.slice(-7);
  // Find all matches (multiple patients with similar phone)
  const matches = PATIENTS.filter(function (p) {
    if (!p || isMergedPatientRecord(p)) return false;
    const nums = [p.mob, p.mobile, p.mob2, p.altMobile].map(function (x) { return String(x || '').replace(/\D/g, ''); }).filter(Boolean);
    return nums.some(function (n) { return tail.length >= 7 && n.includes(tail); });
  });
  if(matches.length) {
    matchEl.innerHTML = matches.map(match=>`
      <div style="background:var(--green-lt);border-radius:8px;padding:10px;margin-bottom:6px;border-left:3px solid var(--green)">
        <div style="display:flex;align-items:center;gap:8px">
          <div style="flex:1">
            <div style="font-size:11px;font-weight:800;color:#1a8c3c;margin-bottom:2px">✅ Existing patient found</div>
            <div style="font-size:12.5px;font-weight:900">${match.name} <span style="font-size:10.5px;color:var(--g1);font-weight:500">(${match.age||'?'}Y / ${match.sex||'?'})</span></div>
            <div style="font-family:var(--mono);font-size:10px;color:var(--bmh-teal)">${match.bmhId} · Visits: ${match.visitCount||1}</div>
          </div>
          <div style="display:flex;flex-direction:column;gap:4px">
            <button class="btn btn-xs btn-gold" onclick="prefillExistingPatient('${match.bmhId}')">✏️ Prefill &amp; Register</button>
            <button class="btn btn-xs btn-outline" onclick="openPatient('${match.bmhId}')">👁️ View Record</button>
          </div>
        </div>
      </div>`).join('');
  } else { matchEl.innerHTML=''; }
}
function prefillExistingPatient(bmhId) {
  const p = (typeof resolveExistingPatientForRegistration === 'function' ? resolveExistingPatientForRegistration(bmhId) : null)
    || PATIENTS.find(function (x) { return String(x?.bmhId || '') === String(bmhId || ''); });
  if(!p) { showToast('Patient not found for prefill', 'w'); return; }
  const name = String(p.name || p.patient || '').trim();
  const fn = document.getElementById('rc-fn'); if(fn) fn.value = name.split(' ')[0]||'';
  const ln = document.getElementById('rc-ln'); if(ln) ln.value = name.split(' ').slice(1).join(' ')||'';
  const rel = document.getElementById('rc-rel'); if(rel) rel.value = p.rel||'';
  const mob = document.getElementById('rc-mob-inp')||document.getElementById('rc-mob'); if(mob) mob.value = p.mob||p.mobile||'';
  const mob2 = document.getElementById('rc-mob2'); if(mob2) mob2.value = p.mob2||'';
  const email = document.getElementById('rc-email'); if(email) email.value = p.email||'';
  const addr = document.getElementById('rc-addr'); if(addr) addr.value = p.addr||'';
  const dob = document.getElementById('rc-dob'); if(dob) { dob.value = p.dob||''; calcRcAge && calcRcAge(); }
  const sex = document.getElementById('rc-sex'); if(sex && p.sex) sex.value = p.sex;
  const age = document.getElementById('rc-age'); if(age) age.value = p.age||'';
  const dept = document.getElementById('rc-dept'); if(dept && p.dept) { dept.value = p.dept; updateRcDr&&updateRcDr(); updatePurposeOptions&&updatePurposeOptions(); }
  const dr = document.getElementById('rc-dr'); if(dr && p.doctor) dr.value = p.doctor;
  const uidEl = document.getElementById('rc-uid'); if(uidEl) uidEl.textContent = p.bmhId;
  const prefillBadge = document.getElementById('rc-prefill-badge');
  if (prefillBadge) {
    prefillBadge.textContent = 'Prefilled from existing patient: ' + p.bmhId;
    prefillBadge.style.display = 'inline-flex';
  }
  const forceNew = document.getElementById('rc-force-new-bmsh'); if (forceNew) forceNew.checked = false;
  const advEl = document.getElementById('rc-advance-amt'); if(advEl) advEl.value = p.advance!=null?p.advance:'';
  const adpEl = document.getElementById('rc-advance-purpose'); if(adpEl) adpEl.value = p.advancePurpose||'';
  const nfEl = document.getElementById('rc-no-fee'); if(nfEl) { nfEl.checked = false; toggleRcNoFee(false); }
  // Clear search/match areas
  ['rc-phone-match','rc-bmhid-result'].forEach(id=>{const e=document.getElementById(id);if(e)e.innerHTML='';});
  const sr = document.getElementById('rc-phone-results'); if(sr) sr.style.display='none';
  // Switch to New Patient tab if on Queue tab
  const newTab = document.querySelector('#pg-reception .ptab');
  if(newTab && !newTab.classList.contains('active')) { ptab(newTab,'rc-new'); }
  showToast(`✏️ ${name || p.bmhId} prefilled — update details if needed and register ✓`,'s');
}
function calcRcAge() {
  const dob = document.getElementById('rc-dob')?.value;
  const ageEl = document.getElementById('rc-age');
  if(!dob || !ageEl) return;
  const birth = new Date(dob);
  const now = new Date();
  let years = now.getFullYear() - birth.getFullYear();
  const m = now.getMonth() - birth.getMonth();
  if(m < 0 || (m === 0 && now.getDate() < birth.getDate())) years--;
  ageEl.value = years + ' Years';
}
function isPrimaryBmhSequenceNumber(num) {
  return Number.isFinite(num) && /^4\d+$/.test(String(Math.trunc(num)));
}
function getKnownHighestBmhNumber() {
  let maxPrimary = 0;
  let maxFallback = 0;
  (window.PATIENTS || []).forEach(function (p) {
    const m = String(p?.bmhId || '').trim().match(/^BMSH-(\d{1,9})$/i);
    if (!m) return;
    const n = parseInt(m[1], 10);
    if (!Number.isFinite(n)) return;
    if (n > maxFallback) maxFallback = n;
    if (isPrimaryBmhSequenceNumber(n) && n > maxPrimary) maxPrimary = n;
  });
  let maxNum = maxPrimary || maxFallback;
  try {
    const ls = parseInt(localStorage.getItem('bmh_last_patient_num') || '0', 10);
    if (Number.isFinite(ls) && (!maxPrimary || isPrimaryBmhSequenceNumber(ls)) && ls > maxNum && ls < maxNum + 10000) maxNum = ls;
  } catch (_) {}
  const inMem = Number(window._nextPatientNum || 0) - 1;
  if (Number.isFinite(inMem) && (!maxPrimary || isPrimaryBmhSequenceNumber(inMem)) && inMem > maxNum && inMem < maxNum + 10000) maxNum = inMem;
  return maxNum;
}

function genRcUID() {
  // Only numeric BMSH-###### IDs participate in the sequence (CSV/hash imports are ignored)
  const maxNum = getKnownHighestBmhNumber();
  const localNext = maxNum + 1;
  window._nextPatientNum = localNext;
  const el = document.getElementById('rc-uid');
  if(el) el.textContent = 'BMSH-' + String(localNext).padStart(6,'0');

  // Also check RTDB in case another device registered a patient (sequence must never lag server)
  if(window.fbOnce) {
    fbOnce('settings/lastPatientNum').then(function(num) {
      if(typeof num !== 'number') return;
      if (getKnownHighestBmhNumber() > 0 && !isPrimaryBmhSequenceNumber(num)) return;
      // RTDB value must be close to the local max — ignore if it's wildly higher (corruption)
      const serverMax = getKnownHighestBmhNumber();
      if (num > serverMax + 10000) {
        // Server counter is corrupted — repair it to match the true local max
        if (window.FBDB) {
          window.FBDB.ref('settings/lastPatientNum').set(serverMax).catch(function(){});
        }
        return;
      }
      const nextFromServer = num + 1;
      if(nextFromServer > (window._nextPatientNum || 0)) {
        window._nextPatientNum = nextFromServer;
        try { localStorage.setItem('bmh_last_patient_num', String(num)); } catch(_) {}
        const el2 = document.getElementById('rc-uid');
        if(el2) el2.textContent = 'BMSH-' + String(nextFromServer).padStart(6,'0');
      }
    }).catch(function(){});
  }

  return 'BMSH-' + String(window._nextPatientNum || localNext).padStart(6,'0');
}
window.genRcUID = genRcUID;

function reserveNextBmhId() {
  const localFloor = getKnownHighestBmhNumber();
  const localId = (typeof genRcUID === 'function' && genRcUID()) || ('BMSH-' + String(localFloor + 1).padStart(6,'0'));
  if(!window.FBDB) return Promise.resolve(localId);

  return window.FBDB.ref('settings/lastPatientNum').transaction(function(current) {
    const hasPrimarySeries = getKnownHighestBmhNumber() > 0;
    const currentIsPrimary = typeof current === 'number' && isPrimaryBmhSequenceNumber(current);
    // If RTDB counter is wildly higher than local patient max, reset it first
    if (typeof current === 'number' && (current > localFloor + 10000 || (hasPrimarySeries && !currentIsPrimary))) {
      return localFloor + 1; // repair: start from true next
    }
    const base = (typeof current === 'number' && current > 0 && current >= localFloor && (!hasPrimarySeries || currentIsPrimary)) ? current : localFloor;
    return base + 1;
  }).then(function(result) {
    const committed = result && result.committed;
    const snap = result && result.snapshot;
    const nextNum = committed && snap ? snap.val() : null;
    if(typeof nextNum === 'number' && nextNum > 0) {
      window._nextPatientNum = nextNum;
      try { localStorage.setItem('bmh_last_patient_num', String(nextNum)); } catch(_) {}
      const reservedId = 'BMSH-' + String(nextNum).padStart(6,'0');
      const el = document.getElementById('rc-uid');
      if(el) el.textContent = reservedId;
      return reservedId;
    }
    return localId;
  }).catch(function() {
    return localId;
  });
}

window._rcDeptFilter = window._rcDeptFilter || 'all';
window._rcQueueSubtab = window._rcQueueSubtab || 'waiting';

function toggleRcNoFee(on) {
  const fee = document.getElementById('rc-fee');
  if(!fee) return;
  if(on) {
    fee.value = '0';
    fee.disabled = true;
    return;
  }
  fee.disabled = false;
  syncReceptionConsultationFee && syncReceptionConsultationFee();
}

function getReceptionConsultationServiceName() {
  const purpose = document.getElementById('rc-purpose')?.value || 'New Consultation';
  if(purpose === 'Not Checked In') return null;
  if(/follow|post-op/i.test(purpose)) return 'Follow-up';
  return 'New Consultation';
}

function getReceptionConsultationRate(centre) {
  const dept = document.getElementById('rc-dept')?.value || 'ophtho';
  const serviceName = getReceptionConsultationServiceName();
  if(!serviceName) return 0;

  const legacyMap = {
    ophtho: ['Consultation — Eye', 'Consultation'],
    obg: ['ANC Consultation', 'Consultation'],
    psych: ['Psychiatry Consultation', 'Consultation'],
    skin: ['Dermatology Consultation', 'Consultation']
  };
  const names = serviceName === 'Follow-up'
    ? ['Follow-up', 'Follow-up Consultation']
    : ['New Consultation'].concat(legacyMap[dept] || ['Consultation']);

  for(const name of names) {
    const amt = getChargeForProcedure(name, centre);
    if(amt) return amt;
    const direct = CENTRE_CHARGES[centre]?.[name];
    if(direct) return direct;
  }
  return 0;
}

function syncReceptionCentreAndFee() {
  const centreEl = document.getElementById('rc-centre');
  const feeEl = document.getElementById('rc-fee');
  if(!centreEl || !feeEl) return;

  const lockedCentre = getUserCentre();
  const centre = getReceptionSelectedCentre();
  centreEl.value = centre;
  centreEl.disabled = !!lockedCentre;
  centreEl.style.opacity = lockedCentre ? '0.7' : '1';

  if(document.getElementById('rc-no-fee')?.checked) {
    feeEl.value = '0';
    feeEl.disabled = true;
    return;
  }

  feeEl.disabled = false;
  const amount = getReceptionConsultationRate(centre);
  feeEl.value = String(amount);
}
window.syncReceptionConsultationFee = syncReceptionCentreAndFee;

function setRcQueueSubtab(mode, btnEl) {
  window._rcQueueSubtab = mode;
  const wrap = document.getElementById('rc-queue-subtabs');
  if(wrap) wrap.querySelectorAll('button').forEach(b => {
    b.classList.toggle('active', b.getAttribute('data-rcq')===mode);
  });
  renderReceptionPage && renderReceptionPage();
}

function ensureDailyReceptionReset() {
  const k = 'bmh_reception_calendar_day';
  const today = new Date().toISOString().slice(0,10);
  try {
    const last = localStorage.getItem(k);
    const banner = document.getElementById('rc-daily-banner');
    if(last && last !== today) {
      genRcUID && genRcUID();
      if(banner) {
        banner.style.display = 'flex';
        banner.innerHTML = '<span style="font-size:16px">📅</span><span><strong>New calendar day</strong> — the queue shows only today\'s check-ins. Full charges stay under <strong>Charges</strong>.</span>';
      }
    } else if(banner) { banner.style.display = 'none'; }
    localStorage.setItem(k, today);
  } catch(e) { /* private mode */ }
}

/** Update demographics for an existing patient (same BMSH ID shown in form) — no new token / fee. */
function updateExistingPatientFromReceptionForm(bmhId) {
  const uid = String(bmhId || '').trim();
  if (!uid) { showToast('Load a patient first (prefill or search)', 'w'); return; }
  const p = (typeof resolveExistingPatientForRegistration === 'function' ? resolveExistingPatientForRegistration(uid) : null)
    || PATIENTS.find(function (x) { return String(x?.bmhId || '') === uid; });
  if (!p) { showToast('Patient not found', 'w'); return; }
  const fn = normalizeReceptionFieldValue('rc-fn', document.getElementById('rc-fn')?.value || '');
  const ln = normalizeReceptionFieldValue('rc-ln', document.getElementById('rc-ln')?.value || '');
  const mob = (document.getElementById('rc-mob-inp')?.value || document.getElementById('rc-mob')?.value || '').trim();
  const dob = document.getElementById('rc-dob')?.value || '';
  const age = document.getElementById('rc-age')?.value || '';
  const sex = document.getElementById('rc-sex')?.value || 'Male';
  const dept = document.getElementById('rc-dept')?.value || 'ophtho';
  const dr = document.getElementById('rc-dr')?.value || '';
  const centre = document.getElementById('rc-centre')?.value || CURRENT_USER?.centre || 'CHD';
  const addr = normalizeReceptionFieldValue('rc-addr', document.getElementById('rc-addr')?.value || '');
  const mob2 = document.getElementById('rc-mob2')?.value?.trim() || '';
  const email = document.getElementById('rc-email')?.value?.trim() || '';
  const rel = normalizeReceptionFieldValue('rc-rel', document.getElementById('rc-rel')?.value || '');
  if (!fn) { showToast('Please enter patient first name', 'w'); return; }
  const name = toTitleCaseName((fn + ' ' + ln).trim());
  p.name = name;
  p.initials = computePatientInitials(name);
  p.age = age;
  p.sex = sex;
  p.mob = mob;
  p.mob2 = mob2;
  p.email = email;
  p.dob = dob;
  p.addr = addr;
  p.rel = rel;
  p.dept = dept;
  p.doctor = dr;
  p.assignedDoctor = dr;
  p.centre = centre;
  normalizePatientRecord(p);
  savePatientToFirebase(p);
  fbUpdate && fbUpdate('patients/' + uid, {
    name: p.name, age: p.age, sex: p.sex, mob: p.mob, mob2: p.mob2, email: p.email, dob: p.dob, addr: p.addr, rel: p.rel, dept: p.dept, doctor: p.doctor, assignedDoctor: p.assignedDoctor, centre: p.centre, initials: p.initials
  }).catch(function () {});
  showToast('Patient details updated ✓', 's');
  renderDocQueue && renderDocQueue();
  renderReceptionPage && renderReceptionPage();
}
window.updateExistingPatientFromReceptionForm = updateExistingPatientFromReceptionForm;

/** Reception — Register & Generate Token (full-width form) */
async function registerPatient() {
  const uidDisplayed = (document.getElementById('rc-uid')?.textContent || '').trim();
  const fn  = normalizeReceptionFieldValue('rc-fn', document.getElementById('rc-fn')?.value  || '');
  const ln  = normalizeReceptionFieldValue('rc-ln', document.getElementById('rc-ln')?.value  || '');
  const mob = (document.getElementById('rc-mob-inp')?.value || document.getElementById('rc-mob')?.value || '').trim();
  const mob2  = document.getElementById('rc-mob2')?.value?.trim() || '';
  const dob = document.getElementById('rc-dob')?.value || '';
  const age = document.getElementById('rc-age')?.value || '';
  const sex = document.getElementById('rc-sex')?.value || 'Male';
  const dept= document.getElementById('rc-dept')?.value || 'ophtho';
  const dr  = document.getElementById('rc-dr')?.value   || '';
  const centre = document.getElementById('rc-centre')?.value || CURRENT_USER?.centre || 'CHD';
  const addr= normalizeReceptionFieldValue('rc-addr', document.getElementById('rc-addr')?.value || '');
  const noFee = document.getElementById('rc-no-fee')?.checked;
  const advAmt = parseFloat(document.getElementById('rc-advance-amt')?.value)||0;
  const advPurpose = normalizeReceptionFieldValue('rc-advance-purpose', document.getElementById('rc-advance-purpose')?.value||'');

  if(!fn) { showToast('Please enter patient first name','w'); return; }

  const name = toTitleCaseName((fn + ' ' + ln).trim());
  const emailEarly = document.getElementById('rc-email')?.value?.trim() || '';
  const forceNewBmsh = !!document.getElementById('rc-force-new-bmsh')?.checked;
  const hintedExistingPt = (!forceNewBmsh && uidDisplayed) ? resolveExistingPatientForRegistration(uidDisplayed) : null;
  const existingPt = hintedExistingPt || findSamePersonForRegistration({
    uidDisplayed: uidDisplayed,
    name: name,
    mob: mob,
    mob2: mob2,
    age: age,
    dob: dob,
    forceNewId: forceNewBmsh
  });
  const isExistingRegistration = !!existingPt;
  const uid = String(isExistingRegistration ? (existingPt && existingPt.bmhId) : (await reserveNextBmhId()) || '').trim();
  if(isExistingRegistration) {
    if(!uid) { showToast('Could not reuse the existing BMSH ID','e'); return; }
  } else if(!/^BMSH-\d{6,9}$/.test(uid)) { showToast('Could not generate a valid BMSH ID','e'); return; }
  const uidEl = document.getElementById('rc-uid');
  if (uidEl) uidEl.textContent = uid;
  if (isExistingRegistration && String(uidDisplayed || '').trim() && String(uidDisplayed).trim() !== String(uid)) {
    showToast('Matched existing patient — keeping ' + uid + ' (one BMSH ID per person) ✓', 'i');
  }

  const initials = computePatientInitials(name);
  const colors = ['#1A3C6E','#0B7B8C','#FF2D55','#AF52DE','#34C759','#FF9500','#5856D6','#FF3B30'];
  const color = existingPt?.color || colors[Math.floor(Math.random()*colors.length)];

  const purposeVal = normalizeReceptionFieldValue('rc-purpose', document.getElementById('rc-purpose')?.value||'New Consultation');
  const isPreReg = purposeVal==='Need to Check In' || purposeVal==='Not Checked In';
  const email = emailEarly;
  const currentIso = new Date().toISOString();
  const queueDateToday = currentIso.slice(0, 10);

  const patient = Object.assign({}, existingPt || {}, {
    bmhId: uid, name, initials, color,
    age, sex, mob, mob2, email, dob, addr,
    dept, doctor: dr, assignedDoctor: dr,
    centre, status: isPreReg ? 'pre-registered' : 'waiting',
    balance: Number(existingPt?.balance || 0),
    advance: advAmt > 0 ? advAmt : Number(existingPt?.advance || 0),
    advancePurpose: advPurpose || existingPt?.advancePurpose || (advAmt > 0 ? 'Advance on account' : ''),
    consultationNoFee: !!noFee,
    seen:false, dilated:false,
    queueRemoved: false,
    queueRemovedAt: null,
    queueRemovedBy: '',
    queueDate: queueDateToday,
    visitDate: queueDateToday,
    preRegistered: isPreReg,
    createdAt: existingPt?.createdAt || currentIso,
    updatedAt: currentIso,
    createdBy: existingPt?.createdBy || CURRENT_USER?.name || 'Reception'
  });
  normalizePatientRecord(patient);

  const exists = PATIENTS.findIndex(p=>p.bmhId===uid);
  if(exists >= 0) PATIENTS[exists] = patient; else PATIENTS.push(patient);

  savePatientToFirebase(patient);

  const numFromId = parseInt(String(uid).replace(/^BMSH-/,''),10);
  if(!isNaN(numFromId) && isPrimaryBmhSequenceNumber(numFromId)) {
    try { localStorage.setItem('bmh_last_patient_num', numFromId); } catch(_) {}
    window._nextPatientNum = numFromId + 1;
  }

  let fee = parseFloat(document.getElementById('rc-fee')?.value || getReceptionConsultationRate(centre) || 0) || 0;
  if(noFee) fee = 0;
  const payMode = document.getElementById('rc-pay-mode')?.value||'Cash';
  const purpose = normalizeReceptionFieldValue('rc-purpose', document.getElementById('rc-purpose')?.value||'New Consultation');
  const refType = document.getElementById('rc-ref-type')?.value || '';
  const refName = normalizeReceptionFieldValue('rc-ref-name', document.getElementById('rc-ref-name')?.value?.trim() || '');
  const refMobile = document.getElementById('rc-ref-mobile')?.value?.trim() || '';
  const insName = normalizeReceptionFieldValue('rc-ins-name', document.getElementById('rc-ins-name')?.value||'');
  const policyNo = (document.getElementById('rc-policy')?.value || '').trim();
  const claimAmountInput = Math.max(0, Number(document.getElementById('rc-claim-amt')?.value || 0));
  patient.checkinAt = Date.now();
  patient.purpose = purpose;
  patient.refType = refType;
  patient.refName = refName;
  patient.refMobile = refMobile;
  patient.referredBy = refName || refType || '';
  const prevVisits = PATIENTS.filter(function (p) {
    if (!p || isMergedPatientRecord(p)) return false;
    return String(p?.bmhId || '') !== String(patient.bmhId || '')
      && patientNameIdentityKey(p?.name || p?.patient) === patientNameIdentityKey(patient.name)
      && getPatientPhoneKeys(p).some(function (phoneKey) { return getPatientPhoneKeys(patient).includes(phoneKey); });
  }).length;
  patient.visitCount = isExistingRegistration
    ? Math.max(Number(existingPt?.visitCount || 0), 1) + 1
    : prevVisits + 1;
  if (refType) {
    const refId = 'REF' + Date.now();
    logReferral(refType, refName, refMobile, { name, bmhId: uid, dept, purpose, centre });
    fbSet && fbSet('referrals/' + refId, {
      id: refId,
      bmhId: uid,
      patient: name,
      dept,
      centre,
      refType,
      refName,
      refMobile,
      purpose,
      createdAt: new Date().toISOString(),
      createdBy: CURRENT_USER?.name || 'Reception'
    });
  }

  const isInsurance = payMode.includes('Insurance')||payMode.includes('PMJAY')||payMode.includes('CGHS')||payMode.includes('TPA');
  const isCreditDue = payMode === 'Credit / Due';
  const previousDue = isExistingRegistration
    ? Math.max(
        0,
        Number(existingPt?.balance || 0),
        Number((typeof bmhGetPatientFinancialSummary === 'function' ? bmhGetPatientFinancialSummary(uid)?.balance : 0) || 0)
      )
    : 0;
  let dueReceivedNow = false;
  if (isExistingRegistration && previousDue > 0) {
    dueReceivedNow = confirm(`${name} has a pending due of ₹${previousDue.toLocaleString('en-IN')}.\n\nDue received now?`);
  }

  if(isInsurance) {
    const claimId = 'TPA'+Date.now();
    const claimAmount = Math.max(claimAmountInput, Number(fee || 0));
    const claim = {id:claimId, patient:name, bmhId:uid, for:purpose, amount:claimAmount, approvedAmount:claimAmount, claimedAmount:claimAmount, status:'pending', mode:payMode, ins:insName||payMode, policy:policyNo, dept, centre, date:new Date().toISOString(), from:'Reception'};
    PAY_REQUESTS.push(claim);
    fbSet&&fbSet('payRequests/'+claimId, claim);
    addBmhPatientCharge(uid, { id: 'chg-' + claimId, cat: inferChargeCategoryFromService(purpose), desc: purpose, qty: 1, rate: fee, amount: fee, source: 'reception', ref: claimId, ts: claim.date });
    patient.ins = insName||payMode;
    patient.policy = policyNo || patient.policy || '';
    patient.claimedAmount = claimAmount;
    patient.balance = Math.max(Number(patient.balance || 0), Number(fee || 0));
    showToast(`🏦 TPA/Insurance patient — claim pending ₹${fee.toLocaleString('en-IN')}`,'i');
  } else if(isCreditDue) {
    addBmhPatientCharge(uid, { id: 'chg-credit-' + Date.now(), cat: inferChargeCategoryFromService(purpose), desc: purpose, qty: 1, rate: fee, amount: fee, source: 'reception', ts: new Date().toISOString() });
    patient.balance = (patient.balance||0) + fee;
    showToast(`📋 ₹${fee} noted as credit/due for ${name}`,'i');
  } else if(fee > 0 || noFee) {
    const txnId = 'TXN'+Date.now();
    addBmhPatientCharge(uid, { id: 'chg-' + txnId, cat: inferChargeCategoryFromService(purpose), desc: purpose + (noFee?' (no fee)':''), qty: 1, rate: fee, amount: fee, source: 'reception', ref: txnId, ts: new Date().toISOString() });
    const txn = {
      id:txnId, patient:name, bmhId:uid, service: purpose + (noFee?' (no fee)':''), amount:fee,
      mode:payMode, collected:true, dept,
      time:new Date().toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'}),
      date:new Date().toISOString(), centre, createdBy:CURRENT_USER?.name||'Reception',
      noFee: !!noFee
    };
    TRANSACTIONS.push(txn);
    saveTransactionToFirebase&&saveTransactionToFirebase(txn);
    patient.balance = bmhSyncPatientRunningBalance(uid);
    fbUpdate&&fbUpdate('patients/'+uid,{balance:patient.balance});
  }

  if(advAmt > 0) {
    const txnA = 'TXN'+Date.now()+'A';
    const txna = {
      id:txnA, patient:name, bmhId:uid, service:'Advance — '+(advPurpose||'On account'), amount:advAmt,
      mode:payMode, collected:true, dept,
      time:new Date().toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'}),
      date:new Date().toISOString(), centre, createdBy:CURRENT_USER?.name||'Reception', type:'advance'
    };
    TRANSACTIONS.push(txna);
    saveTransactionToFirebase&&saveTransactionToFirebase(txna);
  }

  fbUpdate&&fbUpdate('patients/'+uid,{
    checkinAt:patient.checkinAt,purpose,visitCount:patient.visitCount,ins:patient.ins||'', policy: patient.policy || '',
    advance:patient.advance, advancePurpose:patient.advancePurpose, consultationNoFee:patient.consultationNoFee,
    refType: patient.refType || '', refName: patient.refName || '', refMobile: patient.refMobile || '', referredBy: patient.referredBy || '',
    queueRemoved: false, queueRemovedAt: null, queueRemovedBy: '', queueDate: patient.queueDate || queueDateToday, visitDate: patient.visitDate || queueDateToday
  });
  if (typeof window.patchPatientFirestore === 'function') {
    window.patchPatientFirestore(uid, {
      checkinAt: patient.checkinAt,
      purpose,
      visitCount: patient.visitCount,
      ins: patient.ins || '',
      policy: patient.policy || '',
      advance: patient.advance,
      advancePurpose: patient.advancePurpose,
      consultationNoFee: patient.consultationNoFee,
      refType: patient.refType || '',
      refName: patient.refName || '',
      refMobile: patient.refMobile || '',
      referredBy: patient.referredBy || ''
    }).catch(() => {});
  }

  const todayPts = PATIENTS.filter(p=> p.createdAt && p.createdAt.startsWith(new Date().toISOString().slice(0,10)));
  const token = todayPts.length;

  showToast(`✅ ${name} registered — Token #${token}`, 's');
  if (isExistingRegistration || prevVisits > 0) {
    repairDuplicatePatientsForIdentity({ name, mob, mob2 }).catch(function (e) {
      console.warn('duplicate patient merge after registration failed', e);
    });
  }

  maybeScheduleSameDaySurgeryOTFromRegistration(patient);

  if(!isInsurance && !isCreditDue && !isPreReg && fee>0) {
    setTimeout(()=>{
      if(confirm(`✅ ${name} registered — Token #${token}\nFee: ₹${fee.toLocaleString('en-IN')} (${payMode})\n\nPrint receipt?`)) {
        printPaymentReceipt({id:'TXN'+Date.now(),patient:name,bmhId:uid,for:purpose,service:purpose,amount:fee,mode:payMode,bmhId:uid});
      }
    },200);
  }
  if (dueReceivedNow && previousDue > 0) {
    setTimeout(function () {
      rcOpenBillingFor(uid);
      const toggle = document.getElementById('bmh-pay-received-toggle');
      if (toggle) toggle.checked = true;
      bmhTogglePaymentForm(true);
      const amtEl = document.getElementById('bmh-pay-amt');
      if (amtEl) amtEl.value = String(previousDue);
      bmhUpdateBillTotals && bmhUpdateBillTotals();
      showToast('Billing opened with the pending due ready to record', 'i');
    }, 260);
  }

  resetRegistrationForm();
  renderDocQueue && renderDocQueue();
  renderDashboard && renderDashboard();
  renderReceptionPage && renderReceptionPage();
  renderInsuranceTab && renderInsuranceTab();
  renderTpaPage && renderTpaPage();
}
window.registerPatient = registerPatient;

