function renderDeptSummary() {
  const el = document.getElementById('rc-dept-summary-list'); if(!el) return;
  const today = localDateKey(new Date());
  const centre = getEffectiveCentre();
  const selectedDept = window._rcDeptSummaryFilterDept || '';
  const onlyPending = !!window._rcDeptSummaryPendingOnly;
  const todayPRs = PAY_REQUESTS.filter(function (r) {
    if ((r.centre || 'CHD') !== centre) return false;
    const stamp = r.date || r.createdAt || r.updatedAt || '';
    if (!stamp) return true;
    return localDateKey(stamp) === today || String(stamp).slice(0, 10) === today;
  });
  const depts = [
    {k:'ophtho',l:'Ophthalmology',icon:'👁️',color:'var(--blue)'},
    {k:'obg',l:'OBG',icon:'🤰',color:'#c0004e'},
    {k:'psych',l:'Neuropsychiatry',icon:'🧠',color:'var(--orange)'},
    {k:'skin',l:'Skin & Cosmetology',icon:'💆',color:'var(--purple)'},
  ];
  if(!todayPRs.length) {
    el.innerHTML = '<div style="padding:20px;text-align:center;color:var(--g1);font-size:12px">No charge requests from doctors today</div>';
    return;
  }
  el.innerHTML = (selectedDept ? '<div style="display:flex;justify-content:flex-end;margin-bottom:8px"><button type="button" class="btn btn-xs btn-outline" onclick="window._rcDeptSummaryFilterDept=\\\'\\\';window._rcDeptSummaryPendingOnly=false;renderDeptSummary()">Show all departments</button></div>' : '') + depts.map(d=>{
    if (selectedDept && d.k !== selectedDept) return '';
    let dPRs = todayPRs.filter(r=>r.dept===d.k);
    if (onlyPending) dPRs = dPRs.filter(function (r) { return r.status === 'pending'; });
    if(!dPRs.length) return '';
    const pending = dPRs.filter(r=>r.status==='pending');
    const paid = dPRs.filter(r=>r.status==='paid');
    const pendAmt = pending.reduce((s,r)=>s+r.amount,0);
    const paidAmt = paid.reduce((s,r)=>s+r.amount,0);
    const hasSurgery = dPRs.some(r=>(r.for||'').toLowerCase().includes('surg')||PATIENTS.find(p=>p.bmhId===r.bmhId)?.purpose==='Surgery');
    return `<div style="border:1.5px solid ${d.color}44;border-radius:var(--r);overflow:hidden;margin-bottom:8px">
      <div style="background:${d.color}11;padding:10px 14px;display:flex;align-items:center;gap:10px">
        <span style="font-size:18px">${d.icon}</span>
        <div style="flex:1">
          <div style="font-weight:900;font-size:13px;color:${d.color}">${d.l}</div>
          <div style="font-size:10.5px;color:var(--g1)">${pending.length} pending · ${paid.length} cleared</div>
        </div>
        <div style="text-align:right">
          ${pendAmt>0?`<div style="font-size:14px;font-weight:900;color:var(--orange)">₹${pendAmt.toLocaleString('en-IN')} due</div>`:''}
          ${paidAmt>0?`<div style="font-size:11px;color:#1a8c3c;font-weight:700">₹${paidAmt.toLocaleString('en-IN')} paid</div>`:''}
        </div>
        ${hasSurgery?`<button class="btn btn-orange btn-xs" onclick="printSurgeryPack('${d.k}')">📋 Surgery Pack</button>`:''}
      </div>
      <div style="padding:8px 12px">
        ${dPRs.map(r=>{
          const pt = PATIENTS.find(p=>p.bmhId===r.bmhId)||{};
          const bid = String(r.bmhId||'').replace(/'/g, "\\'");
          const canDeleteDue = r.status === 'pending';
          return `<div style="display:flex;align-items:center;gap:9px;padding:7px 0;border-bottom:1px solid var(--g5)">
            <button type="button" class="btn btn-xs btn-outline" style="flex-shrink:0;padding:4px 7px;min-width:36px" title="Open bill & print receipt" onclick="rcOpenBillingForAndPrint('${bid}')">🧾</button>
            <div style="width:30px;height:30px;border-radius:50%;background:${pt.color||d.color};color:#fff;display:flex;align-items:center;justify-content:center;font-weight:900;font-size:11px;flex-shrink:0">${pt.initials||r.patient[0]||'?'}</div>
            <div style="flex:1">
              <div style="font-weight:800;font-size:12.5px">${r.patient}</div>
              <div style="font-size:10.5px;color:var(--g1)">${r.for||'—'} · ${r.from||'Doctor'}</div>
            </div>
            <div style="font-weight:900;font-size:13px;color:${r.status==='paid'?'#1a8c3c':'var(--orange)'}">₹${r.amount.toLocaleString('en-IN')}</div>
            ${r.status==='pending'?`<select id="pay-mode-${r.id}" style="height:28px;border:1px solid var(--g4);border-radius:6px;padding:0 6px;font-size:10.5px;background:#fff">
              <option value="Cash"${isInsuranceLikeMode(r.mode || r.ins || '') ? '' : ' selected'}>Cash</option>
              <option value="UPI"${String(r.mode || '').toLowerCase()==='upi' ? ' selected' : ''}>UPI</option>
              <option value="Credit Card"${String(r.mode || '').toLowerCase()==='credit card' ? ' selected' : ''}>Credit Card</option>
              <option value="Insurance/TPA"${isInsuranceLikeMode(r.mode || r.ins || '') ? ' selected' : ''}>Insurance/TPA</option>
            </select><button class="btn btn-xs" style="background:var(--green);color:#fff;border:none;border-radius:6px;padding:4px 10px;font-size:10.5px;font-weight:800;cursor:pointer" onclick="collectPayment('${r.id}','${r.id}')">Collect</button>`:`<span style="font-size:10px;background:var(--green-lt);color:#1a8c3c;padding:2px 8px;border-radius:10px;font-weight:700">✓ Paid</span>`}
            ${canDeleteDue ? `<button class="btn btn-xs btn-gray" onclick="deletePayRequest('${r.id}')" title="Delete due">✕</button>` : ''}
            <button class="btn btn-xs btn-outline" onclick="openXRefModal('${r.bmhId}')" title="Cross-refer">↔️</button>
            <button class="btn btn-xs" style="background:rgba(175,82,222,.1);color:var(--purple);border:1.5px solid var(--purple);border-radius:6px;padding:3px 6px;font-size:10px;cursor:pointer" onclick="openIPDFromQueue('${r.bmhId}')" title="IPD">🛏️</button>
            <button class="btn btn-xs" style="background:rgba(255,149,0,.1);color:var(--orange);border:1.5px solid var(--orange);border-radius:6px;padding:3px 6px;font-size:10px;cursor:pointer" onclick="openOTFromQueue('${r.bmhId}')" title="OT">🔬</button>
          </div>`;
        }).join('')}
      </div>
    </div>`;
  }).join('') || '<div style="padding:20px;text-align:center;color:var(--g1);font-size:12px">No charges sent today</div>';
}

function updateReceptionDeptSummaryTabBadge() {
  const tab = Array.from(document.querySelectorAll('#pg-reception .ptab')).find(function (el) {
    return (el.textContent || '').includes('Dept Summary');
  });
  if (!tab) return;
  const centre = getEffectiveCentre();
  const pending = (PAY_REQUESTS || []).filter(function (r) {
    return r.status === 'pending' && (r.centre || 'CHD') === centre;
  });
  let badge = tab.querySelector('.rc-dept-summary-badge');
  if (!pending.length) {
    if (badge) badge.remove();
    tab.style.animation = '';
    tab.style.boxShadow = '';
    return;
  }
  if (!badge) {
    badge = document.createElement('span');
    badge.className = 'rc-dept-summary-badge';
    badge.style.cssText = 'display:inline-flex;align-items:center;justify-content:center;min-width:18px;height:18px;padding:0 6px;margin-left:6px;border-radius:999px;background:var(--orange);color:#fff;font-size:10px;font-weight:900;animation:pulse 1.35s infinite;vertical-align:middle';
    tab.appendChild(badge);
  }
  badge.textContent = String(pending.length);
  tab.style.animation = 'pulse 1.35s infinite';
  tab.style.boxShadow = '0 0 0 2px rgba(255,149,0,.16) inset';
}

