// INVENTORY MANUAL ENTRY
function renderInventoryManual() {
  const el = document.getElementById('inv-manual-form'); if(!el) return;
}
function bmhFindOrCreateInventoryItem(rawCode, translated) {
  const lookup = String(rawCode || '').trim();
  let item = BCMAP[lookup] || BCMAP[lookup.toLowerCase().substring(0, 15)] || INVENTORY.find(x => x.barcode === lookup || x.name.toLowerCase() === lookup.toLowerCase());
  if (item) return item;
  item = {
    name: translated || lookup,
    barcode: lookup || ('INV-' + Date.now()),
    qr: lookup || '',
    genericName: String(document.getElementById('inv-in-generic')?.value || '').trim(),
    cat: bmhInventoryCategoryValue(),
    mrp: Number(document.getElementById('inv-in-mrp')?.value || '0') || 0,
    cost: Number(document.getElementById('inv-in-cost')?.value || '0') || 0,
    stock: 0,
    min: Number(document.getElementById('inv-in-min')?.value || '5') || 5,
    exp: document.getElementById('inv-in-exp')?.value || '',
    dept: bmhInventoryDeptValue(),
    vendor: document.getElementById('inv-in-vendor')?.value?.trim() || '',
    store: bmhInventoryStoreValue() || bmhDefaultStoreForDept(bmhInventoryDeptValue()),
    vendorBillingMode: bmhInventoryBillModeValue()
  };
  normalizeInventoryRecord(item);
  INVENTORY.push(item);
  // Save to Firebase
  if (typeof window.saveInventoryToFirebase === 'function') {
    window.saveInventoryToFirebase(item).catch(err => console.error('Firebase save error:', err));
  }
  BCMAP[item.barcode] = item;
  return item;
}
function bmhRecordInventoryPurchase(item, qty, billFile) {
  const vendor = document.getElementById('inv-in-vendor')?.value?.trim()
    || document.getElementById('inv-iol-vendor')?.value?.trim()
    || String(item.vendor || '').trim()
    || '';
  const invoiceNo = document.getElementById('inv-in-invoice')?.value?.trim()
    || String(item.invoiceNo || '').trim()
    || '';
  const dept = bmhInventoryDeptValue();
  const store = bmhInventoryStoreValue() || bmhDefaultStoreForDept(dept);
  const category = bmhInventoryCategoryValue();
  const cost = Number(document.getElementById('inv-in-cost')?.value || item.cost || 0) || 0;
  const mrp = Number(document.getElementById('inv-in-mrp')?.value || item.mrp || 0) || 0;
  const minQty = Number(document.getElementById('inv-in-min')?.value || item.min || 0) || 0;
  const billMode = bmhInventoryBillModeValue();
  item.cost = cost;
  item.mrp = mrp;
  item.dept = dept;
  item.cat = category || item.cat || 'Miscellaneous';
  item.min = minQty;
  item.store = store;
  item.vendor = vendor || item.vendor || '';
  item.vendorBillingMode = billMode;
  item.exp = document.getElementById('inv-in-exp')?.value || item.exp || '';
  normalizeInventoryRecord(item);
  if (item.vendor) learnInventoryOcrValue('vendor', item.vendor);
  if (item.name) learnInventoryOcrValue('itemName', item.name);
  if (item.iolCompany) learnInventoryOcrValue('company', item.iolCompany);
  if (item.iolBrand) learnInventoryOcrValue('brand', item.iolBrand);
  if (item.batchNo) learnInventoryOcrValue('batchNo', item.batchNo);
  if (Number(item.mrp || 0) > 0) rememberInventoryMrp(item.name, item.mrp);
  const totalCost = qty * cost;
  const purchaseTs = bmhNowISO();
  const dueDate = billMode === 'on-use' ? '' : new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
  const purchase = {
    id:'PO' + Date.now() + Math.random().toString(36).slice(2, 5),
    itemName:item.name,
    barcode:item.barcode,
    dept,
    store,
    category,
    vendor,
    invoiceNo,
    qty,
    cost,
    mrp,
    totalCost,
    billMode,
    dueDate,
    ts:purchaseTs,
    billFile: billFile || null,
    billDateKey: new Date().toISOString().slice(0, 10),
    billGroup: [normalizeInventoryTextValue(vendor), invoiceNo || 'NOINV', dept || 'general', new Date().toISOString().slice(0, 10)].join('::')
  };
  normalizeInventoryRecord(purchase);
  window.BMH_PURCHASES.push(purchase);
  if (typeof window.savePurchaseToFirebase === 'function') {
    window.savePurchaseToFirebase(purchase).catch(function (err) {
      console.error('Purchase cloud save error:', err);
    });
  }
  if (billFile && vendor) inventoryRememberBillMeta(vendor, dept, billFile);
  if (vendor && totalCost > 0) {
    const existingVendorBill = (window.BMH_VENDOR_BILLS || []).find(function (v) {
      return String(v.billGroup || '') === String(purchase.billGroup || '')
        && String(v.vendor || '').trim() === vendor
        && String(v.invoiceNo || '') === invoiceNo;
    });
    if (existingVendorBill) {
      existingVendorBill.amount = Number(existingVendorBill.amount || 0) + totalCost;
      existingVendorBill.uploadedName = existingVendorBill.uploadedName || billFile?.name || '';
      existingVendorBill.billFile = existingVendorBill.billFile || billFile || null;
      existingVendorBill.itemName = existingVendorBill.itemName || item.name;
      existingVendorBill.store = existingVendorBill.store || store;
      existingVendorBill.category = existingVendorBill.category || category;
      existingVendorBill.dept = existingVendorBill.dept || dept;
      existingVendorBill.billDateKey = existingVendorBill.billDateKey || purchase.billDateKey;
      existingVendorBill.billMode = existingVendorBill.billMode || billMode;
      normalizeInventoryRecord(existingVendorBill);
    } else {
      const vendorBill = {
        id: 'VB' + Date.now() + Math.random().toString(36).slice(2, 5),
        vendor,
        invoiceNo,
        amount: totalCost,
        dueDate: dueDate,
        status: 'pending',
        uploadedName: billFile?.name || '',
        billFile: billFile || null,
        createdAt: purchase.ts,
        dept: dept,
        billDateKey: purchase.billDateKey,
        billGroup: purchase.billGroup,
        itemName: item.name,
        billMode: billMode,
        store: store,
        category: category,
        usageLinked: billMode === 'on-use'
      };
      normalizeInventoryRecord(vendorBill);
      window.BMH_VENDOR_BILLS.push(vendorBill);
    }
  }
  saveBmhFinancials();
  renderInventoryPurchaseLog();
  bmhRenderVendorTables();
  renderInventoryPoAlerts();
}
// Extend processBC — stock in / patient use with inventory deduction + patient charge line
function processBC(mode, code) {
  if (!code) return;
  const translated = String(code);
  const item = BCMAP[code] || BCMAP[code.toLowerCase().substring(0, 15)] || INVENTORY.find(x => x.name.toLowerCase() === String(code).toLowerCase());
  if (mode === 'in') {
    const qty = Math.max(1, Number(document.getElementById('inv-in-qty')?.value || '1'));
    const target = item || bmhFindOrCreateInventoryItem(code, translated);
    bmhCompressFileToData(document.getElementById('inv-in-bill-file')?.files?.[0], (billFile) => {
      try {
        target._localAddedAt = Date.now();
        target.stock = (target.stock || 0) + qty;
        // Save to Firebase
        if (typeof window.saveInventoryToFirebase === 'function') {
          window.saveInventoryToFirebase(target).catch(err => console.error('Firebase save error:', err));
        }
        bmhRecordInventoryPurchase(target, qty, billFile);
        saveInventoryStockToStorage();
        const catFilter = document.getElementById('inv-stock-cat-filter');
        const storeFilter = document.getElementById('inv-stock-store-filter');
        if (catFilter) catFilter.value = 'all';
        if (storeFilter) storeFilter.value = 'all';
        try { renderStockList(); } catch (e) { console.warn('renderStockList failed', e); }
        const log = document.getElementById('stock-in-log');
        if (log) {
          const d = document.createElement('div');
          d.style.cssText = 'display:flex;align-items:center;justify-content:space-between;gap:10px;padding:8px 10px;background:var(--green-lt);border-radius:8px;margin-bottom:6px;font-size:12px';
          d.innerHTML = `<span><strong>${target.name}</strong> · ${bmhDeptLabel(target.dept || 'general')}</span><span style="font-weight:900;color:#1a8c3c">+${qty}</span>`;
          log.prepend(d);
        }
        resetInventoryStockInForm(false);
        const tabBtn = Array.from(document.querySelectorAll('#pg-inventory .ptab')).find(function (el) { return String(el.textContent || '').includes('Current Stock'); });
        if (tabBtn) ptab(tabBtn, 'inv-stock');
        showToast('Saved ✓', 's');
      } catch (e) {
        console.error('processBC stock-in failed', e);
        showToast('Stock save failed. Please retry.', 'e');
      }
    });
    return;
  }
  if (mode === 'use') {
    const bmhId = document.getElementById('use-pt')?.value || '';
    const qty = Math.max(1, Number(document.getElementById('inv-use-qty')?.value || '1'));
    const useMode = document.getElementById('inv-use-mode')?.value || 'bill';
    const dept = bmhInventoryUseDeptValue();
    if (!bmhId) { showToast('Search and select a patient by BMSH ID / phone first', 'w'); return; }
    if (item) {
      bmhUseInventoryItemForPatient(bmhId, item, { descSuffix: '(inventory use)', qty, mode: useMode, dept });
      const log = document.getElementById('use-log');
      if (log) {
        const d = document.createElement('div');
        d.style.cssText = 'display:flex;align-items:center;justify-content:space-between;gap:10px;padding:8px 10px;background:var(--orange-lt);border-radius:8px;margin-bottom:6px;font-size:12px';
        d.innerHTML = `<span><strong>${item.name}</strong> · ${bmhId}</span><span style="font-weight:900;color:#8a4200">${useMode === 'bill' ? 'Billed' : 'Consumed'} × ${qty}</span>`;
        log.prepend(d);
      }
      showToast(item.name + (useMode === 'bill' ? ' → patient bill ₹' + (Number(item.mrp) || 0).toLocaleString('en-IN') : ' consumed from stock') , 's');
    } else {
      showToast('Scanned: "' + translated + '" — not in inventory', 'i');
      AUTO_BILL.push({ item: translated, mrp: 0, patient: bmhId, time: new Date().toLocaleTimeString() });
      if (useMode !== 'consume') addBmhPatientCharge(bmhId, { id: 'inv' + Date.now(), cat: 'pharmacy', desc: translated + ' (not in stock / OCR)', qty: qty, rate: 0, amount: 0, source: 'inventory', ts: new Date().toISOString() });
      window.BMH_INVENTORY_USAGE.push({ id:'IU' + Date.now(), bmhId, patientName:(PATIENTS.find(x=>x.bmhId===bmhId)||{}).name || bmhId, dept, itemName:translated, barcode:code, qty, mrp:0, cost:0, mode:useMode, ts:bmhNowISO() });
      saveBmhFinancials();
      renderInventoryUsageLog();
      renderAutoBillLog();
      renderBillingPageIfActive && renderBillingPageIfActive();
    }
    const ilc = document.getElementById('inv-low-cnt'); if (ilc) ilc.textContent = INVENTORY.filter(i => i.stock <= i.min).length;
  }
}

