// ─── RENDER OT LIST ───────────────────


function otCaseCard(c, sno) {
  c = normalizeOTCaseRecord(c);
  const timings = c.timings || { incision:'', procEnd:'', anaesStart:'' };
  const statusStyle = {
    pending:{bg:'var(--g6)',border:'var(--g4)',badge:'bd-gray',label:'⏳ Pending'},
    'in-progress':{bg:'var(--blue-lt)',border:'var(--blue)',badge:'bd-blue',label:'🔄 In Progress'},
    completed:{bg:'var(--green-lt)',border:'var(--green)',badge:'bd-green',label:'✅ Completed'},
    postponed:{bg:'var(--red-lt)',border:'var(--red)',badge:'bd-red',label:'⏸️ Postponed'},
  }[c.status]||{bg:'var(--g6)',border:'var(--g4)',badge:'bd-gray',label:c.status};

  const whoHTML = `<div style="display:flex;gap:4px;margin-top:4px">
    <span style="font-size:9px;padding:2px 5px;border-radius:10px;font-weight:700;background:${c.signIn?'var(--green-lt)':'var(--g5)'};color:${c.signIn?'#1a8c3c':'var(--g1)'}">Sign In ${c.signIn?'✓':''}</span>
    <span style="font-size:9px;padding:2px 5px;border-radius:10px;font-weight:700;background:${c.timeOut?'var(--green-lt)':'var(--g5)'};color:${c.timeOut?'#1a8c3c':'var(--g1)'}">T/O ${c.timeOut?'✓':''}</span>
    <span style="font-size:9px;padding:2px 5px;border-radius:10px;font-weight:700;background:${c.signOut?'var(--green-lt)':'var(--g5)'};color:${c.signOut?'#1a8c3c':'var(--g1)'}">Sign Out ${c.signOut?'✓':''}</span>
  </div>`;

  const priorityBadge = c.priority==='emergency'?'<span class="badge bd-red" style="font-size:9px">🚨 Emergency</span>':c.priority==='urgent'?'<span class="badge bd-orange" style="font-size:9px">⚡ Urgent</span>':'';
  const pack = resolveSurgeryPackForCase(c);
  const surgeryMeta = [
    c.site && c.site !== 'N/A' ? '<span style="font-size:12px;font-weight:900;color:#1A3C6E">👁️ ' + c.site + '</span>' : '',
    c.iolType && c.iolType !== '—' && c.iolType !== 'N/A' ? '<span style="font-size:12px;font-weight:900;color:#8a4200">🔬 ' + c.iolType + '</span>' : '',
    c.iolPower && c.iolPower !== '—' ? '<span style="font-size:12px;font-weight:900;color:#0B7B8C">⚡ ' + c.iolPower + '</span>' : ''
  ].filter(Boolean).join(' · ');

  return `<div style="background:${statusStyle.bg};border-radius:var(--r);padding:11px 13px;margin-bottom:8px;border:1.5px solid ${statusStyle.border};cursor:pointer;transition:all .2s" onclick="openOTCase('${c.id}')" onmouseenter="this.style.transform='translateY(-1px)'" onmouseleave="this.style.transform=''">
    <div style="display:flex;align-items:flex-start;gap:10px">
      <div style="font-size:10px;font-weight:900;color:var(--g2);width:20px;text-align:center;flex-shrink:0;padding-top:3px">${sno}</div>
      <div style="width:34px;height:34px;border-radius:50%;background:${c.color};display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:900;color:#fff;flex-shrink:0">${c.initials}</div>
      <div style="flex:1;min-width:0">
        <div style="display:flex;align-items:center;gap:7px;flex-wrap:wrap">
          <div style="font-size:13px;font-weight:900">${c.patient}</div>
          <div style="font-family:var(--mono);font-size:9px;color:var(--bmh-teal);font-weight:700">${c.bmhId}</div>
          <span class="badge ${statusStyle.badge}" style="font-size:9.5px">${statusStyle.label}</span>
          ${c.admitToIpd ? '<span class="badge bd-purple" style="font-size:9px">🛏️ Admitted</span>' : ''}
          ${priorityBadge}
        </div>
        <div style="font-size:11px;color:var(--tx3);margin-top:3px;font-weight:600">${c.procedure}</div>
        <div style="font-size:10.5px;color:var(--g1);margin-top:2px">${c.dx}</div>
        <div style="display:flex;gap:12px;flex-wrap:wrap;font-size:10.5px;color:var(--g1);margin-top:4px">
          <span>👨‍⚕️ ${c.surgeon}</span>
          <span>📅 ${formatDateIN(c.date)}</span>
          <span>🕐 ${c.scheduledTime}</span>
          <span>🏥 ${c.room}</span>
          ${surgeryMeta?`<span>${surgeryMeta}</span>`:''}
        </div>
        ${whoHTML}
        ${otActionIconsHtml(c.id)}
        ${timings.incision&&timings.procEnd?`<div style="font-size:10px;color:${c.status==='completed'?'#1a8c3c':'var(--blue)'};font-weight:700;margin-top:4px">✂️ In: ${timings.incision} → Out: ${timings.procEnd} · Anaes: ${timings.anaesStart||'—'}</div>`:''}
        ${c.complications&&c.complications!=='None'?`<div style="font-size:10px;color:var(--red);font-weight:800;margin-top:3px">⚠️ Complication: ${c.complications}</div>`:''}
      </div>
      <div style="display:flex;flex-direction:column;gap:5px;flex-shrink:0">
        <select style="font-size:10px;padding:3px 5px;border-radius:6px" onchange="updateOTStatus('${c.id}',this.value)" onclick="event.stopPropagation()">
          <option value="pending" ${c.status==='pending'?'selected':''}>Pending</option>
          <option value="in-progress" ${c.status==='in-progress'?'selected':''}>In Progress</option>
          <option value="completed" ${c.status==='completed'?'selected':''}>Completed</option>
          <option value="postponed" ${c.status==='postponed'?'selected':''}>Postponed</option>
        </select>
        <button class="btn btn-xs btn-outline" onclick="event.stopPropagation();openOTAddModal({caseId:'${c.id}'})">✏️ Edit</button>
        ${pack ? `<button class="btn btn-xs btn-gold" onclick="event.stopPropagation();printSurgeryPackForCase('${c.id}','${pack.id}')">📋 Pack</button>` : ''}
        <button class="btn btn-xs btn-outline" onclick="event.stopPropagation();printOTCard('${c.id}')">🖨️</button>
        <button class="btn btn-xs btn-gray" onclick="event.stopPropagation();deleteOTCase('${c.id}')">🗑️</button>
      </div>
    </div>
  </div>`;
}

// ─── OPEN OT CASE DETAIL ─────────────
function openOTCase(id) {
  const idx = OT_CASES.findIndex(x=>x.id===id); if(idx<0) return;
  OT_CASES[idx] = normalizeOTCaseRecord(OT_CASES[idx]);
  const c = OT_CASES[idx];
  activeOTCase = c;

  const timerCase = document.getElementById('ot-timer-case');
  if(timerCase) timerCase.textContent = `${c.patient} · ${c.id}`;

  // Prefill timings
  ['in','anaes','incision','proc-end','out','rr'].forEach((t,i)=>{
    const key = ['patientIn','anaesStart','incision','procEnd','patientOut','rrIn'][i];
    const el = document.getElementById('ot-t-'+t); if(el) el.value = c.timings[key]||'';
  });

  // Prefill notes
  const setVal = (id,val)=>{ const el=document.getElementById(id); if(el) el.value=val; };
  setVal('ot-preop-dx', c.dx || getPreferredOtDiagnosis(c.procedure));
  setVal('ot-postop-dx', c.postopDx || getPreferredOtPostDiagnosis(c.procedure) || c.dx);
  setVal('ot-procedure', c.procedure);
  setVal('ot-implant', c.iol);
  setVal('ot-anaes-dr', c.anaesDoc);
  setVal('ot-findings', c.findings||'');
  setVal('ot-narrative', c.narrative||'');
  setVal('ot-notes', c.notes||'');
  setVal('ot-blood-loss', c.bloodLoss||'');
  setVal('ot-scrub-nurse', c.scrubNurse||'');
  setVal('ot-circ-nurse', c.circNurse||'');
  populateOTPostOpDiagnosisOptions(document.getElementById('ot-postop-dx')?.value || c.postopDx || c.dx || '');
  if (typeof refreshOTNotesTemplateSelect === 'function') refreshOTNotesTemplateSelect();
  if (typeof refreshOTFollowupTemplateSelect === 'function') refreshOTFollowupTemplateSelect();
  const fuSel = document.getElementById('ot-followup-template');
  if (fuSel) fuSel.value = c.followupTemplateKey || '';

  const selAnaes = document.getElementById('ot-anaes-type');
  if(selAnaes) selAnaes.value = c.anaes;

  const selSurg = document.getElementById('ot-notes-surgeon');
  if(selSurg) selSurg.value = c.surgeon;

  const selComp = document.getElementById('ot-complications');
  if(selComp && c.complications) selComp.value = c.complications;

  // Detail panel
  const detail = document.getElementById('ot-case-detail'); if(!detail) return;
  const statusColor = {pending:'var(--g1)','in-progress':'var(--blue)',completed:'#1a8c3c',postponed:'var(--red)'}[c.status]||'var(--g1)';
  detail.innerHTML = `
    <div class="card-hd">
      <div>
        <div class="card-title">${c.patient}</div>
        <div style="font-family:var(--mono);font-size:10px;color:var(--bmh-teal)">${c.bmhId} · ${c.id}</div>
      </div>
      <span class="badge" style="background:${c.status==='completed'?'var(--green-lt)':c.status==='in-progress'?'var(--blue-lt)':'var(--g5)'};color:${statusColor}">${c.status.replace('-',' ').toUpperCase()}</span>
    </div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;font-size:11.5px;margin-bottom:12px">
      ${[['Age/Sex',`${c.age}Y / ${c.sex}`],['Procedure',c.procedure],['OT Date',formatDateIN(c.date)],['Surgeon',c.surgeon],['Room',c.room],['Time',c.scheduledTime],['Anaesthesia',c.anaes],['IOL/Implant',c.iol],['Priority',c.priority.toUpperCase()]].map(([l,v])=>`<div><div style="font-size:9px;font-weight:800;color:var(--g1);text-transform:uppercase;letter-spacing:.4px">${l}</div><div style="font-weight:700;margin-top:1px">${v}</div></div>`).join('')}
    </div>
    <div style="background:var(--g6);border-radius:var(--rsm);padding:10px;margin-bottom:10px">
      <div style="font-size:10px;font-weight:800;color:var(--g1);text-transform:uppercase;letter-spacing:.5px;margin-bottom:5px">Diagnosis</div>
      <div style="font-size:12px;font-weight:700">${c.dx}</div>
    </div>
    ${c.notes?`<div style="background:var(--blue-lt);border-radius:var(--rsm);padding:10px;margin-bottom:10px"><div style="font-size:10px;font-weight:800;color:var(--blue);text-transform:uppercase;letter-spacing:.5px;margin-bottom:5px">Notes / Special Instructions</div><div style="font-size:12px;color:var(--tx3)">${c.notes}</div></div>`:''}
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;margin-bottom:12px">
      ${[['Pre-op Workup',c.preop,'#1a8c3c'],['Consent',c.consent,'#1a8c3c'],['Fasting',c.fasting,'#1a8c3c']].map(([l,v,col])=>`<div style="background:var(--green-lt);border-radius:7px;padding:8px;text-align:center"><div style="font-size:9px;font-weight:800;color:${col};text-transform:uppercase;letter-spacing:.4px;margin-bottom:3px">${l}</div><div style="font-size:10.5px;font-weight:700;color:${col}">${v}</div></div>`).join('')}
    </div>
    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:6px;margin-bottom:12px">
      ${[['Sign In',c.signIn,'signin'],['Time Out',c.timeOut,'timeout'],['Sign Out',c.signOut,'signout']].map(([l,done,tab])=>`<button onclick="ptab(document.querySelector('.ptab[onclick*=${tab}]'),\\'who-${tab}\\')">
        <div style="background:${done?'var(--green-lt)':'var(--g6)'};border-radius:8px;padding:9px;text-align:center;cursor:pointer;border:1.5px solid ${done?'var(--green)':'var(--g4)'}">
          <div style="font-size:16px">${done?'✅':'⬜'}</div>
          <div style="font-size:10px;font-weight:800;color:${done?'#1a8c3c':'var(--g1)'};margin-top:3px">${l}</div>
        </div></button>`).join('')}
    </div>
    <div style="display:flex;gap:7px;flex-wrap:wrap">
      <button class="btn btn-gold btn-sm" onclick="printOTCard('${c.id}')">🖨️ Print OT Card</button>
      <button class="btn btn-outline btn-sm" onclick="openOTAddModal({caseId:'${c.id}'})">✏️ Edit OT Case</button>
      <button class="btn btn-outline btn-sm" onclick="printOTNotes()">📝 Operative Notes</button>
      <button class="btn btn-blue btn-sm" onclick="printWHOChecklist()">✅ WHO Checklist</button>
    </div>`;

  calcOTDurations();
  showToast(`OT Case ${c.id} opened ✓`,'i');
}

// ─── OT UTILITY FUNCTIONS ─────────────
function stampTime(id) {
  const el = document.getElementById(id); if(!el) return;
  el.value = new Date().toTimeString().slice(0,5);
  showToast('⏱️ Time stamped: '+el.value,'s');
  // Save to activeOTCase.timings
  if(activeOTCase) {
    const keyMap = {'ot-t-in':'patientIn','ot-t-anaes':'anaesStart','ot-t-incision':'incision','ot-t-proc-end':'procEnd','ot-t-out':'patientOut','ot-t-rr':'rrIn'};
    const key = keyMap[id];
    if(key) {
      activeOTCase.timings[key] = el.value;
      fbUpdate('otCases/'+activeOTCase.id, {'timings':activeOTCase.timings}).catch(()=>{});
    }
  }
  calcOTDurations();
}

function calcOTDurations() {
  const get = id => { const el=document.getElementById(id); return el?.value||''; };
  const toMins = t => { if(!t) return null; const [h,m]=t.split(':').map(Number); return h*60+m; };
  const fmt = mins => { if(mins===null||isNaN(mins)||mins<0) return '—'; return `${Math.floor(mins/60)?Math.floor(mins/60)+'h ':''}${mins%60}m`; };

  const anaes = toMins(get('ot-t-anaes'));
  const incision = toMins(get('ot-t-incision'));
  const procEnd = toMins(get('ot-t-proc-end'));
  const ptIn = toMins(get('ot-t-in'));
  const ptOut = toMins(get('ot-t-out'));

  const el1=document.getElementById('dur-anaes-incision'); if(el1) el1.textContent=fmt(anaes&&incision?incision-anaes:null);
  const el2=document.getElementById('dur-procedure'); if(el2) el2.textContent=fmt(incision&&procEnd?procEnd-incision:null);
  const el3=document.getElementById('dur-total-ot'); if(el3) el3.textContent=fmt(ptIn&&ptOut?ptOut-ptIn:null);
}

function updateOTStatus(id, status) {
  const c = OT_CASES.find(x=>x.id===id); if(!c) return;
  c.status = status;
  c.lastUpdated = new Date().toISOString();
  let extraUpdates = {};
  if (status === 'completed') {
    const consumeResult = consumeIolForOtCase(c);
    if (consumeResult?.pending) {
      c.iolInventoryPending = true;
      extraUpdates.iolInventoryPending = true;
      if (consumeResult.reason) showToast(consumeResult.reason, 'i');
    }
    if (consumeResult?.updates) extraUpdates = Object.assign(extraUpdates, consumeResult.updates);
    scheduleDefaultSurgeryFollowups(c);
  }
  fbUpdate('otCases/' + id, Object.assign({ status: c.status, lastUpdated: c.lastUpdated }, extraUpdates)).catch(e => console.warn('OT status save error:', e));
  renderOTList();
  showToast(`${c.patient} — status updated to ${c.status} ✓`,'s');
  if(activeOTCase?.id===id) openOTCase(id);
}
function formatFollowupDisplayDate(dateStr) {
  if (!dateStr) return '—';
  try {
    return formatDateIN(dateStr);
  } catch (e) {
    return dateStr;
  }
}
/** Post-op follow-up slot: 11:30 base, +10 min per additional OT case same day for this patient. */
function computePostOpFollowupBaseTimeMinutes(otCase) {
  const c = normalizeOTCaseRecord(otCase || {});
  const surgeryDate = String(c.date || '').slice(0, 10);
  if (!c.bmhId || !surgeryDate) return 11 * 60 + 30;
  const sameDay = (OT_CASES || []).filter(function (row) {
    const oc = normalizeOTCaseRecord(row);
    return oc.bmhId === c.bmhId && String(oc.date || '').slice(0, 10) === surgeryDate;
  });
  sameDay.sort(function (a, b) {
    return String(a.id || '').localeCompare(String(b.id || ''));
  });
  const idx = sameDay.findIndex(function (row) {
    return normalizeOTCaseRecord(row).id === c.id;
  });
  const ord = idx < 0 ? 0 : idx;
  return 11 * 60 + 30 + ord * 10;
}
function minutesToTime24(totalMins) {
  const m = ((totalMins % (24 * 60)) + 24 * 60) % (24 * 60);
  const h = Math.floor(m / 60);
  const mm = m % 60;
  return String(h).padStart(2, '0') + ':' + String(mm).padStart(2, '0');
}
function scheduleDefaultSurgeryFollowups(otCase) {
  const source = otCase || {};
  const c = normalizeOTCaseRecord(source);
  if (!c.bmhId || !c.date) return;
  const linkedTemplate = getOtFollowupTemplateEntry(c);
  const plan = linkedTemplate ? getOtFollowupTemplatePlan(linkedTemplate, c.date) : [];
  const dayOffsets = plan.length ? plan.map(function (row) {
    return { days: row.days, label: row.label, type: 'post-op' };
  }) : [
    { days: 1, label: 'Day 1 review (next morning)', type: 'post-op' },
    { days: 7, label: '1 week review', type: 'post-op' },
    { days: 14, label: '2 week review', type: 'post-op' }
  ];
  const baseDate = new Date(c.date + 'T09:00:00');
  const baseMins = computePostOpFollowupBaseTimeMinutes(c);
  const time = normalizeAptTimeLabel(minutesToTime24(baseMins));
  const made = [];
  dayOffsets.forEach(function (cfg) {
    const dt = new Date(baseDate.getTime() + cfg.days * 24 * 60 * 60 * 1000);
    const iso = dt.toISOString().split('T')[0];
    const existing = (APPOINTMENTS || []).find(function (a) {
      return a.bmhId === c.bmhId && a.date === iso && a.type === 'post-op' && /post-op/i.test(String(a.purpose || ''));
    });
    const apt = existing || {
      id: 'APT' + Date.now() + Math.random().toString(36).slice(2, 5),
      patient: c.patient,
      bmhId: c.bmhId,
      doctor: c.surgeon || CURRENT_USER?.name || '',
      date: iso,
      type: cfg.type,
      source: 'ot-followup-template',
      centre: c.centre || CURRENT_USER?.centre || 'CHD',
      status: 'booked'
    };
    apt.time = time;
    apt.purpose = cfg.label + ' — ' + (c.procedure || 'Surgery');
    apt.dateFormatted = formatFollowupDisplayDate(iso);
    if (!existing) APPOINTMENTS.push(apt);
    saveAppointmentToFirebase && saveAppointmentToFirebase(apt);
    made.push(apt);
  });
  c.autoFollowups = made.map(function (a) { return { date: a.date, time: a.time, label: a.purpose, dateLabel: formatFollowupDisplayDate(a.date) }; });
  c.autoFollowups = made.map(function (a, idx) { return { date: a.date, time: a.time, label: dayOffsets[idx]?.label || 'Follow-up', dateLabel: formatFollowupDisplayDate(a.date) }; });
  source.autoFollowups = c.autoFollowups.slice();
  saveOTCasesToLocalStorage();
  fbUpdate('otCases/' + c.id, { autoFollowups: c.autoFollowups }).catch(function () {});
  renderAptDay && renderAptDay();
}

function setWHOChecked(el, checked) {
  if (!el) return;
  el.setAttribute('data-checked', checked ? '1' : '0');
  el.style.background = checked ? 'var(--green)' : '#fff';
  el.style.borderColor = checked ? 'var(--green)' : 'var(--g4)';
  el.textContent = checked ? '✓' : '';
  el.style.color = checked ? '#fff' : '';
}
function toggleWHO(el) {
  const checked = el.getAttribute('data-checked') !== '1';
  setWHOChecked(el, checked);
}
function checkAllWHO(phase) {
  const tab = document.getElementById('who-' + phase);
  if (!tab) return;
  tab.querySelectorAll('.who-cb').forEach(function (el) { setWHOChecked(el, true); });
  showToast(`All WHO ${phase==='signin'?'Sign In':phase==='timeout'?'Time Out':'Sign Out'} items checked ✓`,'s');
}

function signOffWHO(phase) {
  if(!activeOTCase){showToast('Select a case first','w');return;}
  const field = phase==='signin'?'signIn':phase==='timeout'?'timeOut':'signOut';
  // Check all checkboxes in the relevant WHO tab are ticked
  const tabId = 'who-'+phase;
  const tab = document.getElementById(tabId);
  const unchecked = tab ? tab.querySelectorAll('.who-cb:not([data-checked="1"])') : [];
  if(unchecked.length>0) {
    showToast('⚠️ Please complete all checklist items before signing off','w'); return;
  }
  activeOTCase[field] = true;
  activeOTCase[field+'Time'] = new Date().toTimeString().slice(0,5);
  activeOTCase[field+'By'] = CURRENT_USER?.name || '—';
  fbUpdate('otCases/' + activeOTCase.id, {
    [field]: true,
    [field+'Time']: activeOTCase[field+'Time'],
    [field+'By']: activeOTCase[field+'By'],
    lastUpdated: new Date().toISOString()
  }).catch(e => console.warn('WHO save error:', e));
  showToast(`✅ WHO ${phase==='signin'?'Sign In':phase==='timeout'?'Time Out':'Sign Out'} completed for ${activeOTCase.patient} ✓`,'s');
  renderOTList();
  openOTCase(activeOTCase.id);
}

function addOTCase() {
  if (window._savingOTCase) {
    showToast('OT case is already being added…', 'i');
    return;
  }
  window._savingOTCase = true;
  const saveBtn = document.getElementById('ot-add-save-btn');
  const prevBtnHtml = saveBtn ? saveBtn.innerHTML : '';
  if (saveBtn) {
    saveBtn.disabled = true;
    saveBtn.innerHTML = '⏳ Saving...';
  }
  const releaseOtSaveButton = function () {
    window._savingOTCase = false;
    if (saveBtn) {
      saveBtn.disabled = false;
      saveBtn.innerHTML = prevBtnHtml || '✅ Add to OT List';
    }
  };
  const editId = document.getElementById('ot-add-case-id')?.value || '';
  const ptSel = document.getElementById('ot-pt-sel');
  const ptOpt = ptSel?.options[ptSel.selectedIndex];
  const rawSelectedName = ptOpt?.text?.split(' — ')[0] || '';
  const selectedName = /search above|select patient|select\s*—/i.test(rawSelectedName) ? '' : rawSelectedName;
  const ptId = document.getElementById('ot-bmsh-id')?.value || ptSel?.value || '';
  const proc = document.getElementById('ot-add-proc')?.value||'';
  const surgeon = document.getElementById('ot-add-surgeon')?.value||'';
  const anaes = document.getElementById('ot-add-anaes')?.value||'';
  const date = document.getElementById('ot-add-date')?.value||new Date().toISOString().split('T')[0];
  const time = document.getElementById('ot-add-time')?.value||'09:00';
  const room = document.getElementById('ot-add-room')?.value||'Eye OT';
  const dx = document.getElementById('ot-add-dx')?.value||'';
  const site = document.getElementById('ot-add-site')?.value||'';
  const iol = document.getElementById('ot-add-iol')?.value||'N/A';
  const iolType = document.getElementById('ot-add-iol-model')?.value || '';
  const iolPower = document.getElementById('ot-add-iol-power')?.value || extractIolPower(iol);
  const iclConfig = getOtIclConfigFromForm();
  const iclSummary = buildOtIclSummary(iclConfig);
  const obgCaseType = document.getElementById('ot-add-obg-type')?.value || '';
  const obgGa = document.getElementById('ot-add-obg-ga')?.value || '';
  const obgIndication = document.getElementById('ot-add-obg-indication')?.value || '';
  const obgFetal = document.getElementById('ot-add-obg-fetal')?.value || '';
  const obgLiquor = document.getElementById('ot-add-obg-liquor')?.value || '';
  const obgBlood = document.getElementById('ot-add-obg-blood')?.value || '';
  const obgAnaesNote = document.getElementById('ot-add-obg-anaes-note')?.value || '';
  const obgBaby = document.getElementById('ot-add-obg-baby')?.value || '';
  const obgMother = document.getElementById('ot-add-obg-mother')?.value || '';
  const obgDocs = {
    lscsConsent: !!document.getElementById('ot-add-obg-doc-consent')?.checked,
    anaesConsent: !!document.getElementById('ot-add-obg-doc-anaes')?.checked,
    bloodConsent: !!document.getElementById('ot-add-obg-doc-blood')?.checked,
    newbornSheet: !!document.getElementById('ot-add-obg-doc-newborn')?.checked
  };
  const admitToIpd = !!document.getElementById('ot-add-admit')?.checked;
  const ipdType = document.getElementById('ot-add-admit-type')?.value || '';
  const ipdWard = document.getElementById('ot-add-admit-ward')?.value || '';
  const ipdRoom = document.getElementById('ot-add-admit-room')?.value || '';
  const ipdMonitoring = document.getElementById('ot-add-admit-monitoring')?.value || '';
  const ipdNotes = document.getElementById('ot-add-admit-notes')?.value || '';
  const priority = document.getElementById('ot-add-priority')?.value||'elective';
  const notes = document.getElementById('ot-add-notes')?.value||'';
  const preop = document.getElementById('ot-add-preop')?.value||'';
  const consent = document.getElementById('ot-add-consent')?.value||'';
  const fasting = document.getElementById('ot-add-fasting')?.value||'';
  const pt = PATIENTS.find(p=>p.bmhId===ptId) || (window.CURRENT_PATIENT?.bmhId === ptId ? window.CURRENT_PATIENT : null);
  const ptName = pt?.name || selectedName || 'New Patient';
  const caseKind = getSelectedOTCaseKind();

  if (!ptId && !editId) {
    showToast('Select a patient from lookup before adding to OT list', 'w');
    releaseOtSaveButton();
    return;
  }
  if (ptSel && pt && ![].slice.call(ptSel.options).some(function (o) { return o.value === pt.bmhId; })) {
    const opt = document.createElement('option');
    opt.value = pt.bmhId;
    opt.textContent = `${pt.name} — ${pt.bmhId} — ${pt.age||'?'}Y/${pt.sex||''}`;
    ptSel.appendChild(opt);
    ptSel.value = pt.bmhId;
  }

  const existing = editId ? normalizeOTCaseRecord(OT_CASES.find(function (c) { return c.id === editId; }) || {}) : null;
  const newCase = {
    id: editId || ('OT-'+Date.now()), bmhId:ptId, patient:ptName,
    age:pt?.age||'—', sex:pt?.sex||'—',
    caseKind,
    dx, procedure:proc, procedureMain: parseOtProcedureSelection(proc).main, procedureSub: parseOtProcedureSelection(proc).sub, site, surgeon, anaes, anaesDoc:'',
    date, scheduledTime:time, room, iol: iclSummary || iol, iolType: iclSummary ? (iclConfig.eyes === 'both' ? 'STARR ICL (Both Eyes)' : 'STARR ICL (One Eye)') : iolType, iolPower: (iclSummary ? (iclConfig.eyes === 'both' ? [(iclConfig.firstPower || '—'), (iclConfig.secondPower || '—')].join(' / ') : (iclConfig.onePower || '—')) : iolPower), iclConfig, priority,
    obgCaseType, obgGa, obgIndication, obgFetal, obgLiquor, obgBlood, obgAnaesNote, obgBaby, obgMother, obgDocs,
    centre: pt?.centre || getEffectiveCentre() || CURRENT_USER?.centre || 'CHD',
    preop, consent, fasting, status:'pending',
    admitToIpd, ipdType, ipdWard, ipdRoom, ipdMonitoring, ipdNotes,
    timings:{patientIn:'',anaesStart:'',incision:'',procEnd:'',patientOut:'',rrIn:''},
    complications:'', bloodLoss:'', notes,
    signIn:false, timeOut:false, signOut:false,
    scrubNurse:'', circNurse:'',
    color:pt?.color||'#1A3C6E', initials:ptName.split(' ').map(n=>n[0]).join('').substring(0,2).toUpperCase(),
    createdAt: new Date().toISOString(),
    createdBy: CURRENT_USER?.name || 'System'
  };
  const normalized = normalizeOTCaseRecord(Object.assign({}, existing || {}, newCase));
  if (normalized.procedure) saveOtProcedureOption(normalized.procedure, caseKind === 'obg' ? 'obg' : 'ophtho');
  if (normalized.procedureMain) saveOtProcedureOption(normalized.procedureMain, caseKind === 'obg' ? 'obg' : 'ophtho');
  if (normalized.anaes) normalized.anaes = saveOTAnaesthesiaOption(normalized.anaes) || normalized.anaes;
  if (normalized.dx) rememberManualDiagnosis(normalized.dx, normalized.caseKind === 'obg' ? 'obg' : 'ophtho');
  if (!normalized.dx) normalized.dx = getPreferredOtDiagnosis(normalized.procedure || proc) || normalized.dx;
  if (!normalized.postopDx) normalized.postopDx = getPreferredOtPostDiagnosis(normalized.procedure || proc) || normalized.postopDx;
  if (caseKind === 'obg') {
    normalized.site = 'N/A';
    normalized.eye = 'N/A';
    normalized.iol = 'N/A';
    normalized.iolType = '';
    normalized.iolPower = '';
    if (!/labour room|laser room/i.test(normalized.room || '')) normalized.room = obgCaseType === 'Normal Delivery' || obgCaseType === 'Assisted Delivery' ? 'Labour Room' : (normalized.room || 'Gynae OT');
  }
  if (otProcedureLooksLikeLaserOrMinor(normalized.procedure || proc) && caseKind !== 'obg') {
    normalized.iol = 'N/A';
    normalized.iolType = '';
    normalized.iolPower = '';
    if (!normalized.room || /^eye ot$/i.test(normalized.room)) normalized.room = 'Laser Room';
  }
  if (editId) {
    const idx = OT_CASES.findIndex(function (c) { return c.id === editId; });
    if (idx >= 0) OT_CASES[idx] = normalized;
    else OT_CASES.push(normalized);
  } else {
    OT_CASES.push(normalized);
  }
  saveOTCasesToLocalStorage();
  renderOTList();
  renderIPD && renderIPD();
  closeM('m-ot-add');
  activeOTCase = normalized;
  openOTCase(normalized.id);
  persistOTCaseToCloud(normalized)
    .then(function () {
      if (admitToIpd) ensureIpdAdmissionFromOTCase(normalized, pt);
      showToast(`⚕️ ${ptName} ${editId ? 'updated in' : 'added to'} OT list ✓`,'s');
    })
    .catch(function (e) {
      console.warn('OT save error:', e);
      showToast('OT saved locally. Cloud sync failed, will retry on next update.', 'w');
    })
    .finally(releaseOtSaveButton);
}
function otQuickAddProcedureToCharges() {
  const proc = String(document.getElementById('ot-add-proc')?.value || '').trim();
  if (!proc) { showToast('Type/select procedure first', 'w'); return; }
  const parent = parseOtProcedureSelection(proc).main || '';
  const exists = (CHARGES_DATA || []).some(function (row) {
    return String(row?.name || '').trim().toLowerCase() === proc.toLowerCase();
  });
  if (exists) { showToast('Procedure already exists in charges', 'i'); return; }
  const chd = Number(window.prompt('CHD amount for "' + proc + '"', '0') || 0);
  const rprRaw = window.prompt('RPR amount (leave blank to use CHD)', String(chd || 0));
  const rpr = rprRaw === null || String(rprRaw).trim() === '' ? chd : Number(rprRaw || 0);
  const cat = getSelectedOTCaseKind() === 'obg' ? 'OBG' : 'Eye Sx';
  CHARGES_DATA.push({
    cat: cat,
    kind: 'surgery',
    parent: parent && parent.toLowerCase() !== proc.toLowerCase() ? parent : '',
    name: proc,
    chd: Number.isFinite(chd) ? chd : 0,
    rpr: Number.isFinite(rpr) ? rpr : (Number.isFinite(chd) ? chd : 0)
  });
  saveChargesToFirebase && saveChargesToFirebase();
  renderChargesList && renderChargesList();
  populateOTProcedureOptions(proc);
  showToast('Procedure added to charges ✓', 's');
}

function lookupOTPatient(val) {
  const el = document.getElementById('ot-pt-lookup-result'); if(!el) return;
  if(!val||val.length<3) { el.innerHTML=''; return; }
  const v = val.trim().toUpperCase();
  const vLow = val.trim().toLowerCase();
  const compact = val.replace(/\s/g,'');
  // Search by BMSH ID, phone, or name
  const matches = (PATIENTS || []).filter(function (x) {
    if (!x) return false;
    const bmhId = String(x.bmhId || '').toUpperCase();
    const phone = String(x.mob || x.mobile || '').replace(/\s/g, '');
    const name = String(x.name || '').toLowerCase();
    return bmhId === v
      || bmhId.includes(v.replace('BMSH-', ''))
      || phone.includes(compact)
      || name.includes(vLow);
  }).slice(0,5);
  if(matches.length===1) {
    const p=matches[0];
    el.innerHTML = `<div style="background:var(--green-lt);border-radius:8px;padding:9px;border-left:3px solid var(--green);display:flex;align-items:center;gap:9px">
      <div style="flex:1;font-size:12.5px"><strong>${p.name}</strong> · ${p.bmhId} · ${p.age||'?'}Y/${p.sex||''}</div>
      <div style="display:flex;gap:6px;flex-wrap:wrap">
        <button class="btn btn-xs btn-gold" onclick="fillOTFromPatient('${p.bmhId}')">✅ Prefill</button>
        <button class="btn btn-xs btn-outline" onclick="openPatient('${p.bmhId}')">Open</button>
      </div>
    </div>`;
  } else if(matches.length>1) {
    el.innerHTML = `<div style="border:1.5px solid var(--blue);border-radius:8px;overflow:hidden">
      <div style="padding:5px 10px;background:var(--blue-lt);font-size:10px;font-weight:800;color:var(--blue)">${matches.length} patients found</div>
      ${matches.map(p=>`<div style="display:flex;align-items:center;gap:8px;padding:7px 10px;border-bottom:1px solid var(--g5)">
        <div style="flex:1;font-size:12px"><strong>${p.name}</strong> · ${p.bmhId} · ${p.age||'?'}Y/${(p.sex||'?')[0]}</div>
        <div style="display:flex;gap:6px;flex-wrap:wrap">
          <button class="btn btn-xs btn-gold" onclick="fillOTFromPatient('${p.bmhId}')">Prefill</button>
          <button class="btn btn-xs btn-outline" onclick="openPatient('${p.bmhId}')">Open</button>
        </div>
      </div>`).join('')}
    </div>`;
  } else {
    el.innerHTML = val.length>=4 ? '<div style="font-size:11px;color:var(--g1);padding:8px;background:var(--g6);border-radius:8px;display:flex;align-items:center;justify-content:space-between;gap:8px"><span>No patient found — check BMSH ID or phone</span><button class="btn btn-xs btn-gold" onclick="openNewPatientDialog()">+ New Patient</button></div>' : '';
  }
}
function prefillOTLookupValue() {
  const raw = String(document.getElementById('ot-pt-lookup')?.value || '').trim();
  if (!raw) { showToast('Enter BMSH ID or phone first', 'w'); return; }
  const upper = raw.toUpperCase();
  const lower = raw.toLowerCase();
  const matches = PATIENTS.filter(function (x) {
    if (!x) return false;
    const bmhId = String(x.bmhId || '').toUpperCase();
    const phone = String(x.mob || x.mobile || '').replace(/\s/g, '');
    const name = String(x.name || '').toLowerCase();
    return bmhId === upper
      || bmhId.includes(upper.replace('BMSH-', ''))
      || phone.includes(raw.replace(/\s/g, ''))
      || name.includes(lower);
  });
  if (!matches.length) { showToast('No patient found for this BMSH ID / phone', 'w'); return; }
  fillOTFromPatient(matches[0].bmhId);
}
function inferOtObgTypeFromVisit(visit, procText) {
  const hay = [procText, visit?.['obg-obs-mode-delivery'], visit?.['obg-obs-csection-indication'], visit?.clinicalImpression, visit?.dx, Array.isArray(visit?.obgProcAdvised) ? visit.obgProcAdvised.join(' ') : '']
    .join(' ')
    .toLowerCase();
  if (/lscs|caesar|cesarean|caesarean/.test(hay)) return /emergency|distress|meconium|cord|cpd|failed|fetal distress/.test(hay) ? 'Emergency LSCS' : 'Elective LSCS';
  if (/forceps|vaccum|vacuum|assisted/.test(hay)) return 'Assisted Delivery';
  if (/normal delivery|vaginal delivery|normal labour|natural/.test(hay)) return 'Normal Delivery';
  if (/mtp|suction|evacuation|d&c|abortion/.test(hay)) return /painless/.test(hay) ? 'Painless Abortion' : 'MTP / Suction Evacuation';
  if (/iucd|cu-t|multiload/.test(hay)) return 'IUCD Insertion / Removal';
  if (/hyst|lapar|cyst|myom|salping|gynae surgery/.test(hay)) return 'Gynae Surgery';
  return '';
}
function prefillOtObgFieldsFromPatient(p) {
  const visit = p?.lastVisit || {};
  const setV = function (id, value) {
    const el = document.getElementById(id);
    if (el) el.value = value || '';
  };
  const joinBits = function (values) {
    return values.map(function (value) { return String(value || '').trim(); }).filter(Boolean).join(' · ');
  };
  const obgType = inferOtObgTypeFromVisit(visit, document.getElementById('ot-add-proc')?.value || '');
  const suggestedProcedure = String(document.getElementById('ot-add-proc')?.value || '').trim()
    || (Array.isArray(visit.obgProcAdvised) && visit.obgProcAdvised[0])
    || (Array.isArray(visit.planProcedures) && visit.planProcedures[0])
    || visit['obg-obs-mode-delivery']
    || '';
  if (suggestedProcedure) {
    setV('ot-add-proc', suggestedProcedure);
    populateOTProcedureOptions(suggestedProcedure);
  }
  if (visit.dx || visit.clinicalImpression) {
    populateOTDiagnosisOptions(visit.dx || visit.clinicalImpression || '');
    setV('ot-add-dx', visit.dx || visit.clinicalImpression || '');
  }
  if (obgType) setV('ot-add-obg-type', obgType);
  setV('ot-add-obg-ga', visit.ga || visit['obg-obs-gestation-age'] || '');
  setV('ot-add-obg-indication', visit['obg-obs-csection-indication'] || visit.clinicalImpression || visit.dx || visit.mainComplaint || '');
  setV('ot-add-obg-fetal', joinBits([visit.presentation, visit.fhr ? ('FHR ' + visit.fhr) : '', visit.fetalMovement ? ('FM ' + visit.fetalMovement) : '']));
  setV('ot-add-obg-liquor', joinBits([visit['obg-obs-liquor'], visit['obg-obs-liquor-note'], visit['obg-obs-cord-neck']]));
  setV('ot-add-obg-blood', joinBits([visit.bloodGroup, visit['obg-obs-rbs'] ? ('RBS ' + visit['obg-obs-rbs']) : '', visit.urineProtein ? ('Urine protein ' + visit.urineProtein) : '', visit.urineSugar ? ('Urine sugar ' + visit.urineSugar) : '']));
  setV('ot-add-obg-anaes-note', joinBits([visit.bp ? ('BP ' + visit.bp) : '', visit.weight ? ('Wt ' + visit.weight) : '', visit.riskTag]));
  setV('ot-add-obg-baby', joinBits([visit['obg-obs-gender'], visit['obg-obs-birth-weight'] ? ('Birth wt ' + visit['obg-obs-birth-weight']) : '', visit['obg-obs-apgar'] ? ('APGAR ' + visit['obg-obs-apgar']) : '', visit['obg-obs-nicu'] ? ('NICU ' + visit['obg-obs-nicu']) : '', visit['obg-obs-nicu-note']]));
  setV('ot-add-obg-mother', joinBits([visit.bp ? ('BP ' + visit.bp) : '', visit.weight ? ('Wt ' + visit.weight) : '', visit.clinicalImpression, visit.ancNotes]));
  const setChecked = function (id, value) {
    const el = document.getElementById(id);
    if (el) el.checked = !!value;
  };
  const deliveryFlow = /lscs|delivery/.test(String(obgType || '').toLowerCase()) || /delivery|labour|caesar|lscs/.test(String(suggestedProcedure || '').toLowerCase());
  const majorOtFlow = /lscs|gynae surgery|mtp/.test(String(obgType || '').toLowerCase());
  setChecked('ot-add-obg-doc-consent', deliveryFlow || majorOtFlow);
  setChecked('ot-add-obg-doc-anaes', majorOtFlow);
  setChecked('ot-add-obg-doc-blood', /lscs|placenta|pph|high-risk/.test(String([obgType, visit.riskTag, visit['obg-obs-pph']].join(' ')).toLowerCase()));
  setChecked('ot-add-obg-doc-newborn', deliveryFlow);
  const roomEl = document.getElementById('ot-add-room');
  if (roomEl && (!roomEl.value || /eye ot/i.test(roomEl.value))) {
    roomEl.value = /normal delivery|assisted delivery/.test(String(obgType || '').toLowerCase()) ? 'Labour Room' : 'Gynae OT';
  }
}

function fillOTFromPatient(bmhId) {
  const p = PATIENTS.find(x=>x.bmhId===bmhId); if(!p) return;
  // Update the dropdown
  const ptSel = document.getElementById('ot-pt-sel');
  if(ptSel) {
    // Add option if not present
    if(![...ptSel.options].some(o=>o.value===bmhId)) {
      const opt=document.createElement('option'); opt.value=bmhId;
      opt.textContent=`${p.name} — ${p.bmhId} — ${p.age||'?'}Y/${p.sex||''}`;
      ptSel.appendChild(opt);
    }
    ptSel.value=bmhId;
  }
  window.CURRENT_PATIENT = p;
  // Fill all fields
  const setV=(id,v)=>{const e=document.getElementById(id);if(e)e.value=v;};
  const isObg = normalizeDeptKeyForQueue(p.dept || '') === 'obg';
  const eyeRadio = document.getElementById('ot-case-kind-eye');
  const obgRadio = document.getElementById('ot-case-kind-obg');
  if (eyeRadio) eyeRadio.checked = !isObg;
  if (obgRadio) obgRadio.checked = !!isObg;
  setV('ot-bmsh-id', p.bmhId);
  setV('ot-age-sex', `${p.age||'?'}Y / ${p.sex||'—'}`);
  populateOTDiagnosisOptions('');
  setV('ot-add-dx', '');
  setV('ot-add-site', p.eye || p.opEye || p.surgEye || p.operatingEye || 'N/A');
  if(p.doctor) { const drSel=document.getElementById('ot-add-surgeon'); if(drSel) drSel.value=p.doctor; }
  setV('ot-add-proc', '');
  populateOTProcedureMainSelect('');
  const subSel = document.getElementById('ot-add-proc-sub');
  if (subSel) subSel.value = '';
  const subSel2 = document.getElementById('ot-add-proc-sub-2');
  if (subSel2) subSel2.value = '';
  populateOTProcedureOptions('');
  populateOTIolOptions(p.iol || p.iolType || '', p.iolPower || extractIolPower(p.iol || p.iolType || ''));
  if (isObg) prefillOtObgFieldsFromPatient(p);
  toggleOTOBGFields();
  toggleOTProcedureSpecificFields();
  // Clear lookup
  const el=document.getElementById('ot-pt-lookup-result'); if(el) el.innerHTML='';
  const lkp=document.getElementById('ot-pt-lookup'); if(lkp) lkp.value='';
  showToast(`✅ ${p.name} prefilled into OT case`,'s');
}

function prefillOTCase(bmhId) {
  if(!bmhId) return;
  fillOTFromPatient(bmhId);
}

