function getLikelyOtConsentIds(otCase) {
  const proc = String(otCase?.procedure || otCase?.procedureMain || '').toLowerCase();
  const out = [];
  if (/phaco|pmics|cataract|pciol|iol/.test(proc)) out.push('consent-cataract-hi', 'consent-cataract-pa', 'c-phaco');
  if (/ivt|intravitreal|anti-vegf|bevacizumab|ranibizumab|aflibercept/.test(proc)) out.push('c-ivt-vegf');
  if (/steroid|ozurdex|triamcinolone/.test(proc)) out.push('c-ivt-steroid');
  if (/trab/.test(proc)) out.push('c-trab');
  if (/lasik/.test(proc)) out.push('c-lasik');
  if (/pterygium/.test(proc)) out.push('c-pteryg');
  if (/dcr/.test(proc)) out.push('c-dcr');
  if (/squint/.test(proc)) out.push('c-squint');
  if (/ptosis|eyelid/.test(proc)) out.push('c-ptosis');
  if (/yag|capsulotomy/.test(proc)) out.push('c-yag');
  if (/iridotomy|lpi/.test(proc)) out.push('c-lpi');
  if (/trabeculoplasty|slt|alt/.test(proc)) out.push('c-alt');
  if (/lscs|caesar|caesare|cesare/.test(proc)) out.push('c-lscs');
  if (/normal delivery|assisted delivery|labour/.test(proc)) out.push('c-nd');
  if (/laparoscopy/.test(proc)) out.push('c-lap');
  if (/hysteroscopy|d&c|d and c/.test(proc)) out.push('c-hysteroscopy');
  if (/iucd|iud|cu-t/.test(proc)) out.push('c-iucd');
  if (/mtp|suction|evacuation|abortion/.test(proc)) out.push('obg-mtp-preop', 'obg-mtp-op', 'obg-mtp-postop');
  return Array.from(new Set(out)).filter(function (id) { return !!getConsentEntry(id); });
}
function openLikelyOtConsent() {
  const c = activeOTCase || {
    bmhId: document.getElementById('ot-bmsh-id')?.value || '',
    patient: (PATIENTS.find(function (p) { return p.bmhId === (document.getElementById('ot-bmsh-id')?.value || ''); }) || {}).name || '',
    procedure: document.getElementById('ot-add-proc')?.value || '',
    procedureMain: document.getElementById('ot-add-proc-main')?.value || ''
  };
  const likely = getLikelyOtConsentIds(c);
  if (!likely.length) {
    openM('m-consents');
    renderConsentModal && renderConsentModal();
    return;
  }
  if (likely.length === 1) {
    const data = getConsentEntry(likely[0]);
    if (data) {
      printStructuredConsentThreeVariants(data);
      showToast('Procedure consent sent to printer ✓', 's');
      return;
    }
  }
  openM('m-consents');
  populateConsentTypeSelectors && populateConsentTypeSelectors();
  const sel = document.getElementById('mc-type');
  if (sel && likely[0] && [].slice.call(sel.options).some(function (o) { return o.value === likely[0]; })) sel.value = likely[0];
  renderConsentModal && renderConsentModal();
  showToast('Likely consents loaded for this OT procedure', 'i');
}

function saveOTNotes() {
  if(!activeOTCase) { showToast('No case selected','w'); return; }
  const notes = document.getElementById('ot-notes')?.value || '';
  const complications = document.getElementById('ot-complications')?.value || 'None';
  const bloodLoss = document.getElementById('ot-blood-loss')?.value || document.querySelector('#pg-ot input[placeholder*="blood"]')?.value || '';
  const findings = document.getElementById('ot-findings')?.value || '';
  const narrative = document.getElementById('ot-narrative')?.value || '';
  const surgeon = document.getElementById('ot-notes-surgeon')?.value || activeOTCase.surgeon || '';
  const anaesDoc = document.getElementById('ot-anaes-dr')?.value || activeOTCase.anaesDoc || '';
  const scrubNurse = document.getElementById('ot-scrub-nurse')?.value || activeOTCase.scrubNurse || '';
  const circNurse = document.getElementById('ot-circ-nurse')?.value || activeOTCase.circNurse || '';
  const preDx = document.getElementById('ot-preop-dx')?.value || activeOTCase.dx || '';
  const postDx = document.getElementById('ot-postop-dx')?.value || activeOTCase.dx || '';
  const procedure = document.getElementById('ot-procedure')?.value || activeOTCase.procedure || '';
  const implant = document.getElementById('ot-implant')?.value || activeOTCase.iol || '';
  activeOTCase.notes = notes;
  activeOTCase.complications = complications;
  activeOTCase.bloodLoss = bloodLoss;
  activeOTCase.findings = findings;
  activeOTCase.narrative = narrative;
  activeOTCase.surgeon = surgeon;
  activeOTCase.anaesDoc = anaesDoc;
  activeOTCase.scrubNurse = scrubNurse;
  activeOTCase.circNurse = circNurse;
  activeOTCase.dx = postDx || preDx;
  activeOTCase.procedure = procedure || activeOTCase.procedure;
  activeOTCase.iol = implant || activeOTCase.iol;
  activeOTCase.followupTemplateKey = document.getElementById('ot-followup-template')?.value || activeOTCase.followupTemplateKey || '';
  if (activeOTCase.followupTemplateKey) scheduleDefaultSurgeryFollowups(activeOTCase);
  // Save to Firebase
  fbSet('otCases/' + activeOTCase.id, { ...activeOTCase, lastUpdated: new Date().toISOString(), updatedBy: CURRENT_USER?.name || 'System' })
    .then(() => showToast('Operative notes saved to database ✓', 's'))
    .catch(e => showToast('Save failed: ' + e.message, 'w'));
  renderOTList();
}
function refreshOTNotesTemplateSelect() {
  const sel = document.getElementById('ot-notes-template');
  if (!sel) return;
  const cur = sel.value;
  const activeProc = String(document.getElementById('ot-procedure')?.value || activeOTCase?.procedure || activeOTCase?.procedureMain || '').trim().toLowerCase();
  const activeMain = String(activeOTCase?.procedureMain || '').trim().toLowerCase();
  const activeDept = String(activeOTCase?.caseType || activeOTCase?.dept || '').toLowerCase();
  sel.innerHTML = '<option value="">— Select template —</option>';
  const otKeys = Object.keys(RX_TEMPLATES_DATA || {}).filter(function (key) {
    return normalizeRxTemplateDeptKey(RX_TEMPLATES_META[key]?.dept || '') === 'ot';
  }).sort(function (a, b) {
    const am = RX_TEMPLATES_META[a] || {};
    const bm = RX_TEMPLATES_META[b] || {};
    const aArea = String(am.otArea || '').toLowerCase();
    const bArea = String(bm.otArea || '').toLowerCase();
    const aTarget = am.surgery || am.name || '';
    const bTarget = bm.surgery || bm.name || '';
    const aAreaMatch = !activeDept || !aArea || aArea.indexOf(activeDept) >= 0;
    const bAreaMatch = !activeDept || !bArea || bArea.indexOf(activeDept) >= 0;
    const aMatch = (!activeProc && !activeMain) || otTemplateMatchesProcedure(aTarget, activeProc) || otTemplateMatchesProcedure(aTarget, activeMain);
    const bMatch = (!activeProc && !activeMain) || otTemplateMatchesProcedure(bTarget, activeProc) || otTemplateMatchesProcedure(bTarget, activeMain);
    if (aAreaMatch !== bAreaMatch) return aAreaMatch ? -1 : 1;
    if (aMatch !== bMatch) return aMatch ? -1 : 1;
    return String(am.name || a).localeCompare(String(bm.name || b));
  });
  otKeys.forEach(function (key) {
    const meta = RX_TEMPLATES_META[key] || {};
    const opt = document.createElement('option');
    opt.value = key;
    const target = meta.surgery || '';
    const area = String(meta.otArea || '').trim();
    const isMatch = (!activeProc && !activeMain) || otTemplateMatchesProcedure(target, activeProc) || otTemplateMatchesProcedure(target, activeMain);
    opt.textContent = (meta.name || key) + (area ? (' [' + area.replace(/^OT\s*-\s*/i, '') + ']') : '') + (target ? (' — ' + target) : '') + (isMatch ? '' : ' (other)');
    sel.appendChild(opt);
  });
  if ([].slice.call(sel.options).some(function (o) { return o.value === cur; })) sel.value = cur;
}
function refreshOTFollowupTemplateSelect() {
  const sel = document.getElementById('ot-followup-template');
  if (!sel) return;
  const cur = activeOTCase?.followupTemplateKey || sel.value || '';
  const activeProc = String(document.getElementById('ot-procedure')?.value || activeOTCase?.procedure || activeOTCase?.procedureMain || '').trim().toLowerCase();
  sel.innerHTML = '<option value="">— Select follow-up template —</option>';
  const keys = Object.keys(RX_TEMPLATES_DATA || {}).filter(function (key) {
    return normalizeRxTemplateDeptKey(RX_TEMPLATES_META[key]?.dept || '') === 'ot-followup';
  }).sort(function (a, b) {
    const am = RX_TEMPLATES_META[a] || {};
    const bm = RX_TEMPLATES_META[b] || {};
    const aMatch = !activeProc || otTemplateMatchesProcedure(am.surgery || am.name || '', activeProc);
    const bMatch = !activeProc || otTemplateMatchesProcedure(bm.surgery || bm.name || '', activeProc);
    if (aMatch !== bMatch) return aMatch ? -1 : 1;
    return String(am.name || a).localeCompare(String(bm.name || b));
  });
  keys.forEach(function (key) {
    const meta = RX_TEMPLATES_META[key] || {};
    const opt = document.createElement('option');
    opt.value = key;
    opt.textContent = (meta.name || key) + (meta.surgery ? (' — ' + meta.surgery) : '');
    sel.appendChild(opt);
  });
  if ([].slice.call(sel.options).some(function (o) { return o.value === cur; })) sel.value = cur;
}
function applyOTFollowupTemplate(key) {
  if (!activeOTCase) { showToast('Open an OT case first', 'w'); return; }
  activeOTCase.followupTemplateKey = key || '';
  fbUpdate && fbUpdate('otCases/' + activeOTCase.id, { followupTemplateKey: activeOTCase.followupTemplateKey }).catch(function () {});
  if (key) scheduleDefaultSurgeryFollowups(activeOTCase);
  showToast(key ? 'OT follow-up template linked ✓' : 'OT follow-up template cleared', 's');
}
function applyOTNotesTemplate(key) {
  if (!key || !RX_TEMPLATES_DATA[key]) return;
  const rows = RX_TEMPLATES_DATA[key] || [];
  const notesText = rows.map(function (row) {
    const bits = [];
    const name = rxDrugTradeName(row) || row.trade || row.name || row.generic || '';
    if (name) bits.push(name);
    if (row.freq) bits.push(row.freq);
    if (row.dur) bits.push(row.dur);
    return bits.join(' — ');
  }).filter(Boolean).join('\n');
  const noteArea = document.getElementById('ot-notes');
  const findings = document.getElementById('ot-findings');
  const narrative = document.getElementById('ot-narrative');
  const meta = RX_TEMPLATES_META[key] || {};
  if (findings && !findings.value.trim()) findings.value = meta.notes || '';
  if (narrative && !narrative.value.trim()) narrative.value = notesText;
  if (noteArea && !noteArea.value.trim()) noteArea.value = notesText;
  if (document.getElementById('ot-procedure') && !document.getElementById('ot-procedure').value.trim() && meta.surgery) document.getElementById('ot-procedure').value = meta.surgery;
  const followupKey = findMatchingOtFollowupTemplateKey(key, document.getElementById('ot-procedure')?.value || meta.surgery || '');
  const followupSel = document.getElementById('ot-followup-template');
  if (followupKey && followupSel) {
    followupSel.value = followupKey;
    applyOTFollowupTemplate(followupKey);
  }
  showToast('OT note template applied ✓', 's');
}

