// ─── REPORTS ─────────────────
function generateDailyReport() {
  const el=document.getElementById('rep-daily-result'); if(!el) return;
  const fromVal = document.getElementById('rep-from')?.value;
  const toVal   = document.getElementById('rep-to')?.value;
  const deptFilter = document.getElementById('rep-dept')?.value || '';
  const today = new Date().toISOString().split('T')[0];
  const rangeFrom = fromVal || today;
  const rangeTo   = toVal   || today;
  const todayLabel = new Date().toLocaleDateString('en-IN',{weekday:'long',day:'numeric',month:'long',year:'numeric'});

  const repCentreFilter = document.getElementById('rep-centre')?.value || '';
  const selectedCentre = repCentreFilter || normalizeAppointmentCentreValue((typeof getEffectiveCentre === 'function' ? getEffectiveCentre() : (CURRENT_USER?.centre || 'CHD')) || 'CHD');
  const allowAllCentres = !repCentreFilter && !!(CURRENT_USER?.isAdmin || CURRENT_USER?.canSeeAllCentres);
  const inRange = function (p) {
    const d = localDateKey(p.checkinAt || p.createdAt || p.registeredAt || p.updatedAt || p.queueDate || p.date);
    if (!d) return false;
    return d >= rangeFrom && d <= rangeTo;
  };
  const deptMap = {ophtho:'Ophthalmology',obg:'OBG',psych:'Neuropsychiatry',skin:'Skin'};
  const allPts = PATIENTS.filter(function (p) {
    if (deptFilter && p.dept !== deptFilter) return false;
    if (!allowAllCentres && normalizeAppointmentCentreValue(p.centre || selectedCentre) !== selectedCentre) return false;
    return true;
  });
  const dateFilteredPts = allPts.filter(inRange);

  // Compute totals from TRANSACTIONS array
  const txInRange = TRANSACTIONS.filter(tx=>{
    const d=(tx.date||'').split('T')[0]||today;
    if (d < rangeFrom || d > rangeTo) return false;
    if (!allowAllCentres && normalizeAppointmentCentreValue(tx.centre || selectedCentre) !== selectedCentre) return false;
    if (deptFilter && String(tx.dept || '') !== deptFilter) return false;
    return true;
  });
  const totalCollection = txInRange.reduce((s,t)=>s+getNetTransactionAmount(t),0);
  const pendingPay = PAY_REQUESTS.filter(function (pr) {
    if (pr.collected) return false;
    if (!allowAllCentres && normalizeAppointmentCentreValue(pr.centre || selectedCentre) !== selectedCentre) return false;
    if (deptFilter && String(pr.dept || '') !== deptFilter) return false;
    return true;
  }).reduce((s,pr)=>s+(parseFloat(pr.amount)||0),0);
  const surgeriesDone = OT_CASES.filter(function (c) {
    const d = localDateKey(c.date || c.otDate || c.surgeryDate || c.createdAt || c.updatedAt);
    if (!d || d < rangeFrom || d > rangeTo) return false;
    if (!allowAllCentres && normalizeAppointmentCentreValue(c.centre || selectedCentre) !== selectedCentre) return false;
    if (deptFilter && String(c.dept || '') !== deptFilter) return false;
    return String(c.status || '').toLowerCase() === 'completed';
  }).length;

  // Per-dept breakdown
  const depts = [['ophtho','Ophthalmology','👁️'],['obg','OBG','🤰'],['psych','Neuropsychiatry','🧠'],['skin','Skin','💆']];
  const deptRows = depts.map(([key,name,icon])=>{
    const pts = dateFilteredPts.filter(p=>p.dept===key);
    const deptTx = txInRange.filter(t=>t.dept===key);
    const consult = deptTx.filter(t=>normalizePaymentMode(t.mode)!=='Insurance/TPA').reduce((s,t)=>s+getNetTransactionAmount(t),0);
    const ins = deptTx.filter(t=>normalizePaymentMode(t.mode)==='Insurance/TPA').reduce((s,t)=>s+getNetTransactionAmount(t),0);
    return `<tr><td>${icon} ${name}</td><td>${pts.length}</td><td>₹${consult.toLocaleString('en-IN')}</td><td>₹0</td><td>₹${ins.toLocaleString('en-IN')}</td><td style="font-weight:900">₹${(consult+ins).toLocaleString('en-IN')}</td></tr>`;
  }).join('');
  const totalPts = depts.reduce((s,[k])=>s+dateFilteredPts.filter(p=>p.dept===k).length,0);

  const rangeLabel = fromVal||toVal ? `${new Date(rangeFrom).toLocaleDateString('en-IN',{day:'numeric',month:'short'})} – ${new Date(rangeTo).toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'})}` : todayLabel;

  el.innerHTML=`<div class="card">
    <div class="card-hd"><div><div class="card-title">📅 Daily Summary — ${rangeLabel}</div><div class="card-sub">${deptFilter ? (deptMap[deptFilter] || deptFilter) : 'All departments'} · ${allowAllCentres ? 'All visible centres' : (selectedCentre==='RPR'?'Ropar':'Chandigarh')} Centre</div></div>
    <button class="btn btn-gold btn-xs" onclick="window.print()">🖨️ Print</button></div>
    <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:14px">
      ${[
        ['Total OPD Patients', totalPts||dateFilteredPts.length, 'blue'],
        ['Total Collection', '₹'+totalCollection.toLocaleString('en-IN'), 'green'],
        ['Pending Payments', '₹'+pendingPay.toLocaleString('en-IN'), 'red'],
        ['Surgeries Done', surgeriesDone, 'orange']
      ].map(([l,v,c])=>`<div style="background:var(--${c}-lt,var(--g6));border-radius:10px;padding:12px;text-align:center"><div style="font-size:10px;color:var(--g1);font-weight:800;text-transform:uppercase">${l}</div><div style="font-size:22px;font-weight:900;color:var(--${c})">${v}</div></div>`).join('')}
    </div>
    <table><thead><tr><th>Department</th><th>Patients</th><th>Consultations ₹</th><th>Investigations ₹</th><th>Insurance ₹</th><th>Total ₹</th></tr></thead>
    <tbody>${deptRows}</tbody></table>
    <div style="display:flex;gap:8px;margin-top:12px;flex-wrap:wrap">
      ${depts.map(([k,d])=>`<button class="btn btn-outline btn-xs" onclick="showDeptDetail('${d}')">📋 ${d} Detail</button>`).join('')}
    </div>
    <div id="dept-detail-panel" style="margin-top:12px"></div>
  </div>`;
}

function showDeptDetail(dept) {
  const el=document.getElementById('dept-detail-panel'); if(!el) return;
  const deptPts = PATIENTS.filter(p=>{const m={Ophthalmology:'ophtho',OBG:'obg',Neuropsychiatry:'psych',Skin:'skin'}; return p.dept===m[dept];});
  el.innerHTML=`<div style="background:var(--g6);border-radius:var(--r);padding:14px">
    <div style="font-size:13px;font-weight:900;color:var(--bmh-blue);margin-bottom:10px">${dept} — Today's Detail</div>
    <table><thead><tr><th>#</th><th>Patient</th><th>BMSH ID</th><th>Doctor</th><th>Purpose</th><th>Amount ₹</th><th>Status</th></tr></thead>
    <tbody>${deptPts.map((p,i)=>`<tr><td>${i+1}</td><td>${p.name}</td><td style="font-family:var(--mono);font-size:10px">${p.bmhId}</td><td>${p.doctor}</td><td>${p.purpose}</td><td style="font-weight:800">₹800</td><td>${p.seen?'<span class="badge bd-green">Done</span>':'<span class="badge bd-orange">Pending</span>'}</td></tr>`).join('')}</tbody>
    </table></div>`;
}

function searchReportPatients(val) {
  const el=document.getElementById('rep-patient-result'); if(!el) return;
  if(!val||val.length<2){el.innerHTML='';return;}
  const matches=PATIENTS.filter(p=>p.name.toLowerCase().includes(val.toLowerCase())||p.bmhId.includes(val)||(p.mob&&p.mob.includes(val)));
  el.innerHTML=matches.length?`<div class="card">
    <div class="card-hd"><div class="card-title">Results (${matches.length})</div><button class="btn btn-gold btn-xs" onclick="window.print()">🖨️</button></div>
    <table><thead><tr><th>#</th><th>Name</th><th>BMSH ID</th><th>Age/Sex</th><th>Mobile</th><th>Doctor</th><th>Last Visit</th><th>Diagnosis</th></tr></thead>
    <tbody>${matches.map((p,i)=>`<tr onclick="openPatient('${p.bmhId}')"><td>${i+1}</td><td style="font-weight:800">${p.name}</td><td style="font-family:var(--mono);font-size:10px">${p.bmhId}</td><td>${p.age}Y/${p.sex[0]}</td><td>${p.mob||'—'}</td><td>${p.doctor}</td><td>${new Date().toLocaleDateString('en-IN')}</td><td><span class="badge bd-orange">Cataract OS</span></td></tr>`).join('')}
    </tbody></table></div>`:
  `<div style="padding:20px;text-align:center;color:var(--g1)">No patients found for "${val}"</div>`;
}

function generateSurgeryReport() {
  const proc=document.getElementById('rep-surg-name')?.value||'';
  const el=document.getElementById('rep-surgery-result'); if(!el) return;
  const filtered = getProcedureReportRows();
  const esc = function(v){ return String(v || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); };
  el.innerHTML=`<div class="card">
    <div class="card-hd"><div><div class="card-title">⚕️ ${proc||'All Procedures'} — ${filtered.length} patients</div></div><button class="btn btn-gold btn-xs" onclick="printSurgeryReportCurrent()">🖨️ Print</button></div>
    ${filtered.length?`<table><thead><tr><th>#</th><th>Patient</th><th>Phone</th><th>Age/Sex</th><th>BMSH ID</th><th>Procedure Advised</th><th>OT — Done As</th><th>Relevant Date</th><th>Doctor</th><th>Centre</th><th>Status</th><th>Counsellor</th></tr></thead>
    <tbody>${filtered.map((p,i)=>{ const follow=window.PROC_COUNSELLOR_LOG[p.key]||{}; const statusLabel=p.status==='done'?'Done':p.status==='scheduled'?'Scheduled':'Advised'; const otDoneCell = p.otProcedure ? `<div style="font-size:11px;font-weight:800;color:var(--green)">✅ ${esc(p.otProcedure)}</div>` : (p.status==='scheduled'?`<span style="font-size:10px;color:var(--blue)">Scheduled</span>`:'<span style="font-size:10px;color:var(--g1)">—</span>'); return `<tr><td>${i+1}</td><td style="font-weight:800">${esc(p.patient)}${p.referredBy?`<div style="font-size:10px;color:var(--g1);margin-top:2px">Ref: ${esc(p.referredBy)}</div>`:''}${p.advice?`<div style="font-size:10px;color:var(--g1);margin-top:4px;line-height:1.35"><b>Advice:</b> ${esc(p.advice)}</div>`:''}</td><td>${esc(p.mobile||'—')}</td><td>${esc(p.ageSex||'—')}</td><td style="font-family:var(--mono);font-size:10px">${esc(p.bmhId)}</td><td>${esc(p.proc)}</td><td>${otDoneCell}</td><td>${esc(p.date||'—')}</td><td>${esc(p.doctor)}</td><td>${esc(p.centre||'—')}</td><td><span class="badge ${p.status==='done'?'bd-green':p.status==='scheduled'?'bd-blue':'bd-orange'}">${esc(statusLabel)}</span></td><td><div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap"><button class="btn btn-xs btn-outline" onclick="openCounsellorFollowup('${p.key}')">📞 Follow-up</button>${follow.status?`<span style="font-size:10px;color:var(--g1)">${esc(follow.status)}${follow.nextDate?` · ${esc(follow.nextDate)}`:''}</span>`:''}</div></td></tr>`; }).join('')}
    </tbody></table>`:'<div style="padding:20px;text-align:center;color:var(--g1)">No records found</div>'}
  </div>`;
}

function openSurgeryReportWindow() {
  const rows = getProcedureReportRows();
  const proc = document.getElementById('rep-surg-name')?.value || 'Procedure Report';
  const w = window.open('', '_blank', 'width=1200,height=800');
  if (!w) { showToast('Popup blocked — allow popups to open report window', 'w'); return; }
  w.document.write(buildProcedureReportHtml(rows, proc || 'Procedure Report'));
  w.document.close();
}

function printSurgeryReportCurrent() {
  const rows = getProcedureReportRows();
  const proc = document.getElementById('rep-surg-name')?.value || 'Procedure Report';
  safePrint(buildProcedureReportHtml(rows, proc || 'Procedure Report'));
  showToast('Procedure report ready to print ✓', 's');
}

