// ─── RENDER RX DRUGS (Trade — Generic — route — dates — taper) ─────────────
function renderRxDrugs() {
  const activePage = document.querySelector('.page.active') || document.querySelector('.page');
  const el = activePage ? activePage.querySelector('#rx-drugs') : document.getElementById('rx-drugs');
  if(!el) return;
  if(!RX_DRUGS||!RX_DRUGS.length){
    el.innerHTML='<div style="padding:14px;text-align:center;color:var(--g1);font-size:12px">No drugs added — type above to search (Settings library + built-in list)</div>';
    return;
  }
  const activePageId = activePage?.id || '';
  const isOphtho = activePageId === 'pg-ophtho' || activePageId.includes('ophtho');
  const showRouteSite = isOphtho;
  const freqOpts=RX_FREQ_OPTIONS;
  const durOpts=RX_DURATION_OPTIONS;
  const typeOpts=RX_TYPE_OPTIONS;
  const eyeOpts=RX_SITE_OPTIONS;
  const mealOpts=RX_MEAL_TIMING_OPTIONS;
  const lang = typeof rxLang!=='undefined'?rxLang:'en';
  const rxAlerts = computeRxInteractionAlerts();
  const rowGridCols = showRouteSite
    ? 'minmax(180px,2.4fr) minmax(100px,1.05fr) minmax(120px,1.15fr) minmax(150px,1.35fr) minmax(110px,1.05fr) minmax(126px,1fr) minmax(126px,1fr) 92px'
    : 'minmax(220px,2.75fr) minmax(120px,1.1fr) minmax(170px,1.4fr) minmax(120px,1.05fr) minmax(126px,1fr) minmax(126px,1fr) 92px';

  RX_DRUGS.forEach((d,i)=>{
    if (!d.dateFrom) d.dateFrom = new Date().toISOString().split('T')[0];
    if (!d.drugType && d.type) d.drugType = d.type;
    if (!d.trade && d.brand) d.trade = d.brand;
    if (!d.brand && d.trade) d.brand = d.trade;
    if (!d.generic && d.name) d.generic = d.name;
    if (!d.name && d.generic) d.name = d.generic;
    const tn = String(d.trade || d.brand || '').trim();
    const gn = String(d.generic || d.name || '').trim();
    if (!tn && gn) { d.trade = gn; d.brand = gn; }
    ensureRxTaperRows(d);
    d.freq = normalizeRxFreqLabel(d.freq);
    d.dur = normalizeRxDurationLabel(d.dur);
    d.taperRows.forEach(tr => {
      tr.freq = normalizeRxFreqLabel(tr.freq);
      tr.dur = normalizeRxDurationLabel(tr.dur || d.dur);
    });
  });

  const esc = (s) => String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/"/g,'&quot;');
  const inputBase = 'width:100%;box-sizing:border-box;min-height:34px;font-size:12px;padding:6px 8px;border:1.5px solid #c7c7cc;border-radius:8px;background:#fff;color:#111';
  const nameInput = 'width:100%;box-sizing:border-box;min-height:34px;font-size:12.5px;padding:6px 8px;border:1.5px solid #1A3C6E;border-radius:8px;background:#fff;color:#1A3C6E;font-weight:800';
  const subInput = 'width:100%;box-sizing:border-box;min-height:28px;font-size:10.5px;padding:4px 8px;border:1.5px solid #d1d1d6;border-radius:8px;background:#fff;color:#6a6a6a;font-style:italic;margin-top:4px';
  const header = `<div style="display:grid;grid-template-columns:${rowGridCols};gap:8px;align-items:end;padding:8px 10px;background:#f2f5fb;border:1px solid #d6dce8;border-radius:10px 10px 0 0;font-size:9.5px;font-weight:900;color:#465066;text-transform:uppercase;letter-spacing:.45px">
    <div>Name</div><div>Type</div>${showRouteSite ? '<div>Eye</div>' : ''}<div>Frequency / Instructions</div><div>Duration</div><div>From</div><div>To</div><div>Actions</div>
  </div>`;
  const renderRow = (baseDrug, row, i, prefix, opts = {}) => {
    const isTaper = !!opts.isTaper;
    const rowFreq = row.freq || '';
    const rowDur = row.dur || baseDrug.dur || '';
    const line = buildRxPlainInstructionLine({
      ...baseDrug,
      ...(isTaper ? { trade:'', brand:'', generic:'', name:'' } : {}),
      drugType: row.drugType || row.type || baseDrug.drugType || baseDrug.type || 'Tablet',
      eye: row.eye || baseDrug.eye || ['Oral'],
      freq: rowFreq,
      dur: rowDur,
      dateFrom: row.dateFrom || '',
      dateTo: row.dateTo || ''
    }, lang, (iso)=> {
      if (!iso) return '—';
      const t = Date.parse(iso);
      return Number.isNaN(t) ? String(iso) : new Date(t).toLocaleDateString('en-IN',{day:'2-digit',month:'2-digit',year:'numeric'});
    });
    const tradeName = rxDrugTradeName(baseDrug) || '';
    const genericName = rxDrugGenericName(baseDrug) || '';
    const combinedName = genericName && genericName.toLowerCase() !== tradeName.toLowerCase()
      ? `${tradeName} (${genericName})`
      : tradeName;
    const taperBtn = `<button type="button" class="btn btn-xs" onclick="${opts.taperOnclick}" style="background:#fff7e8;color:#8a4200;border:1px solid rgba(212,160,23,.55);padding:5px 8px;font-size:10px;font-weight:800;width:100%">Taper</button>`;
    const removeBtn = `<button type="button" class="btn btn-xs btn-gray" onclick="${opts.removeOnclick}" style="padding:5px 8px;font-size:10px;font-weight:800;width:100%">✕</button>`;
    return `<div style="border-left:${isTaper ? '3px solid #ff9500' : '3px solid #1A3C6E'};border-right:1px solid #d6dce8;border-bottom:1px solid #d6dce8;border-left-width:${isTaper ? '3px' : '3px'};background:${isTaper ? '#fffaf2' : '#fff'}">
      <div style="display:grid;grid-template-columns:${rowGridCols};gap:8px;align-items:start;padding:8px 10px">
        <div>
          ${isTaper
            ? `<div style="min-height:34px;display:flex;align-items:center;padding:6px 8px;background:#fff;border:1.5px solid #1A3C6E;border-radius:8px;font-size:12px;font-weight:800;color:#1A3C6E">${esc(combinedName || 'Medicine')}</div><div style="min-height:28px;display:flex;align-items:center;padding:4px 8px;background:#fff4df;border:1px dashed rgba(212,160,23,.6);border-radius:8px;font-size:10.5px;font-weight:800;color:#8a4200;margin-top:4px">Taper step</div>`
            : `<input value="${esc(combinedName || '')}" onchange="const m=(this.value||'').match(/^(.*?)(?:\\s*\\((.*)\\))?\\s*$/);${prefix}.trade=(m&&m[1]?m[1].trim():this.value.trim());${prefix}.brand=${prefix}.trade;${prefix}.generic=(m&&m[2]?m[2].trim():'');${prefix}.name=${prefix}.generic;renderRxDrugs()" placeholder="Trade name (Generic)" style="${nameInput}"><div style="padding:4px 8px;font-size:10.5px;color:#6a6a6a;line-height:1.25">${genericName ? 'Edit as Trade name (Generic)' : 'Use brackets for generic if needed'}</div>`}
        </div>
        <div><select onchange="${prefix}.drugType=this.value;${prefix}.type=this.value;renderRxDrugs()" style="${inputBase}">${typeOpts.map(t=>`<option${(row.drugType || row.type || baseDrug.drugType || baseDrug.type || 'Tablet')===t?' selected':''}>${t}</option>`).join('')}</select></div>
        ${showRouteSite ? `<div><select onchange="${prefix}.eye=[this.value];renderRxDrugs()" style="${inputBase}">${eyeOpts.map(e=>`<option${(((row.eye && row.eye[0]) || (baseDrug.eye && baseDrug.eye[0]) || 'Oral')===e)?' selected':''}>${e}</option>`).join('')}</select></div>` : ''}
        <div>
          <select onchange="${prefix}.freq=this.value;window.syncRxDrugDates(${i})" style="${inputBase}">${freqOpts.map(f=>`<option${rowFreq===f?' selected':''}>${f}</option>`).join('')}</select>
          <select onchange="${prefix}.mealTiming=this.value;renderRxDrugs()" style="${subInput}">
            <option value="">Meal / intake note</option>
            ${mealOpts.filter(Boolean).map(opt=>`<option value="${esc(opt)}"${String(row.mealTiming || baseDrug.mealTiming || '')===opt?' selected':''}>${opt}</option>`).join('')}
          </select>
        </div>
        <div><select onchange="${prefix}.dur=this.value;window.syncRxDrugDates(${i})" style="${inputBase}">${durOpts.map(v=>`<option${rowDur===v?' selected':''}>${v}</option>`).join('')}</select></div>
        <div><input type="date" value="${esc(row.dateFrom || '')}" onchange="${prefix}.dateFrom=this.value;window.syncRxDrugDates(${i})" style="${inputBase}"></div>
        <div><input type="date" value="${esc(row.dateTo || '')}" onchange="${prefix}.dateTo=this.value;renderRxDrugs()" style="${inputBase}"></div>
        <div style="display:flex;flex-direction:column;gap:6px">${taperBtn}${removeBtn}</div>
      </div>
    </div>`;
  };
  el.innerHTML = `<div class="rx-drugs-root" style="display:flex;flex-direction:column;gap:12px;width:100%;max-width:100%;min-width:0;box-sizing:border-box">
    ${rxAlerts.length ? `<div style="border:1.5px solid rgba(204,0,0,.25);background:#fff4f4;border-radius:10px;padding:10px 12px"><div style="font-size:11px;font-weight:900;color:#b42318;text-transform:uppercase;letter-spacing:.4px;margin-bottom:6px">Drug interaction / history alerts</div>${rxAlerts.map(function (a) { return `<div style="font-size:11.5px;line-height:1.5;color:#7a1f1f;margin-bottom:4px">• ${esc(a)}</div>`; }).join('')}</div>` : ''}
    ${RX_DRUGS.map((d,i)=>{
      const taperRows = ensureRxTaperRows(d);
      const mainPrefix = `RX_DRUGS[${i}]`;
      return `<div style="border-radius:10px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,.05)">
        ${header}
        ${renderRow(d, d, i, mainPrefix, {
          taperOnclick:`window.addTaperRow(${i})`,
          removeOnclick:`window.removeDrug(${i})`
        })}
        ${taperRows.map((tap, tapIdx) => renderRow(d, tap, i, `RX_DRUGS[${i}].taperRows[${tapIdx}]`, {
          isTaper:true,
          taperOnclick:`window.addTaperRow(${i},null,${tapIdx})`,
          removeOnclick:`window.clearTaperRow(${i},${tapIdx})`
        })).join('')}
      </div>`;
    }).join('')}
  </div>`;
  scheduleActiveClinicRxAutosave();
}
function computeRxInteractionAlerts() {
  const alerts = [];
  const text = RX_DRUGS.map(function (d) {
    return [d.trade, d.brand, d.generic, d.name].join(' ').toLowerCase();
  }).join(' || ');
  const has = function (re) { return re.test(text); };
  const phxVal = function (id) { return document.getElementById(id)?.value || window.CURRENT_PATIENT?.lastVisit?.[id] || 'N'; };
  const extraHx = String(document.getElementById('hx-other-systemic')?.value || window.CURRENT_PATIENT?.lastVisit?.otherSystemic || '').toLowerCase();
  const allergySpec = String(document.getElementById('drug-allergy-spec')?.value || window.CURRENT_PATIENT?.lastVisit?.drugAllergySpec || '').toLowerCase();
  if (has(/\btimolol\b|\bcosopt\b/) && (phxVal('phx-asthma___copd') === 'Y' || /asthma|copd|bronch/.test(extraHx))) {
    alerts.push('Timolol / Cosopt may worsen asthma or COPD.');
  }
  if (has(/\btimolol\b|\bcosopt\b/) && (phxVal('phx-heart_disease__') === 'Y' || /heart|block|brady/.test(extraHx))) {
    alerts.push('Timolol-containing drops may aggravate bradycardia or heart disease.');
  }
  if (has(/\bdiamox\b|\bacetazolamide\b/) && (phxVal('phx-renal_disease') === 'Y' || /renal|kidney/.test(extraHx))) {
    alerts.push('Acetazolamide / Diamox needs caution in renal disease.');
  }
  if (has(/\bdiamox\b|\bacetazolamide\b/) && /sulfa|sulfonamide/.test(allergySpec)) {
    alerts.push('Acetazolamide / Diamox may cross-react with sulfonamide allergy.');
  }
  if (has(/\bpred\b|\bpred forte\b|\bdexameth|\blotepred|\bsteroid/) && phxVal('phx-diabetes_mellit') === 'Y') {
    alerts.push('Steroid therapy may raise sugars; monitor diabetes control.');
  }
  if (has(/\bketorolac\b|\bbromfenac\b|\bnepafenac\b|\bacular\b|\byellox\b/) && (/nsaid|aspirin/.test(allergySpec) || String(document.getElementById('drug-allergy')?.value || '').toLowerCase().includes('nsaid'))) {
    alerts.push('Topical NSAID use needs caution with NSAID / aspirin allergy history.');
  }
  if (has(/\bbrimonidine\b|\balphagan\b/) && /clonidine/.test(extraHx)) {
    alerts.push('Brimonidine with clonidine-like therapy may increase systemic side effects.');
  }
  const seen = new Set();
  RX_DRUGS.forEach(function (d) {
    const key = String(rxDrugTradeName(d) || d.trade || d.name || d.generic || '').trim().toLowerCase();
    if (!key) return;
    if (seen.has(key)) alerts.push((d.trade || d.name || d.generic || 'Drug') + ' appears more than once in the prescription.');
    seen.add(key);
  });
  return Array.from(new Set(alerts));
}

// ─── TEMPLATE SAVE ─────────────
function openSaveRxTemplate() {
  const deptInp = document.getElementById('tpl-dept-inp');
  if (deptInp) deptInp.value = normalizeRxTemplateDeptKey(rxDeptKeyFromUi());
  const preview = document.getElementById('tpl-preview-drugs');
  if(preview) preview.innerHTML = RX_DRUGS.length
    ? RX_DRUGS.map((d,i)=>{
      const taperRows = ensureRxTaperRows(d);
      return `<div style="padding:5px 0;border-bottom:1px solid var(--g5);font-size:11.5px"><strong>${i+1}. ${rxDrugTradeName(d)||d.name}</strong> <em style="color:var(--g1);font-size:10px">${rxDrugGenericName(d)&&rxDrugGenericName(d)!==rxDrugTradeName(d)?'('+rxDrugGenericName(d)+')':''}</em> — ${d.freq} — ${d.dur}${taperRows.length?taperRows.map((tr,idx)=>`<div style="font-size:10px;color:var(--orange);margin-top:3px">Taper ${idx+1}: ${tr.freq} · ${tr.dur}</div>`).join(''):''}</div>`;
    }).join('')
    : '<span style="color:var(--g1)">No drugs in prescription</span>';
  openM('m-save-rx-tpl');
}
function saveRxAsTemplate() {
  const name = toDisplayTitleCase(document.getElementById('tpl-name-inp')?.value?.trim()); if(!name){showToast('Enter template name','w');return;}
  if(!RX_DRUGS.length){showToast('No drugs to save','w');return;}
  const dept = normalizeRxTemplateDeptKey(document.getElementById('tpl-dept-inp')?.value || 'all');
  const notes = document.getElementById('tpl-notes-inp')?.value?.trim() || '';
  const key = name.toLowerCase().replace(/\s+/g,'-');
  if(typeof RX_TEMPLATES_DATA!=='undefined') RX_TEMPLATES_DATA[key] = RX_DRUGS.map(d=>{
    const eyeVal = Array.isArray(d.eye) ? d.eye[0] : d.eye;
    const taperRows = ensureRxTaperRows(d);
    return {
      trade:d.trade||d.brand||d.name,
      generic:d.generic||d.name||'',
      type:d.drugType||d.type||'Tablet',
      eye:eyeVal,
      freq:d.freq,
      dur:d.dur,
      taperRows:taperRows.length ? taperRows.map(tr => ({...tr})) : []
    };
  });
  if (typeof RX_TEMPLATES_META !== 'undefined') RX_TEMPLATES_META[key] = { dept, name, notes };
  saveRxTemplatesToStorage();
  refreshRxTemplateSelects();
  if (typeof renderSetRxTplList === 'function') renderSetRxTplList();
  document.querySelectorAll('[onchange*="applyRxTemplate"],#rx-tpl-sel').forEach(sel=>{
    if(![...sel.options].find(o=>o.value===key)){
      const opt=document.createElement('option'); opt.value=key; opt.textContent=name; sel.appendChild(opt);
    }
  });
  showToast('📋 Template "'+name+'" saved ✓','s');
  closeM('m-save-rx-tpl');
  const ni=document.getElementById('tpl-name-inp'); if(ni)ni.value='';
  const nn=document.getElementById('tpl-notes-inp'); if(nn)nn.value='';
}

// ─── PROFESSIONAL LAB REPORT PRINT ─────────────
function printLabReport() {
  const sel = document.getElementById('lab-pt-sel');
  const order = (sel && sel.value ? LAB_ORDERS.find(function (o) { return o.id === sel.value; }) : null) || activeLabOrder || LAB_ORDERS[0];
  if (!order) { showToast('No lab report selected', 'w'); return; }
  const pt = PATIENTS.find(function (x) { return x.bmhId === order.bmhId; }) || {};
  const groups = { haem:'Haematology', coag:'Coagulogram', chem:'Clinical Chemistry', rft:'Renal Function Test', lft:'Liver Function Test', lipid:'Lipid Profile', electro:'Serum Electrolytes', sero:'Serology', urine:'Urine Examination', stool:'Stool Examination', hcg:'Pregnancy Test', semen:'Semen Analysis', rafq:'RA Factor', thyroid:'Thyroid Function', bio:'Biochemistry', diab:'Diabetes', custom:'Additional Tests' };
  const grouped = {};
  Object.keys(groups).forEach(function (g) { grouped[g] = []; });
  order.tests.forEach(function (name) {
    const row = Object.assign({}, getLabTestMeta(name), order.results[normalizeLabTestName(name)] || {});
    const g = row.group || 'custom';
    if (!grouped[g]) grouped[g] = [];
    grouped[g].push(row);
  });
  // merge legacy bio/diab into chem for printing (avoid duplicate sections)
  if (grouped.bio && grouped.bio.length) grouped.chem = (grouped.chem || []).concat(grouped.bio);
  if (grouped.diab && grouped.diab.length) grouped.chem = (grouped.chem || []).concat(grouped.diab);
  if (grouped.bio) grouped.bio = [];
  if (grouped.diab) grouped.diab = [];
  const insights = buildLabInsights(order);
  const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><style>*{margin:0;padding:0;box-sizing:border-box;print-color-adjust:economy;-webkit-print-color-adjust:economy}body{font-family:Arial,sans-serif;font-size:10.8px;color:#111;padding:0 12mm 12mm;background:#fff}@page{size:A4 portrait;margin:40mm 12mm 12mm}.pt-bar{display:grid;grid-template-columns:repeat(3,1fr);gap:8px;border:1px solid #9ca3af;border-radius:8px;padding:8px 10px;margin-bottom:10px;background:#fff}.pt-lbl{font-size:8.5px;color:#555;font-weight:700;text-transform:uppercase;letter-spacing:.3px}.lab-group-blurb{margin:10px 0 0;padding:6px 8px;font-size:9.5px;color:#555;line-height:1.45;background:#f9fafb;border-radius:6px;border:1px solid #e5e7eb}.section-hd{font-size:10.8px;font-weight:900;color:#111;text-transform:uppercase;letter-spacing:.5px;margin:11px 0 0;padding:6px 8px;background:#ececec;border-left:4px solid #666}.insights{margin:10px 0;padding:8px 10px;border:1px solid #bdbdbd;border-radius:8px;background:#f7f7f7;font-size:10.3px;line-height:1.52}table{width:100%;border-collapse:collapse;margin-top:8px}thead th{background:#666;color:#fff;padding:6px 8px;text-align:left;font-size:9px;font-weight:800;text-transform:uppercase}td{padding:6px 8px;border:1px solid #d7d7d7;font-size:10.1px;vertical-align:top}tr:nth-child(even){background:#fafafa}.flag-h{color:#111;font-weight:900;background:#e7e7e7}.flag-l{color:#111;font-weight:900;background:#f1f1f1}.flag-n{color:#111;font-weight:800}.footer{margin-top:14px;padding-top:8px;border-top:1px solid #c7c7c7}.signs{display:grid;grid-template-columns:1fr 1fr;gap:28px;margin-top:18px}.signline{border-bottom:1px solid #333;height:28px;margin-bottom:4px}.small{font-size:9px;color:#555}</style></head><body>
<div class="pt-bar">
  <div><div class="pt-lbl">Patient</div><div style="font-weight:900">${escapeHtmlConsent(order.patient || pt.name || '—')}</div></div>
  <div><div class="pt-lbl">BMSH ID</div><div style="font-family:monospace;color:#222;font-weight:700">${escapeHtmlConsent(order.bmhId || pt.bmhId || '—')}</div></div>
  <div><div class="pt-lbl">Age/Sex</div><div style="font-weight:700">${escapeHtmlConsent(formatLabAgeSex(pt))}</div></div>
  <div><div class="pt-lbl">Ref. Doctor</div><div style="font-weight:700">${escapeHtmlConsent(order.dr || pt.assignedDoctor || pt.doctor || '—')}</div></div>
  <div><div class="pt-lbl">Report Date</div><div style="font-weight:700">${escapeHtmlConsent(formatDateIN(order.completedAt || order.date || new Date()))}</div></div>
  <div><div class="pt-lbl">Lab Technician</div><div style="font-weight:700">${escapeHtmlConsent(order.tech || '—')}</div></div>
</div>
${insights.length ? `<div class="insights"><div style="font-weight:900;margin-bottom:4px;color:#333">Interpretive notes</div>${insights.map(function (x) { return '<div>• ' + escapeHtmlConsent(x) + '</div>'; }).join('')}${order.comments ? '<div style="margin-top:6px"><b>Lab comment:</b> ' + escapeHtmlConsent(order.comments) + '</div>' : ''}</div>` : (order.comments ? `<div class="insights"><div style="font-weight:900;margin-bottom:4px;color:#333">Lab comment</div>${escapeHtmlConsent(order.comments)}</div>` : '')}
${Object.keys(groups).map(function (key) {
  if (key === 'bio' || key === 'diab') return '';
  const rows = grouped[key] || [];
  if (!rows.length) return '';
  const blurb = LAB_GROUP_HEAD_BLURBS[key] || '';
  return (blurb ? '<div class="lab-group-blurb">' + escapeHtmlConsent(blurb) + '</div>' : '') + '<div class="section-hd">' + groups[key] + '</div><table><thead><tr><th>Test</th><th>Value</th><th>Unit</th><th>Normal Range</th><th>Flag</th></tr></thead><tbody>' + rows.map(function (row) {
    const flag = String(row.flag || '—');
    const cls = flag === 'HIGH' ? 'flag-h' : flag === 'LOW' ? 'flag-l' : 'flag-n';
    const pblur = String(row.patientBlurb || getLabPatientBlurbForName(row.name) || '').trim();
    const abn = flag === 'HIGH' || flag === 'LOW' ? String(row.abnormalNote || '').trim() : '';
    const subParts = [pblur, abn].filter(Boolean);
    const sub = subParts.length ? '<div style="margin-top:3px;font-size:9px;color:#6b7280;line-height:1.35">' + escapeHtmlConsent(subParts.join(' — ')) + '</div>' : '';
    return '<tr><td style="font-weight:700">' + escapeHtmlConsent(row.name || '') + sub + '</td><td class="' + cls + '">' + escapeHtmlConsent(row.val || '—') + '</td><td>' + escapeHtmlConsent(row.unit || '') + '</td><td>' + escapeHtmlConsent(row.range || '') + '</td><td class="' + cls + '">' + escapeHtmlConsent(flag || '—') + '</td></tr>';
  }).join('') + '</tbody></table>';
}).join('')}
<div class="signs">
  <div><div class="signline"></div><div class="small">Lab Technician Signature</div></div>
  <div><div class="signline"></div><div class="small">Authorised Signatory</div></div>
</div>
<div class="footer"><div class="small" style="text-align:center">This outsourced laboratory report is computer generated. Reference intervals and interpretation may vary by method, age, sex, and clinical context.</div></div>
</body></html>`;
  safePrint(html);
  showToast('Lab report sent to printer ✓','s');
}

