function toggleLgPw() {
  const p = document.getElementById('lg-pass');
  p.type = p.type === 'password' ? 'text' : 'password';
}



function loginUser() {
  try {
    var user = ((document.getElementById('lg-email') || document.getElementById('lg-user')) ? (document.getElementById('lg-email') || document.getElementById('lg-user')).value : '').trim().toLowerCase();
    var pass = (document.getElementById('lg-pass') ? document.getElementById('lg-pass').value : '');
    var userCandidates = getLoginUserCandidates(user);
    var forcedUrgent = getForcedUrgentLoginProfile(user, pass);
    
    if (!user || !pass) {
      showLoginErr('Please enter username and password');
      return;
    }
    if (forcedUrgent) {
      activateUserSession(forcedUrgent.username, forcedUrgent.profile, { showToastOnSuccess: true, auditLogin: true });
      return;
    }
    
    var matchedUser = userCandidates.find(function (candidate) {
      return USER_DB && USER_DB[candidate] && isAcceptedLoginPassword(candidate, USER_DB[candidate], pass);
    }) || user;
    var profile = USER_DB ? USER_DB[matchedUser] : null;
    if (!profile || !isAcceptedLoginPassword(matchedUser, profile, pass)) {
      if (window.FBDB) {
        window.FBDB.ref('userSettings').once('value').then(function(snap) {
          const settings = snap.val() || {};
          const found = findUserSettingsCandidate(userCandidates, settings);
          if(!found || !found.profile) {
            showLoginErr('Incorrect username or password');
            var pi = document.getElementById('lg-pass');
            if (pi) pi.value = '';
            return;
          }
          matchedUser = found.username;
          USER_DB[matchedUser] = Object.assign({}, USER_DB[matchedUser] || {}, found.profile);
          if (!isAcceptedLoginPassword(matchedUser, USER_DB[matchedUser], pass)) {
            showLoginErr('Incorrect username or password');
            var pi2 = document.getElementById('lg-pass');
            if (pi2) pi2.value = '';
            return;
          }
          activateUserSession(matchedUser, USER_DB[matchedUser], { showToastOnSuccess: true, auditLogin: true });
        }).catch(function() {
          showLoginErr('Incorrect username or password');
          var pi3 = document.getElementById('lg-pass');
          if (pi3) pi3.value = '';
        });
        return;
      }
      showLoginErr('Incorrect username or password');
      var pi = document.getElementById('lg-pass');
      if (pi) pi.value = '';
      return;
    }

    // Block disabled accounts
    if (profile.disabled === true) {
      showLoginErr('This account has been disabled. Please contact the administrator.');
      var pi2 = document.getElementById('lg-pass');
      if (pi2) pi2.value = '';
      return;
    }
    try {
      var rem = document.getElementById('lg-remember');
      if (rem && rem.checked) {
        localStorage.setItem('bmh_creds', JSON.stringify({u: matchedUser, p: pass}));
      } else {
        localStorage.removeItem('bmh_creds');
      }
    } catch(storErr) {}

    activateUserSession(matchedUser, profile, { showToastOnSuccess: true, auditLogin: true });


  } catch(loginErr) {
    console.error('Login error:', loginErr);
    showLoginErr('Login error: ' + loginErr.message + '. Please refresh and try again.');
  }
}

function activateUserSession(user, profile, opts) {
  opts = opts || {};
  function deferBootstrap(fn, delay) {
    const runner = function(){ try { fn(); } catch (e) { console.warn('Deferred bootstrap error:', e); } };
    if (typeof window !== 'undefined' && typeof window.requestIdleCallback === 'function') {
      window.requestIdleCallback(runner, { timeout: Math.max(300, delay || 800) });
      return;
    }
    setTimeout(runner, delay || 0);
  }
  const uname = String(user || '').toLowerCase();
  if (uname === 'rec_rpr' || uname === 'reception.rpr' || uname === 'reception.rpr@bawejahospital.com') profile = Object.assign({}, profile, { centre: 'RPR', name: 'Reception Ropar' });
  if (uname === 'rec_chd' || uname === 'reception.chd' || uname === 'reception.chd@bawejahospital.com') profile = Object.assign({}, profile, { centre: 'CHD', name: 'Reception CHD' });
  if (uname === 'optometrist' || uname === 'opto_rpr' || uname === 'opto.rpr' || uname === 'opto,rpr' || uname === 'optometrist@bawejahospital.com' || uname === 'opto.rpr@bawejahospital.com') profile = Object.assign({}, profile, { centre: 'RPR', name: 'Optometrist RPR' });
  if (uname === 'drtarun' || uname === 'drtarun.rpr' || uname === 'drtarun@bawejahospital.com' || uname === 'drtarun.rpr@bawejahospital.com') profile = Object.assign({}, profile, { centre: 'RPR', name: 'Dr. Tarun Baweja', dept: 'Neuropsychiatry' });
  if (uname === 'drnamrata' || uname === 'drnamrata.rpr' || uname === 'drnamrata@bawejahospital.com' || uname === 'drnamrata.rpr@bawejahospital.com') profile = Object.assign({}, profile, { centre: 'RPR', name: 'Dr. Namrata Baweja', dept: 'OBG' });
  if (uname === 'drpooja' || uname === 'drpooja.rpr' || uname === 'drpooja@bawejahospital.com' || uname === 'drpooja.rpr@bawejahospital.com') profile = Object.assign({}, profile, { centre: 'RPR', name: 'Dr. Pooja Baweja', dept: 'Skin' });
  if (uname === 'lab.chd@bawejahospital.com') profile = Object.assign({}, profile, { centre: 'CHD', name: 'Lab Tech CHD' });
  if (uname === 'lab.rpr@bawejahospital.com') profile = Object.assign({}, profile, { centre: 'RPR', name: 'Lab Tech Ropar' });
  if (uname === 'tpa.chd@bawejahospital.com') profile = Object.assign({}, profile, { centre: 'CHD', name: 'TPA Executive CHD' });
  if (uname === 'tpa.rpr@bawejahospital.com') profile = Object.assign({}, profile, { centre: 'RPR', name: 'TPA Executive RPR' });
  if (uname === 'inventory.chd@bawejahospital.com') profile = Object.assign({}, profile, { centre: 'CHD', name: 'Inventory CHD' });
  if (uname === 'inventory.rpr@bawejahospital.com') profile = Object.assign({}, profile, { centre: 'RPR', name: 'Inventory RPR' });
  CURRENT_USER = Object.assign({}, profile, {username: user});
  window.CURRENT_USER = CURRENT_USER;
  try { sessionStorage.setItem('bmh_active_session', JSON.stringify({ u: user })); } catch (e) {}

  var gate = document.getElementById('login-gate');
  if (gate) gate.style.display = 'none';
  var shell = document.getElementById('shell');
  if (shell) shell.style.display = 'flex';

  var cSel = document.getElementById('c-sel-row');
  var preferredCentre = profile.centre;
  if (profile.isAdmin || profile.canSeeAllCentres || profile.centre === 'BOTH') {
    try { preferredCentre = localStorage.getItem('bmh_admin_centre_pref') || 'RPR'; } catch (e) { preferredCentre = 'RPR'; }
  }
  preferredCentre = normalizeAppointmentCentreValue(preferredCentre || 'CHD');
  if(preferredCentre === 'CHD' || preferredCentre === 'RPR') {
    var cLabel = preferredCentre === 'CHD' ? 'Chandigarh' : 'Ropar';
    var tbCp = document.getElementById('tb-cp');
    if(tbCp) tbCp.textContent = '📍 ' + cLabel;
    var rcCentre = document.getElementById('rc-centre');
    if (rcCentre) rcCentre.value = preferredCentre;
    document.querySelectorAll('.c-btn').forEach(function(b){ b.classList.remove('active'); b.style.opacity = profile.isAdmin ? '1' : '0.5'; b.style.pointerEvents = profile.isAdmin ? '' : 'none'; });
    var activeBtn = document.querySelector('.c-btn[data-centre="' + preferredCentre + '"]');
    if(activeBtn) { activeBtn.classList.add('active'); activeBtn.style.opacity='1'; }
    if(cSel && !profile.isAdmin) cSel.style.opacity = '0.6';
  } else {
    if(cSel) cSel.style.opacity = '1';
    document.querySelectorAll('.c-btn').forEach(function(b){ b.style.opacity='1'; b.style.pointerEvents=''; });
  }

  var sbnm = document.getElementById('sbnm'); if (sbnm) sbnm.textContent = profile.name;
  var cDisp = profile.centre === 'BOTH' ? 'Admin' : profile.centre;
  var sbrl = document.getElementById('sbrl'); if (sbrl) sbrl.textContent = profile.role + ' · ' + cDisp;
  var sbav = document.getElementById('sbav');
  if (sbav) sbav.textContent = profile.name.replace('Dr. ','').split(' ').map(function(n){return n[0]||'';}).join('').substring(0,2).toUpperCase();

  if (typeof buildSidebarForRole === 'function') buildSidebarForRole(profile.role, profile.dept, profile.name);

  var pageMap = { Admin:'dashboard', Doctor:'doctor-queue', Reception:'reception', Lab:'lab', TPA:'tpa', Inventory:'inventory', Optometrist:'doctor-queue' };
  var firstPage = pageMap[profile.role] || 'dashboard';
  if (typeof tryScheduleRouteRestoreFromHash === 'function') {
    tryScheduleRouteRestoreFromHash(function () { if (typeof nav === 'function') nav(firstPage, null); });
  } else if (typeof nav === 'function') {
    nav(firstPage, null);
  }

  setTimeout(function() {
    try {
      if (typeof loadPatientsFromFirebase === 'function')  loadPatientsFromFirebase();
      deferBootstrap(function() {
        if (typeof loadBmhFinancials === 'function') loadBmhFinancials();
      }, 180);
      deferBootstrap(function() {
        var hotRoles = ['Admin', 'Reception', 'TPA'];
        if (hotRoles.indexOf(String(profile.role || '')) !== -1) {
          if (typeof listenPayRequests === 'function') listenPayRequests();
        }
      }, 320);
      deferBootstrap(function() {
        var hotRoles = ['Admin', 'Reception', 'TPA'];
        if (hotRoles.indexOf(String(profile.role || '')) !== -1) {
          if (typeof loadTodayTransactions === 'function') loadTodayTransactions();
        }
      }, 650);
      deferBootstrap(function() {
        var hotRoles = ['Admin', 'Reception', 'TPA'];
        if (hotRoles.indexOf(String(profile.role || '')) !== -1) {
          if (typeof listenAppointments === 'function') listenAppointments();
        }
      }, 900);
      deferBootstrap(function() {
        if (typeof listenDeletionRequestsForApprover === 'function') listenDeletionRequestsForApprover();
        if (profile.role === 'Lab' && typeof listenLabOrders === 'function') listenLabOrders();
      }, 1250);
      deferBootstrap(function() {
        if (!window.FBDB) return;
        window.FBDB.ref('userSettings').once('value').then(function(snap) {
          const settings = snap.val();
          if(!settings) return;
          Object.entries(settings).forEach(function([uname, data]) {
            if(!USER_DB[uname] && data.name && data.role) {
              USER_DB[uname] = { pw: data.pw||'', name: data.name, role: data.role||'Reception', dept: data.dept||'', centre: data.centre||'CHD', degrees: data.degrees||'', canSeeAllCentres: !!data.canSeeAllCentres, isAdmin: !!data.isAdmin, disabled: !!data.disabled };
            } else if(USER_DB[uname]) {
              if(data.pw) USER_DB[uname].pw = data.pw;
              if(data.disabled !== undefined) USER_DB[uname].disabled = data.disabled;
            }
          });
        }).catch(function(e){ console.warn('userSettings load error:', e); });
      }, 1600);
      if (opts.auditLogin && typeof fbPush === 'function') {
        fbPush('auditLog', { user: profile.name, role: profile.role, centre: profile.centre, action: 'LOGIN', timestamp: new Date().toISOString() });
      }
    } catch(fbErr) { console.warn('Firebase listener error:', fbErr); }
  }, 250);

  if (opts.showToastOnSuccess && typeof showToast === 'function') showToast('Welcome, ' + profile.name + ' ✓', 's');
}
function preloadUserSettings() {
  if(!window.FBDB) return;
  window.FBDB.ref('userSettings').once('value').then(function(snap) {
    const settings = snap.val();
    if(!settings) return;
    Object.entries(settings).forEach(function([uname, data]) {
      USER_DB[uname] = Object.assign({}, USER_DB[uname] || {}, data);
    });
    if (CURRENT_USER?.isAdmin) renderAdminUsersList && renderAdminUsersList();
  }).catch(function(e){ console.warn('user preload error:', e); });
}

