CRITICAL_CHARGE_ROWS.push.apply(CRITICAL_CHARGE_ROWS, DEFAULT_ZERO_CHARGE_LAB_ROWS);
function upsertCriticalChargeRow(row) {
  const idx = CHARGES_DATA.findIndex(function (existing) {
    return String(existing.cat || '') === String(row.cat || '')
      && String(existing.parent || '') === String(row.parent || '')
      && String(existing.name || '').toLowerCase() === String(row.name || '').toLowerCase();
  });
  if (idx < 0) {
    // Only add on initial boot before any cloud/saved data has been applied.
    // If cloud data is loaded and the item is missing, the user deleted it — keep it deleted.
    if (!window._bmhChargesCloudLoaded) {
      const next = { cat: row.cat || '', kind: row.kind || row.cat || 'procedure', parent: row.parent || '', name: row.name || '', chd: Number(row.chd || 0), rpr: Number(row.rpr || 0) };
      CHARGES_DATA.push(next);
      if (next.name) { CENTRE_CHARGES.CHD[next.name] = next.chd; CENTRE_CHARGES.RPR[next.name] = next.rpr; }
    }
    return;
  }
  // Item exists — sync CENTRE_CHARGES from the user's saved prices, never overwrite them with hardcoded defaults
  const existing = CHARGES_DATA[idx];
  if (existing.name) {
    CENTRE_CHARGES.CHD[existing.name] = existing.chd;
    CENTRE_CHARGES.RPR[existing.name] = existing.rpr;
  }
}
function ensureCriticalChargesLoaded() {
  // Do NOT hardcode CENTRE_CHARGES prices here — they come from user-saved CHARGES_DATA via upsertCriticalChargeRow.
  // Hardcoding them here would overwrite prices the user has changed and saved.
  CRITICAL_CHARGE_ROWS.forEach(upsertCriticalChargeRow);
  migrateLegacyPmicsChargeParents();
}
ensureCriticalChargesLoaded();
function getChargeMainHeadings() {
  return Array.from(new Set((CHARGES_DATA || []).map(function (row) {
    return String(row.parent || '').trim();
  }).filter(Boolean))).sort();
}
function getChargeNamesForCategory(cat) {
  return Array.from(new Set((CHARGES_DATA || []).filter(function (row) {
    return !cat || row.cat === cat;
  }).map(function (row) {
    return String(row.name || '').trim();
  }).filter(Boolean))).sort();
}
function refreshChargeModalSuggestions() {
  const parentList = document.getElementById('charge-parent-list');
  const nameList = document.getElementById('charge-name-list');
  const cat = document.getElementById('add-charge-cat')?.value || '';
  if (parentList) {
    parentList.innerHTML = getChargeMainHeadings().map(function (name) {
      return '<option value="' + String(name).replace(/"/g, '&quot;') + '"></option>';
    }).join('');
  }
  if (nameList) {
    nameList.innerHTML = getChargeNamesForCategory(cat).map(function (name) {
      return '<option value="' + String(name).replace(/"/g, '&quot;') + '"></option>';
    }).join('');
  }
}
function canEditChargeCategory(cat) {
  if (isCurrentUserAdmin()) return true;
  const dept = String(CURRENT_USER?.dept || '').toLowerCase();
  const c = String(cat || '').toLowerCase();
  if (dept.includes('oph') && c.includes('eye')) return true;
  if ((dept.includes('obg') || dept.includes('gyn')) && c.includes('obg')) return true;
  if (dept.includes('psych') && c.includes('psych')) return true;
  if ((dept.includes('skin') || dept.includes('derm') || dept.includes('cosmet')) && c.includes('skin')) return true;
  return false;
}

function renderChargesList() {
  const el = document.getElementById('set-procs-list') || document.getElementById('charges-list');
  if(!el) return;
  const cats = [...new Set(CHARGES_DATA.map(c=>c.cat))];
  el.innerHTML = `<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:12px;align-items:center">
    <button type="button" class="btn btn-gold btn-sm" onclick="openAddChargeModal()">+ Add Procedure</button>
    <button type="button" class="btn btn-outline btn-sm" onclick="saveCharges()">💾 Save &amp; sync to cloud</button>
    <span style="font-size:11px;color:var(--g1)">Doctors can edit charges for their own departments. Use main heading + subcategory for grouped surgery packages.</span>
  </div>` + cats.map(cat => {
    const rows = CHARGES_DATA.filter(c=>c.cat===cat);
    const editable = canEditChargeCategory(cat);
    const groups = {};
    rows.forEach(function (row) {
      const key = row.parent || '__root__';
      if (!groups[key]) groups[key] = [];
      groups[key].push(row);
    });
    return `<div style="margin-bottom:8px">
      <div style="font-size:9.5px;font-weight:800;color:var(--bmh-blue);text-transform:uppercase;letter-spacing:.5px;padding:4px 8px;background:var(--g6);border-radius:5px;margin-bottom:4px">${cat}</div>
      ${Object.keys(groups).map(function (parentKey) {
        const childRows = groups[parentKey];
        const parentRow = parentKey !== '__root__'
          ? rows.find(function (r) { return !r.parent && String(r.name || '') === String(parentKey); })
          : null;
        const parentIdx = parentRow ? CHARGES_DATA.indexOf(parentRow) : -1;
        const parentHtml = parentKey !== '__root__'
          ? `<div style="display:flex;align-items:center;gap:8px;justify-content:space-between;font-size:10px;font-weight:900;color:var(--tx);padding:6px 8px;background:#fff7e8;border:1px solid rgba(212,160,23,.35);border-radius:7px;margin:6px 0 4px">
              <div style="flex:1;min-width:0">${parentKey}</div>
              ${editable ? `<div style="display:flex;gap:5px;flex-shrink:0"><button class="btn btn-xs btn-gold" onclick="openAddChargeModalForParent('${String(parentKey).replace(/'/g,"\\'")}','${String(cat).replace(/'/g,"\\'")}')">+ Add</button>${parentIdx > -1 ? `<button class="btn btn-xs btn-outline" onclick="editChargeHeading(${parentIdx})">✏️</button><button class="btn btn-xs btn-gray" onclick="deleteChargeHeading(${parentIdx})">✕</button>` : ''}</div>` : ''}
            </div>`
          : '';
        return parentHtml + childRows.map((c,i)=>{
        const gIdx = CHARGES_DATA.indexOf(c);
        const disabled = editable ? '' : 'disabled';
        return `<div style="display:grid;grid-template-columns:70px 1fr 90px 90px 40px;gap:5px;padding:4px 8px;border-bottom:1px solid var(--g5);align-items:center;font-size:11.5px">
          <span class="badge bd-gray" style="font-size:9px">${(c.kind || c.cat || '').toString().replace(/</g,'&lt;')}</span>
          <input type="text" value="${c.name}" style="font-size:11.5px;font-weight:600" onchange="CHARGES_DATA[${gIdx}].name=this.value;saveChargesToFirebase().then(function(){showToast('Saved ✓','s');})" ${disabled}>
          <input type="number" value="${c.chd}" style="font-size:12px;font-weight:800;color:var(--bmh-blue);text-align:right" onchange="CHARGES_DATA[${gIdx}].chd=parseInt(this.value);CENTRE_CHARGES.CHD[CHARGES_DATA[${gIdx}].name]=parseInt(this.value);saveChargesToFirebase().then(function(){showToast('Saved ✓','s');})" ${disabled}>
          <input type="number" value="${c.rpr}" style="font-size:12px;font-weight:800;color:#8a4200;text-align:right" onchange="CHARGES_DATA[${gIdx}].rpr=parseInt(this.value);CENTRE_CHARGES.RPR[CHARGES_DATA[${gIdx}].name]=parseInt(this.value);saveChargesToFirebase().then(function(){showToast('Saved ✓','s');})" ${disabled}>
          ${editable ? `<button class="btn btn-xs btn-gray" title="Delete charge" onclick="deleteChargeAt(${gIdx})">✕</button>` : '<span></span>'}
        </div>`;
      }).join(''); }).join('')}
    </div>`;
  }).join('');
  refreshChargeModalSuggestions();
  renderAllDeptSendBars && renderAllDeptSendBars();
}
function editChargeHeading(idx) {
  const row = CHARGES_DATA[idx];
  if (!row) return;
  if (!isCurrentUserAdmin() && !canEditChargeCategory(row.cat)) { showToast('You can edit charges only for your own department', 'w'); return; }
  const oldName = String(row.name || '').trim();
  const next = prompt('Edit main heading', oldName);
  if (next === null) return;
  const newName = String(next || '').trim();
  if (!newName || newName === oldName) return;
  row.name = newName;
  CHARGES_DATA.forEach(function (r) {
    if (String(r.parent || '').trim() === oldName) r.parent = newName;
  });
  saveChargesToFirebase().then(function () {
    renderChargesList();
    renderCentresCharges();
    showToast('Main heading saved to database ✓', 's');
  }).catch(function () { showToast('Save failed. Please retry.', 'e'); });
}
function deleteChargeHeading(idx) {
  const row = CHARGES_DATA[idx];
  if (!row) return;
  if (!isCurrentUserAdmin() && !canEditChargeCategory(row.cat)) { showToast('You can edit charges only for your own department', 'w'); return; }
  const heading = String(row.name || '').trim();
  if (!heading) return;
  if (!confirm('Delete main heading "' + heading + '" and all its subheadings?')) return;
  for (let i = CHARGES_DATA.length - 1; i >= 0; i -= 1) {
    const r = CHARGES_DATA[i];
    if (String(r.name || '').trim() === heading || String(r.parent || '').trim() === heading) CHARGES_DATA.splice(i, 1);
  }
  saveChargesToFirebase().then(function () {
    renderChargesList();
    renderCentresCharges();
    showToast('Main heading deleted from database ✓', 's');
  }).catch(function () { showToast('Delete failed. Please retry.', 'e'); });
}

