window.deleteChargeHeading = deleteChargeHeading;
window.deleteChargeAt = deleteChargeAt;
window.saveChargeFromModal = saveChargeFromModal;
window.saveCharges = saveCharges;
function saveChargeFromModal() {
  const cat = document.getElementById('add-charge-cat')?.value || 'Eye';
  if (!isCurrentUserAdmin() && !canEditChargeCategory(cat)) { showToast('You can edit charges only for your own department', 'w'); return; }
  const rawParent = document.getElementById('add-charge-parent')?.value?.trim() || '';
  const rawName = document.getElementById('add-charge-name')?.value?.trim();
  const kind = document.getElementById('add-charge-kind')?.value || 'procedure';
  const chd = parseInt(document.getElementById('add-charge-chd')?.value || '0', 10) || 0;
  const rpr = parseInt(document.getElementById('add-charge-rpr')?.value || '0', 10) || 0;
  const isLabCharge = String(cat).toLowerCase() === 'lab' || String(kind).toLowerCase() === 'lab';
  const parent = isLabCharge ? normalizeInvestigationLabel(rawParent) : rawParent;
  const name = isLabCharge ? normalizeInvestigationLabel(rawName) : rawName;
  if (!name && !parent) { showToast('Enter a main heading or charge name', 'w'); return; }
  const finalName = name || parent;
  const finalParent = name ? parent : '';
  const existing = CHARGES_DATA.find(function (row) {
    return row.cat === cat && String(row.parent || '') === finalParent && String(row.name || '').toLowerCase() === String(finalName || '').toLowerCase();
  });
  if (existing) {
    existing.chd = chd;
    existing.rpr = rpr;
    existing.parent = finalParent;
    existing.kind = kind;
  } else {
    CHARGES_DATA.push({cat, kind, parent: finalParent, name: finalName, chd, rpr});
  }
  CENTRE_CHARGES.CHD[finalName] = chd;
  CENTRE_CHARGES.RPR[finalName] = rpr;
  saveChargesToFirebase().then(function(){
    renderChargesList();
    renderCentresCharges();
    resetChargeModalFields();
    showToast('Saved to database ✓', 's');
  }).catch(function(){
    showToast('Charge save failed. Please retry.', 'e');
  });
}

function saveCharges() {
  // Sync back to CENTRE_CHARGES (used by send row)
  CHARGES_DATA.forEach(c => {
    CENTRE_CHARGES.CHD[c.name] = c.chd;
    CENTRE_CHARGES.RPR[c.name] = c.rpr;
  });
  showToast('Saving charges to database…', 'i');
  saveChargesToFirebase().then(function () {
    renderAllDeptSendBars && renderAllDeptSendBars();
    renderChargesList && renderChargesList();
    showToast('Saved to database ✓', 's');
  }).catch(function () {
    showToast('Charge save failed. Please retry.', 'e');
  });
}

function getChargeForProcedure(name, centre) {
  // Look up in CHARGES_DATA first, then fall back to CENTRE_CHARGES
  const match = CHARGES_DATA.find(c=>c.name.toLowerCase().includes(name.toLowerCase())||name.toLowerCase().includes(c.name.toLowerCase().split(' ')[0]));
  if(match) return centre==='RPR' ? match.rpr : match.chd;
  return CENTRE_CHARGES[centre||'CHD']?.[name] || 0;
}

