// TRANSACTIONS declared at top of DATA section

const DEPT_COLORS = {
  ophtho:{label:'👁️ Ophthalmology',bg:'var(--blue-lt)',border:'var(--blue)',text:'var(--blue)'},
  obg:{label:'🤰 OBG',bg:'var(--purple-lt)',border:'var(--purple)',text:'var(--purple)'},
  psych:{label:'🧠 Neuropsychiatry',bg:'var(--orange-lt)',border:'var(--orange)',text:'var(--orange)'},
  skin:{label:'💆 Skin',bg:'var(--green-lt)',border:'var(--green)',text:'var(--green)'},
};
function txnIsoDate(txn) {
  const d = String(txn?.date || txn?.createdAt || '');
  return d.includes('T') ? d.split('T')[0] : d.slice(0, 10);
}
function isCollectedTxn(txn) {
  if (!txn || txn.isRefund === true || txn.collected === false) return false;
  return (Number(txn.amount) || 0) > 0;
}
function isEEGTransaction(txn) {
  const hay = [
    txn?.service,
    txn?.name,
    txn?.narration,
    txn?.purpose,
    txn?.type
  ].filter(Boolean).join(' ').toLowerCase();
  return /\beeg\b/.test(hay);
}
function getConcessionAdjustedCollectionTotal(transactions) {
  return (transactions || []).filter(isCollectedTxn).reduce(function (s, t) {
    return s + getNetTransactionAmount(t);
  }, 0);
}

function renderCollectionDashboard() {
  const today = new Date();
  const todayKeyLocal = [
    today.getFullYear(),
    String(today.getMonth() + 1).padStart(2, '0'),
    String(today.getDate()).padStart(2, '0')
  ].join('-');
  const allTxn = TRANSACTIONS.filter(function (t) {
    return (t.centre || 'CHD') === getEffectiveCentre() && txnIsoDate(t) === todayKeyLocal && !isInsuranceLikeMode(t.mode || t.ins || '');
  });
  const collected = allTxn.filter(t=>t.collected);

  // Update summary cards
  const total = getConcessionAdjustedCollectionTotal(collected);
  const cash  = collected.filter(t=>t.mode==='Cash').reduce((s,t)=>s+getNetTransactionAmount(t),0);
  const upi   = collected.filter(t=>t.mode!=='Cash').reduce((s,t)=>s+getNetTransactionAmount(t),0);

  const fmt = n => '₹'+n.toLocaleString('en-IN');
  const setEl = (id,v) => { const e=document.getElementById(id); if(e) e.textContent=v; };
  setEl('rc-total-collected', fmt(total));
  setEl('rc-total-txn', collected.length+' transactions');
  setEl('rc-cash-total', fmt(cash));
  setEl('rc-upi-total', fmt(upi));
  setEl('rc-upi-total2', fmt(upi));
  setEl('rc-pending-total', fmt(0));
  setEl('rc-pending-total2', fmt(0));
  setEl('rc-ins-total', fmt(collected.filter(t=>t.mode==='Insurance').reduce((s,t)=>s+t.amount,0)));
  // OPD / Investigations / Procedures breakdown
  const opdTotal = collected.filter(function (t) {
    return transactionHasChargeCategory(t, 'consultation');
  }).reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
  const invTotal = collected.filter(function (t) {
    return transactionHasChargeCategory(t, 'diagnostic');
  }).reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
  const procTotal = collected.filter(function (t) {
    return transactionHasChargeCategory(t, 'surgery');
  }).reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
  setEl('rc-opd-total', fmt(opdTotal));
  setEl('rc-inv-total', fmt(invTotal));
  setEl('rc-proc-total', fmt(procTotal));

  // Dept breakdown — OPD / Investigation / Procedure & surgery shown inside each department (sums to dept total)
  const deptEl = document.getElementById('rc-dept-collection');
  if(deptEl) {
    const depts = ['ophtho','obg','psych','skin'];
    deptEl.innerHTML = depts.map(dept => {
      const dTxn = collected.filter(t=>t.dept===dept);
      const dTotal = dTxn.reduce((s,t)=>s+getNetTransactionAmount(t),0);
      const dc = DEPT_COLORS[dept];
      const did = 'dept-txn-'+dept;
      if(!dTxn.length) return '';
      const sumCat = function (want) {
        return dTxn.filter(function (t) {
          return inferChargeCategoryFromService(t.service || t.for || t.desc || '') === want;
        }).reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
      };
      const opdD = sumCat('consultation');
      const invD = sumCat('diagnostic');
      const sxD = sumCat('surgery');
      const otherD = dTxn.filter(function (t) {
        const c = inferChargeCategoryFromService(t.service || t.for || t.desc || '');
        return c !== 'consultation' && c !== 'diagnostic' && c !== 'surgery';
      }).reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
      const chk = Math.abs(dTotal - (opdD + invD + sxD + otherD)) < 0.5;
      return `<div style="border:1.5px solid ${dc.border};border-radius:var(--r);overflow:hidden;background:#fff">
        <div style="display:flex;align-items:center;gap:10px;padding:10px 14px;background:${dc.bg};cursor:pointer" onclick="toggleDeptDetail('${did}')">
          <div style="flex:1">
            <div style="font-size:13px;font-weight:800;color:${dc.text}">${dc.label}</div>
            <div style="font-size:10.5px;color:var(--g1);margin-top:4px;display:flex;flex-wrap:wrap;gap:6px 12px;align-items:center">
              <span style="cursor:pointer" onclick="event.stopPropagation();openRcCollectionDetailModal('${dept}','opd')">OPD <strong style="color:#166534">${fmt(opdD)}</strong></span>
              <span style="opacity:.35">·</span>
              <span style="cursor:pointer" onclick="event.stopPropagation();openRcCollectionDetailModal('${dept}','inv')">Inv <strong style="color:#1e40af">${fmt(invD)}</strong></span>
              <span style="opacity:.35">·</span>
              <span style="cursor:pointer" onclick="event.stopPropagation();openRcCollectionDetailModal('${dept}','sx')">Sx/Proc <strong style="color:#6b21a8">${fmt(sxD)}</strong></span>
              ${otherD > 0 ? `<span style="opacity:.35">·</span><span style="cursor:pointer" onclick="event.stopPropagation();openRcCollectionDetailModal('${dept}','other')">Other <strong>${fmt(otherD)}</strong></span>` : ''}
            </div>
            ${!chk ? '<div style="font-size:9px;color:var(--orange);margin-top:4px">Note: category split may not match total if service text is unclear.</div>' : ''}
            <div style="font-size:10.5px;color:var(--g1);margin-top:2px">${dTxn.length} transaction${dTxn.length>1?'s':''} today</div>
            <div style="margin-top:6px"><button type="button" class="btn btn-xs btn-outline" onclick="event.stopPropagation();printRcCollectionDetail('${dept}','all')">🖨️ Print Dept</button></div>
          </div>
          <div style="text-align:right">
            <div style="font-size:18px;font-weight:900;color:${dc.text}">${fmt(dTotal)}</div>
          </div>
          <div id="chev-${did}" style="font-size:16px;color:${dc.text}">⌄</div>
        </div>
        <div id="${did}" style="display:none;padding:8px 12px">
          ${dTxn.length ? dTxn.map(t=>`
            <div style="display:flex;align-items:center;gap:8px;padding:6px 0;border-bottom:1px solid var(--g5);font-size:12px">
              <div style="flex:1"><div style="font-weight:700;display:flex;align-items:center;gap:6px;flex-wrap:wrap">${t.patient}${t.type==='advance' ? '<span class="badge" style="font-size:8px;background:var(--blue-lt);color:var(--blue);border:1px solid var(--blue)">Advance</span>' : ''}</div><div style="font-size:10.5px;color:var(--g1)">${t.service||'—'} · ${t.time||'—'}</div></div>
              <span class="badge bd-gray" style="font-size:9.5px">${t.mode||'—'}</span>
              <div style="font-weight:800;color:#1a8c3c">${fmt(t.amount)}</div>
              <button title="Delete" onclick="deleteTransaction('${t.id}')" style="background:none;border:none;cursor:pointer;font-size:12px;color:var(--red);padding:0 2px">🗑️</button>
            </div>`).join('') : '<div style="padding:8px;color:var(--g1);font-size:11.5px">No collected payments yet</div>'}
        </div>
      </div>`;
    }).join('');
  }

  // All transactions
  const allEl = document.getElementById('rc-all-txn');
  if(allEl) {
    allEl.innerHTML = allTxn.length ? allTxn.slice().reverse().map(t=>`
      <div style="display:flex;align-items:center;gap:9px;padding:8px 12px;background:${t.collected?'#fff':'var(--orange-lt)'};border-radius:var(--rsm);border:1px solid ${t.collected?'var(--g5)':'rgba(255,149,0,.3)'}">
        <div style="font-size:16px">${DEPT_COLORS[t.dept]?.label?.split(' ')[0]||'🏥'}</div>
        <div style="flex:1">
          <div style="font-size:12.5px;font-weight:700;display:flex;align-items:center;gap:6px;flex-wrap:wrap">${t.patient}${t.type==='advance' ? '<span class="badge" style="font-size:8px;background:var(--blue-lt);color:var(--blue)">Advance</span>' : ''} <span style="font-family:monospace;font-size:10px;color:var(--bmh-teal)">${t.bmhId||''}</span></div>
          <div style="font-size:11px;color:var(--g1)">${t.service||'—'} · ${t.time||'—'}</div>
        </div>
        <span class="badge bd-gray" style="font-size:9.5px">${t.mode||'—'}</span>
        <div style="font-weight:900;color:${t.collected?'#1a8c3c':'var(--orange)'};font-size:13px">₹${t.amount.toLocaleString('en-IN')}</div>
        <span class="badge ${t.collected?'bd-green':'bd-orange'}" style="font-size:9.5px">${t.collected?'✅':'⏳'}</span>
        <button title="Delete this transaction" onclick="deleteTransaction('${t.id}')" style="background:var(--red-lt);color:var(--red);border:1px solid rgba(255,59,48,.3);border-radius:5px;padding:2px 6px;font-size:11px;cursor:pointer;flex-shrink:0">🗑️</button>
      </div>`).join('')
    : '<div style="padding:16px;text-align:center;color:var(--g1);font-size:12px">No transactions today</div>';
  }
}

function openRcCollectionDetailModal(dept, catKey) {
  const today = new Date();
  const todayKeyLocal = [
    today.getFullYear(),
    String(today.getMonth() + 1).padStart(2, '0'),
    String(today.getDate()).padStart(2, '0')
  ].join('-');
  const collected = TRANSACTIONS.filter(function (t) {
    return (t.centre || 'CHD') === getEffectiveCentre() && txnIsoDate(t) === todayKeyLocal && t.collected;
  }).filter(function (t) { return t.dept === dept; });
  let list = [];
  if (catKey === 'other') {
    list = collected.filter(function (t) {
      const c = inferChargeCategoryFromService(t.service || t.for || t.desc || '');
      return c !== 'consultation' && c !== 'diagnostic' && c !== 'surgery';
    });
  } else {
    const want = catKey === 'opd' ? 'consultation' : catKey === 'inv' ? 'diagnostic' : catKey === 'sx' ? 'surgery' : '';
    list = collected.filter(function (t) {
      return inferChargeCategoryFromService(t.service || t.for || t.desc || '') === want;
    });
  }
  const fmt = function (n) { return '₹' + n.toLocaleString('en-IN'); };
  const isConsultationPurpose = function (purpose) {
    const p = String(purpose || '').toLowerCase();
    return /consult|follow|post\s*-?\s*op|opd|review|registration|new consultation/.test(p);
  };
  const todayConsultationPatients = (PATIENTS || []).filter(function (p) {
    if (!p || !centreMatch(p)) return false;
    if (String(p.dept || '').toLowerCase() !== String(dept || '').toLowerCase()) return false;
    if (!isConsultationPurpose(p.purpose || '')) return false;
    return localDateKey(p.checkinAt || p.createdAt || p.queueDate || p.visitDate || p.updatedAt) === todayKeyLocal;
  });
  const dc = DEPT_COLORS[dept];
  const title = (dc?.label || dept) + ' — ' + ({ opd: 'OPD / consultations', inv: 'Investigations & diagnostics', sx: 'Procedures & surgery', other: 'Other' }[catKey] || catKey);
  const bodyEl = document.getElementById('m-rc-collection-detail-body');
  const titleEl = document.getElementById('m-rc-collection-detail-title');
  if (titleEl) titleEl.innerHTML = escapeHtmlConsent(title) + ' <button type="button" class="btn btn-xs btn-outline" style="margin-left:8px" onclick="printRcCollectionDetail(\'' + String(dept).replace(/'/g, "\\'") + '\',\'' + String(catKey).replace(/'/g, "\\'") + '\')">🖨️ Print</button>';
  if (!bodyEl) return;
  const paidTotal = list.reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
  const paidPatients = new Set(list.map(function (t) { return t.bmhId || ''; }).filter(Boolean)).size;
  const wantCat = catKey === 'opd' ? 'consultation' : catKey === 'inv' ? 'diagnostic' : catKey === 'sx' ? 'surgery' : null;
  let unpaid = [];
  if (wantCat) {
    unpaid = (PAY_REQUESTS || []).filter(function (r) {
      if (String(r.status || '').toLowerCase() === 'paid') return false;
      if (String(r.dept || '').toLowerCase() !== String(dept || '').toLowerCase()) return false;
      return inferChargeCategoryFromService(r.for || '') === wantCat;
    });
  }
  const unpaidTotal = unpaid.reduce(function (s, r) { return s + (Number(r.amount) || 0); }, 0);
  const unpaidPatients = new Set(unpaid.map(function (r) { return r.bmhId || ''; }).filter(Boolean)).size;
  const paidRows = list.map(function (t) {
    const rowStyle = 'display:flex;align-items:center;gap:7px;padding:7px 8px;border-bottom:1px solid var(--g5);font-size:12px';
    const attrs = t.bmhId
      ? ' style="' + rowStyle + ';cursor:pointer" onclick="openPatient(\'' + String(t.bmhId).replace(/'/g, "\\'") + '\')"'
      : ' style="' + rowStyle + '"';
    return '<div' + attrs + '>'
      + '<div style="flex:1"><div style="font-weight:800">' + escapeHtmlConsent(t.patient || '') + '</div><div style="font-size:10.5px;color:var(--g1)">' + escapeHtmlConsent(t.service || '—') + ' · ' + escapeHtmlConsent(t.time || '—') + '</div></div>'
      + '<span class="badge bd-gray" style="font-size:9px">' + escapeHtmlConsent(t.mode || '—') + '</span>'
      + '<div style="font-weight:900;color:#1a8c3c">' + fmt(getNetTransactionAmount(t)) + '</div>'
      + '</div>';
  }).join('');
  const unpaidRows = unpaid.map(function (r) {
    return '<div style="display:flex;align-items:center;gap:7px;padding:7px 8px;border-bottom:1px solid var(--g5);font-size:12px">'
      + '<div style="flex:1"><div style="font-weight:800">' + escapeHtmlConsent(r.patient || '') + '</div><div style="font-size:10.5px;color:var(--g1)">' + escapeHtmlConsent(r.for || '—') + '</div></div>'
      + '<span class="badge bd-orange" style="font-size:9px">Pending</span>'
      + '<div style="font-weight:900;color:#b45309">' + fmt(Number(r.amount) || 0) + '</div>'
      + '<select id="pay-mode-' + String(r.id).replace(/"/g, '&quot;') + '" style="height:28px;border:1px solid var(--g4);border-radius:6px;padding:0 6px;font-size:10.5px;background:#fff">'
      + '<option value="Cash"' + (isInsuranceLikeMode(r.mode || r.ins || '') ? '' : ' selected') + '>Cash</option>'
      + '<option value="UPI"' + (String(r.mode || '').toLowerCase() === 'upi' ? ' selected' : '') + '>UPI</option>'
      + '<option value="Credit Card"' + (String(r.mode || '').toLowerCase() === 'credit card' ? ' selected' : '') + '>Credit Card</option>'
      + '<option value="Insurance/TPA"' + (isInsuranceLikeMode(r.mode || r.ins || '') ? ' selected' : '') + '>Insurance/TPA</option>'
      + '</select>'
      + '<button type="button" class="btn btn-xs" style="background:var(--green);color:#fff;border:none;border-radius:6px;padding:4px 10px;font-size:10.5px;font-weight:800;cursor:pointer" onclick="collectPayment(\'' + String(r.id).replace(/'/g, "\\'") + '\',\'' + String(r.id).replace(/'/g, "\\'") + '\')">Collect</button>'
      + '</div>';
  }).join('');
  const groupedByService = {};
  list.forEach(function (t) {
    const key = String(t.service || t.for || t.desc || 'Consultation').trim() || 'Consultation';
    if (!groupedByService[key]) groupedByService[key] = { count: 0, amount: 0, bmhId: t.bmhId || '' };
    groupedByService[key].count += 1;
    groupedByService[key].amount += getNetTransactionAmount(t);
    if (!groupedByService[key].bmhId && t.bmhId) groupedByService[key].bmhId = t.bmhId;
  });
  const groupedRows = Object.entries(groupedByService).sort(function (a, b) {
    return b[1].amount - a[1].amount;
  }).map(function (entry) {
    const label = entry[0];
    const g = entry[1];
    const rowStyle = 'display:flex;justify-content:space-between;gap:8px;padding:6px 8px;border-bottom:1px solid var(--g5);font-size:11.5px';
    const attrs = g.bmhId
      ? ' style="' + rowStyle + ';cursor:pointer" onclick="openPatient(\'' + String(g.bmhId).replace(/'/g, "\\'") + '\')"'
      : ' style="' + rowStyle + '"';
    return '<div' + attrs + '><div><strong>' + escapeHtmlConsent(label) + '</strong> · ' + g.count + ' patient(s)</div><div style="font-weight:800">' + fmt(g.amount) + '</div></div>';
  }).join('');
  const consultPaidIds = new Set(list.filter(function (t) { return getNetTransactionAmount(t) > 0; }).map(function (t) { return t.bmhId || ''; }).filter(Boolean));
  const totalConsultPts = new Set(todayConsultationPatients.map(function (p) { return p.bmhId; })).size;
  const paidConsult = consultPaidIds.size;
  // Only count patients explicitly marked as no-fee, not just those without a transaction
  const noFeeConsult = todayConsultationPatients.filter(function (p) { return !!p.consultationNoFee; }).length;
  let html = '';
  if (wantCat) {
    const rightLabel = catKey === 'opd' ? 'No fee consultations' : 'Unpaid (pending requests)';
    const rightCount = catKey === 'opd' ? noFeeConsult : unpaidPatients;
    const rightAmt = catKey === 'opd' ? '' : (' · <strong style="color:#b45309">' + fmt(unpaidTotal) + '</strong>');
    const leftPatients = catKey === 'opd' ? paidConsult : paidPatients;
    const titleText = catKey === 'opd' ? 'Today — paid vs no-fee consultations' : 'Today — paid vs unpaid';
    html += '<div style="background:linear-gradient(180deg,#fff7ed,#fff);border:1px solid #f59e0b;border-radius:10px;padding:10px 12px;margin-bottom:12px">'
      + '<div style="font-size:11px;font-weight:900;color:#8a4200;text-transform:uppercase;margin-bottom:6px">' + titleText + '</div>'
      + '<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;font-size:12px">'
      + '<div><span style="color:var(--g1)">Paid (collected)</span><br><strong>' + leftPatients + '</strong> patient(s) · <strong style="color:#1a8c3c">' + fmt(paidTotal) + '</strong></div>'
      + '<div><span style="color:var(--g1)">' + rightLabel + '</span><br><strong>' + rightCount + '</strong> patient(s)' + rightAmt + '</div>'
      + '</div></div>';
    html += '<details open style="margin-bottom:8px;border:1px solid var(--g5);border-radius:8px;padding:8px 10px;background:#fff">'
      + '<summary style="cursor:pointer;font-weight:800;font-size:12px">Service / purpose summary</summary>'
      + '<div style="margin-top:6px">' + (groupedRows || '<div style="padding:10px;color:var(--g1);font-size:12px">No grouped items in this category.</div>') + '</div></details>';
  }
  if (wantCat) {
    html += '<details open style="margin-bottom:8px;border:1px solid var(--g5);border-radius:8px;padding:8px 10px;background:#fff">'
      + '<summary style="cursor:pointer;font-weight:800;font-size:12px">Collected transactions (' + list.length + ')</summary>'
      + '<div style="margin-top:6px">' + (paidRows || '<div style="padding:10px;color:var(--g1);font-size:12px">No collected items in this category today.</div>') + '</div></details>';
    html += '<details style="margin-bottom:8px;border:1px solid var(--g5);border-radius:8px;padding:8px 10px;background:#fff">'
      + '<summary style="cursor:pointer;font-weight:800;font-size:12px">Pending payment requests (' + unpaid.length + ')</summary>'
      + '<div style="margin-top:6px">' + (unpaidRows || '<div style="padding:10px;color:var(--g1);font-size:12px">No pending requests in this category.</div>') + '</div></details>';
  } else {
    html += list.length ? paidRows : '<div style="padding:14px;color:var(--g1);font-size:12px">No transactions in this category for today.</div>';
  }
  bodyEl.innerHTML = html;
  openM('m-rc-collection-detail');
}
window.openRcCollectionDetailModal = openRcCollectionDetailModal;
function toggleDeptDetail(id) {
  const el = document.getElementById(id);
  const ch = document.getElementById('chev-'+id);
  if(!el) return;
  const open = el.style.display!=='none';
  el.style.display = open?'none':'block';
  if(ch) ch.textContent = open?'⌄':'⌃';
}

function printDayCollection() {
  const today = new Date().toLocaleDateString('en-IN',{day:'numeric',month:'long',year:'numeric'});
  const todayKeyLocal = localDateKey(new Date());
  const collected = TRANSACTIONS.filter(function (t) {
    return t.collected && (t.centre || 'CHD') === getEffectiveCentre() && txnIsoDate(t) === todayKeyLocal;
  });
  const total = collected.reduce((s,t)=>s+getNetTransactionAmount(t),0);
  const fmt = n=>'₹'+n.toLocaleString('en-IN');
  const lhSrc = window.LH_SRC||'';

  const html = `<!DOCTYPE html><html><head><meta charset="UTF-8">
<style>
@import url('https://fonts.googleapis.com/css2?family=Lato:wght@400;700;900&display=swap');
*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Lato',Arial,sans-serif;font-size:11.5px;padding:10mm 14mm}
@page{size:A4 portrait;margin:0}
table{width:100%;border-collapse:collapse}th{background:#1A3C6E;color:#fff;padding:6px 9px;font-size:10px;text-transform:uppercase;letter-spacing:.5px}
td{border:1px solid #ddd;padding:6px 9px}tr:nth-child(even){background:#f8f9fc}
.total-row{background:#EBF3FF!important;font-weight:900;font-size:13px}
</style></head><body>
${lhSrc?`<img src="${lhSrc}" style="width:100%;height:auto;margin-bottom:12px">`:''}
<div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:14px;border-bottom:2px solid #1A3C6E;padding-bottom:8px">
  <div style="font-size:18px;font-weight:900;color:#1A3C6E">Daily Collection Summary</div>
  <div style="font-size:12px;color:#555">${today}</div>
</div>
<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:16px">
  <div style="background:#EBF3FF;border-radius:6px;padding:10px;text-align:center"><div style="font-size:8.5px;font-weight:700;color:#666;text-transform:uppercase;margin-bottom:4px">Total</div><div style="font-size:20px;font-weight:900;color:#1A3C6E">${fmt(total)}</div></div>
  <div style="background:#EBF3FF;border-radius:6px;padding:10px;text-align:center"><div style="font-size:8.5px;font-weight:700;color:#666;text-transform:uppercase;margin-bottom:4px">Cash</div><div style="font-size:20px;font-weight:900;color:#1a8c3c">${fmt(collected.filter(t=>t.mode==='Cash').reduce((s,t)=>s+getNetTransactionAmount(t),0))}</div></div>
  <div style="background:#EBF3FF;border-radius:6px;padding:10px;text-align:center"><div style="font-size:8.5px;font-weight:700;color:#666;text-transform:uppercase;margin-bottom:4px">UPI/Card</div><div style="font-size:20px;font-weight:900;color:#1A3C6E">${fmt(collected.filter(t=>t.mode!=='Cash').reduce((s,t)=>s+getNetTransactionAmount(t),0))}</div></div>
  <div style="background:#EBF3FF;border-radius:6px;padding:10px;text-align:center"><div style="font-size:8.5px;font-weight:700;color:#666;text-transform:uppercase;margin-bottom:4px">Transactions</div><div style="font-size:20px;font-weight:900;color:#1A3C6E">${collected.length}</div></div>
</div>
<table>
  <thead><tr><th>#</th><th>Time</th><th>Patient</th><th>BMSH ID</th><th>Department</th><th>Service</th><th>Mode</th><th>Amount</th></tr></thead>
  <tbody>
    ${collected.map((t,i)=>`<tr><td>${i+1}</td><td>${t.time}</td><td style="font-weight:700">${t.patient}</td><td style="font-family:monospace;font-size:10px">${t.bmhId}</td><td>${{ophtho:'Ophthalmology',obg:'OBG',psych:'Psychiatry',skin:'Skin'}[t.dept]||t.dept}</td><td>${t.service}${isEEGTransaction(t)?' <span style="font-size:10px;color:#8a4200">(50% concession applied)</span>':''}</td><td>${t.mode}</td><td style="font-weight:700;text-align:right">${fmt(getNetTransactionAmount(t))}</td></tr>`).join('')}
    <tr class="total-row"><td colspan="7" style="text-align:right;border:1px solid #1A3C6E">TOTAL COLLECTED</td><td style="text-align:right;border:1px solid #1A3C6E">${fmt(total)}</td></tr>
  </tbody>
</table>
<div style="margin-top:24px;display:flex;justify-content:space-between">
  <div><div style="border-bottom:1px solid #333;width:160px;margin-bottom:4px"></div><div style="font-size:10px;color:#888">Cashier / Receptionist</div></div>
  <div style="text-align:right"><div style="border-bottom:1px solid #333;width:160px;margin-bottom:4px"></div><div style="font-size:10px;color:#888">Supervisor / In-charge</div></div>
</div>
</body></html>`;
  safePrint(html);
  showToast('Collection summary sent to printer ✓','s');
}

function printDayCollectionByDept() {
  const todayLabel = new Date().toLocaleDateString('en-IN',{day:'numeric',month:'long',year:'numeric'});
  const todayKeyLocal = localDateKey(new Date());
  const txns = TRANSACTIONS.filter(function (t) {
    return t.collected && (t.centre || 'CHD') === getEffectiveCentre() && txnIsoDate(t) === todayKeyLocal;
  });
  const depts = ['ophtho','obg','psych','skin'];
  const fmt = function (n) { return '₹' + Number(n || 0).toLocaleString('en-IN'); };
  const isConsultPurpose = function (purpose) {
    const p = String(purpose || '').toLowerCase();
    return /consult|follow|post\s*-?\s*op|opd|review|registration|new consultation/.test(p);
  };
  const groupedLine = function (name, arr) {
    const total = arr.reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
    const rate = arr.length ? (total / arr.length) : 0;
    const rateText = Number.isInteger(rate) ? rate : Math.round(rate);
    return '<div style="font-size:11px;margin-top:3px">' + escapeHtmlConsent(name) + ' — ' + arr.length + ' × ' + rateText + ' = <strong>' + fmt(total) + '</strong></div>';
  };
  const deptBlocks = depts.map(function (dept) {
    const arr = txns.filter(function (t) { return String(t.dept || '').toLowerCase() === dept; });
    if (!arr.length) return '';
    const consult = arr.filter(function (t) { return inferChargeCategoryFromService(t.service || t.for || t.desc || '') === 'consultation'; });
    const inv = arr.filter(function (t) { return inferChargeCategoryFromService(t.service || t.for || t.desc || '') === 'diagnostic'; });
    const sx = arr.filter(function (t) { return inferChargeCategoryFromService(t.service || t.for || t.desc || '') === 'surgery'; });
    const other = arr.filter(function (t) {
      const c = inferChargeCategoryFromService(t.service || t.for || t.desc || '');
      return c !== 'consultation' && c !== 'diagnostic' && c !== 'surgery';
    });
    const consultPts = new Set((PATIENTS || []).filter(function (p) {
      return centreMatch(p) && String(p.dept || '').toLowerCase() === dept
        && isConsultPurpose(p.purpose || '')
        && localDateKey(p.checkinAt || p.createdAt || p.queueDate || p.visitDate || p.updatedAt) === todayKeyLocal;
    }).map(function (p) { return p.bmhId; }));
    const paidConsultPts = new Set(consult.filter(function (t) { return getNetTransactionAmount(t) > 0; }).map(function (t) { return t.bmhId || ''; }).filter(Boolean));
    const noFeeConsult = Math.max(0, consultPts.size - paidConsultPts.size);
    const byName = function (items) {
      const map = {};
      items.forEach(function (t) {
        const k = String(t.service || t.for || t.desc || 'Service').trim() || 'Service';
        if (!map[k]) map[k] = [];
        map[k].push(t);
      });
      return Object.keys(map).sort().map(function (k) { return groupedLine(k, map[k]); }).join('');
    };
    const sxLines = sx.map(function (t) {
      return '<div style="font-size:11px;margin-top:3px">- ' + escapeHtmlConsent(String(t.service || 'Surgery')) + ' - <strong>' + fmt(getNetTransactionAmount(t)) + '</strong></div>';
    }).join('') || '<div style="font-size:11px;margin-top:3px;color:#666">No surgery entries</div>';
    const deptTotal = arr.reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
    const consultTotal = consult.reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
    return '<div style="border:1px solid #d6dbe6;border-radius:10px;padding:10px 12px;margin-bottom:10px">'
      + '<div style="font-size:15px;font-weight:900;color:#1A3C6E">' + escapeHtmlConsent(DEPT_COLORS[dept]?.label || dept) + '</div>'
      + '<div style="margin-top:6px;font-size:12px"><strong>OPD:</strong> total ' + consultPts.size + ', no fee ' + noFeeConsult + ', paid ' + paidConsultPts.size + ' = <strong>' + fmt(consultTotal) + '</strong></div>'
      + (consult.length ? byName(consult) : '<div style="font-size:11px;margin-top:3px;color:#666">No paid consultation rows</div>')
      + '<div style="margin-top:8px;font-size:12px"><strong>Investigations:</strong></div>'
      + (inv.length ? byName(inv) : '<div style="font-size:11px;margin-top:3px;color:#666">No investigation entries</div>')
      + '<div style="margin-top:8px;font-size:12px"><strong>Surgery:</strong></div>'
      + sxLines
      + '<div style="margin-top:8px;font-size:12px"><strong>Other charges:</strong></div>'
      + (other.length ? byName(other) : '<div style="font-size:11px;margin-top:3px;color:#666">No other entries</div>')
      + '<div style="margin-top:9px;padding-top:7px;border-top:1px solid #e5e7eb;text-align:right;font-size:13px;font-weight:900">Department Total: ' + fmt(deptTotal) + '</div>'
      + '</div>';
  }).join('');
  const grandTotal = txns.reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
  const html = '<!DOCTYPE html><html><head><meta charset="UTF-8"><style>body{font-family:Arial,sans-serif;padding:10mm;color:#111}</style></head><body>'
    + '<h2 style="margin:0;color:#1A3C6E">Department-wise Concise Collection Summary</h2>'
    + '<div style="margin:6px 0 12px;color:#555">' + todayLabel + '</div>'
    + (deptBlocks || '<div>No collections for today.</div>')
    + '<div style="margin-top:10px;text-align:right;font-size:14px;font-weight:900">Grand Total: ' + fmt(grandTotal) + '</div>'
    + '</body></html>';
  safePrint(html);
  showToast('Department-wise concise summary sent to printer ✓','s');
}
function printRcCollectionDetail(dept, catKey) {
  const todayLabel = new Date().toLocaleDateString('en-IN',{day:'numeric',month:'long',year:'numeric'});
  const todayKeyLocal = localDateKey(new Date());
  const txns = TRANSACTIONS.filter(function (t) {
    return t.collected && (t.centre || 'CHD') === getEffectiveCentre() && txnIsoDate(t) === todayKeyLocal
      && String(t.dept || '').toLowerCase() === String(dept || '').toLowerCase();
  });
  const rows = (catKey === 'all' ? txns : txns.filter(function (t) {
    const c = inferChargeCategoryFromService(t.service || t.for || t.desc || '');
    if (catKey === 'opd') return c === 'consultation';
    if (catKey === 'inv') return c === 'diagnostic';
    if (catKey === 'sx') return c === 'surgery';
    if (catKey === 'other') return c !== 'consultation' && c !== 'diagnostic' && c !== 'surgery';
    return true;
  }));
  const fmt = function (n) { return '₹' + Number(n || 0).toLocaleString('en-IN'); };
  const total = rows.reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
  const bodyRows = rows.map(function (t, i) {
    return '<tr><td style="border:1px solid #ddd;padding:6px">' + (i + 1) + '</td>'
      + '<td style="border:1px solid #ddd;padding:6px">' + escapeHtmlConsent(t.patient || '') + '</td>'
      + '<td style="border:1px solid #ddd;padding:6px">' + escapeHtmlConsent(t.bmhId || '') + '</td>'
      + '<td style="border:1px solid #ddd;padding:6px">' + escapeHtmlConsent(t.service || '') + '</td>'
      + '<td style="border:1px solid #ddd;padding:6px">' + escapeHtmlConsent(t.mode || '') + '</td>'
      + '<td style="border:1px solid #ddd;padding:6px;text-align:right;font-weight:800">' + fmt(getNetTransactionAmount(t)) + '</td></tr>';
  }).join('');
  const html = '<!DOCTYPE html><html><head><meta charset="UTF-8"><style>body{font-family:Arial;padding:12mm}table{width:100%;border-collapse:collapse}th{background:#1A3C6E;color:#fff;padding:7px;font-size:11px}</style></head><body>'
    + '<h2 style="margin:0;color:#1A3C6E">Collection Detail - ' + escapeHtmlConsent((DEPT_COLORS[dept]?.label || dept) + (catKey && catKey !== 'all' ? (' / ' + catKey.toUpperCase()) : '')) + '</h2>'
    + '<div style="margin:6px 0 10px;color:#555">' + todayLabel + '</div>'
    + '<table><thead><tr><th>#</th><th>Patient</th><th>BMSH ID</th><th>Service</th><th>Mode</th><th>Amount</th></tr></thead><tbody>'
    + (bodyRows || '<tr><td colspan="6" style="border:1px solid #ddd;padding:8px">No rows</td></tr>')
    + '<tr><td colspan="5" style="border:1px solid #ddd;padding:7px;text-align:right;font-weight:900">Total</td><td style="border:1px solid #ddd;padding:7px;text-align:right;font-weight:900">' + fmt(total) + '</td></tr>'
    + '</tbody></table></body></html>';
  safePrint(html);
}

