// ── PATIENTS ─────────────────────────────────────────────────
function savePatientToFirebase(patient) {
  if(!patient || !patient.bmhId) return;
  normalizePatientRecord(patient);
  const centreRaw = patient.centre
    || (typeof getEffectiveCentre === 'function' ? getEffectiveCentre() : '')
    || CURRENT_USER?.centre
    || 'CHD';
  const centre = patientCentreKey(centreRaw);
  const payload = {
    ...patient,
    centre,
    lastUpdated: new Date().toISOString(),
    updatedBy: CURRENT_USER?.name || 'System'
  };
  const rt = fbSet(`patients/${patient.bmhId}`, payload);
  const fs = typeof window.upsertPatientFirestore === 'function'
    ? window.upsertPatientFirestore(payload).catch(err => { console.warn('Firestore patient sync:', err); })
    : Promise.resolve();
  return Promise.all([rt, fs]).then(() => showToast('Patient saved to database ✓', 's'))
    .catch(e => showToast('Save failed: ' + e.message, 'w'));
}

let _fbPatientsLoaded = false;
let _renderDashTimer = null;
function getActivePageId() {
  return document.querySelector('.page.active')?.id || '';
}
function renderActivePageAfterRealtimeUpdate() {
  const activeId = getActivePageId();
  if (activeId === 'pg-dashboard') {
    renderDashboard && renderDashboard();
    return;
  }
  if (activeId === 'pg-reception') {
    renderReceptionPage && renderReceptionPage();
    renderCollectionDashboard && renderCollectionDashboard();
    return;
  }
  if (activeId === 'pg-doctor-queue') {
    renderDocQueue && renderDocQueue();
    return;
  }
  if (activeId === 'pg-ipd') {
    renderIPD && renderIPD();
    return;
  }
  if (activeId === 'pg-ot') {
    renderOTListSafe && renderOTListSafe();
    return;
  }
}
function _debouncedRenderDash() {
  if(_renderDashTimer) clearTimeout(_renderDashTimer);
  _renderDashTimer = setTimeout(() => {
    renderActivePageAfterRealtimeUpdate();
  }, 300);
}
function applyPatientsPayload(data) {
  const all = data ? Object.values(data) : [];
  const chunkSize = 250;
  const normalized = [];
  let idx = 0;
  if (window._bmhPatientsApplyTimer) {
    clearTimeout(window._bmhPatientsApplyTimer);
    window._bmhPatientsApplyTimer = null;
  }
  window._bmhPatientsHydrating = true;
  const finish = function () {
    window._BMH_ALL_PATIENTS_CACHE = normalized;
    rebuildPatientsArrayFromGlobalCache();
    window._bmhPatientsHydrating = false;
    if(!_fbPatientsLoaded) {
      _fbPatientsLoaded = true;
      showToast('Connected to database ✓','s');
    }
    genRcUID && genRcUID();
    _debouncedRenderDash();
  };
  const pump = function () {
    const end = Math.min(idx + chunkSize, all.length);
    for (; idx < end; idx += 1) normalized.push(normalizePatientRecord(all[idx]));
    if (idx < all.length) {
      window._bmhPatientsApplyTimer = setTimeout(pump, 0);
    } else {
      finish();
    }
  };
  if (!all.length) {
    finish();
    return;
  }
  pump();
}
function refreshPatientsFromFirebase() {
  if (window._bmhPatientsRefreshInFlight || !window.FBDB) return Promise.resolve();
  window._bmhPatientsRefreshInFlight = true;
  return fbOnce('patients').then(function (data) {
    applyPatientsPayload(data);
  }).catch(function (e) {
    console.warn('patients refresh failed', e);
  }).finally(function () {
    window._bmhPatientsRefreshInFlight = false;
    window._bmhPatientsLastRefreshAt = Date.now();
  });
}
function schedulePatientsRefreshLoop() {
  if (window._bmhPatientsRefreshLoopStarted) return;
  window._bmhPatientsRefreshLoopStarted = true;
  const maybeRefresh = function () {
    if (document.visibilityState === 'hidden') return;
    const last = Number(window._bmhPatientsLastRefreshAt || 0);
    if (Date.now() - last < 120000) return;
    refreshPatientsFromFirebase();
  };
  document.addEventListener('visibilitychange', function () {
    if (document.visibilityState === 'visible') maybeRefresh();
  });
  window.addEventListener('focus', function () { maybeRefresh(); });
}
window.refreshPatientsFromFirebase = refreshPatientsFromFirebase;

function loadPatientsFromFirebase() {
  if(window._bmhRtdbPatientsListening) return;
  window._bmhRtdbPatientsListening = true;
  refreshPatientsFromFirebase();
  schedulePatientsRefreshLoop();
}

// ── PAY REQUESTS (real-time sync) ────────────────────────────
function savePayRequestToFirebase(pr) {
  fbSet(`payRequests/${pr.id}`, {
    ...pr,
    date: new Date().toISOString(),
    centre: CURRENT_USER?.centre || 'CHD'
  });
}
function isInsuranceLikeMode(value) {
  return /Insurance|TPA|PMJAY|CGHS|ECHS|Ayushman|Cashless/i.test(String(value || ''));
}
function getDisplayTpaClaims() {
  const centre = CURRENT_USER?.isAdmin ? null : (CURRENT_USER?.centre || 'CHD');
  const liveClaims = (PAY_REQUESTS || []).filter(function (r) {
    if (!isInsuranceLikeMode(r.mode || r.ins || '')) return false;
    if (centre && String(r.centre || 'CHD') !== String(centre)) return false;
    return true;
  }).map(function (r) {
    return Object.assign({ _synthetic: false }, r);
  });
  const byBmhId = new Set(liveClaims.map(function (r) { return String(r.bmhId || '').trim(); }).filter(Boolean));
  const synthetic = (PATIENTS || []).filter(function (p) {
    if (!p || !p.bmhId) return false;
    if (byBmhId.has(String(p.bmhId))) return false;
    if (centre && String(p.centre || 'CHD') !== String(centre)) return false;
    const ins = String(p.ins || p.refType || '').trim();
    if (!isInsuranceLikeMode(ins)) return false;
    return true;
  }).map(function (p) {
    const summary = typeof bmhGetPatientFinancialSummary === 'function' ? bmhGetPatientFinancialSummary(p.bmhId) : null;
    const amount = Math.max(Number(summary?.balance || 0), Number(summary?.chargeTotal || 0), Number(p.balance || 0), 0);
    return {
      id: 'SYNTPA-' + p.bmhId,
      bmhId: p.bmhId,
      patient: p.name || '—',
      for: p.purpose || 'Cashless / TPA Case',
      amount: amount,
      approvedAmount: amount,
      status: 'pending',
      mode: 'Insurance/TPA',
      ins: p.ins || 'Insurance/TPA',
      policy: p.policy || '',
      dept: p.dept || 'ophtho',
      centre: p.centre || centre || 'CHD',
      date: p.updatedAt || p.checkinAt || p.createdAt || new Date().toISOString(),
      from: 'Reception',
      _synthetic: true
    };
  });
  return liveClaims.concat(synthetic).sort(function (a, b) { return new Date(b.date || 0) - new Date(a.date || 0); });
}

function listenPayRequests() {
  if (window._bmhPayRequestsListening) return;
  window._bmhPayRequestsListening = true;
  const centre = CURRENT_USER?.isAdmin ? null : (CURRENT_USER?.centre || 'CHD');
  fbOn('payRequests', data => {
    PAY_REQUESTS.length = 0;
    Object.values(data || {}).forEach(r => {
      if(!centre || r.centre === centre || CURRENT_USER?.isAdmin) PAY_REQUESTS.push(r);
    });
    runOneTimePendingDuesCleanup && runOneTimePendingDuesCleanup();
    bmhRunEndOfDayEegPurge && bmhRunEndOfDayEegPurge();
    // Update badge
    const nb = document.getElementById('nb-pay');
    if(nb) nb.textContent = PAY_REQUESTS.filter(r=>r.status==='pending').length;
    const activeId = getActivePageId();
    if (activeId === 'pg-reception') renderReceptionPage && renderReceptionPage();
    else if (activeId === 'pg-dashboard') renderDashboard && renderDashboard();
  });
}
function runOneTimePendingDuesCleanup() {
  const cleanupKey = 'bmh_pending_dues_cleanup_20260409';
  try {
    if (localStorage.getItem(cleanupKey) === 'done') return;
  } catch (e) {}
  const pending = (PAY_REQUESTS || []).filter(function (r) {
    return r && r.status === 'pending' && !isInsuranceLikeMode(r.mode || r.ins || '');
  });
  if (!pending.length) {
    try { localStorage.setItem(cleanupKey, 'done'); } catch (e) {}
    return;
  }
  pending.forEach(function (pr) {
    pr.status = 'cancelled';
    pr.cancelledAt = new Date().toISOString();
    pr.cancelledBy = CURRENT_USER?.name || 'System cleanup';
    try { if (window.firebase && firebase.database) firebase.database().ref('payRequests/' + pr.id).update({ status:'cancelled', cancelledAt: pr.cancelledAt, cancelledBy: pr.cancelledBy }); } catch (e) {}
  });
  try { localStorage.setItem(cleanupKey, 'done'); } catch (e) {}
  showToast('Pending dues cleaned up ✓', 's');
}

