// ── TRANSACTIONS / COLLECTIONS ───────────────────────────────
function saveTodayTransactionsToLocal() {
  try { localStorage.setItem('bmh_transactions_' + todayKey(), JSON.stringify(TRANSACTIONS || [])); } catch (e) { /* noop */ }
}
function saveTransactionToFirebase(txn) {
  const key = txn.id || fbKey();
  const exists = (TRANSACTIONS || []).find(function (row) { return row.id === key; });
  if (!exists) TRANSACTIONS.push(Object.assign({}, txn, { id: key }));
  saveTodayTransactionsToLocal();
  fbSet(`transactions/${todayKey()}/${key}`, { ...txn, id: key });
}

function deleteTransaction(txnId) {
  const t = TRANSACTIONS.find(x=>x.id===txnId);
  if(!t) { showToast('Transaction not found','w'); return; }
  const label = `₹${t.amount?.toLocaleString('en-IN')||'?'} — ${t.patient||'?'} (${t.service||'—'}, ${t.mode||'—'})`;
  
  // Check if reception user can bypass approval for amounts under 500 rupees
  if (canBypassApproval(t.amount)) {
    if(!confirm(`Delete this transaction (under ₹500)?\n${label}\nThis cannot be undone.`)) return;
    const idx = TRANSACTIONS.findIndex(x=>x.id===txnId);
    if (idx < 0) return;
    TRANSACTIONS.splice(idx,1);
    try { if(window.firebase&&firebase.database) firebase.database().ref(`transactions/${todayKey()}/${txnId}`).remove(); } catch(e){}
    fbPush&&fbPush('auditLog',{user:CURRENT_USER?.name||'Staff',role:CURRENT_USER?.role||'Staff',action:'DELETE_TXN',item:label,timestamp:new Date().toISOString()});
    showToast(`🗑️ Deleted: ${label}`,'i');
    renderCollectionDashboard&&renderCollectionDashboard(); renderReceptionPage&&renderReceptionPage();
    return;
  }
  
  // Standard approval flow for amounts 500+ or non-reception users
  if(!confirm(`Delete this transaction?\n${label}\nThis cannot be undone.`)) return;
  const idx = TRANSACTIONS.findIndex(x=>x.id===txnId);
  if (idx < 0) return;
  TRANSACTIONS.splice(idx,1);
  saveTodayTransactionsToLocal();
  try { if(window.firebase&&firebase.database) firebase.database().ref(`transactions/${todayKey()}/${txnId}`).remove(); } catch(e){}
  fbPush&&fbPush('auditLog',{user:CURRENT_USER?.name||'Staff',role:CURRENT_USER?.role||'Staff',action:'DELETE_TXN',item:label,timestamp:new Date().toISOString()});
  showToast(`🗑️ Deleted: ${label}`,'i');
  renderCollectionDashboard&&renderCollectionDashboard(); renderReceptionPage&&renderReceptionPage();
}

// ══════════════════════════════════════════════════════════════
// DELETION APPROVAL SYSTEM — non-admins request, admins approve
// Reception users can bypass approval for entries under 500 rupees
// ══════════════════════════════════════════════════════════════
window.PENDING_DELETE_REQUESTS = window.PENDING_DELETE_REQUESTS || [];
window.ALL_DELETE_REQUESTS = window.ALL_DELETE_REQUESTS || [];

function isConsultationChargeEntry(pr) {
  const txt = String(pr?.for || pr?.service || pr?.desc || '').toLowerCase();
  return /\bconsultation\b|\bconsult\b/.test(txt);
}

function isReceptionUser() {
  const role = String(CURRENT_USER?.role || '').toLowerCase();
  const centre = String(CURRENT_USER?.centre || '').toLowerCase();
  return (role === 'reception' && (centre.includes('rpr') || centre.includes('chd')));
}

function canBypassApproval(amount) {
  if (!amount) return false;
  const numericAmount = Number(amount) || 0;
  return numericAmount < 500 && isReceptionUser();
}

function showDeleteApprovalRequiredPopup() {
  alert('This deletion requires admin approval.\n\nPlease request approval. Admin can review it in Settings > Approvals and approve to delete.');
}

function requestDeletion(type, itemId, label) {
  window._delReqType  = type;
  window._delReqId    = itemId;
  window._delReqLabel = label;
  const lbl = document.getElementById('del-req-item-label');
  if (lbl) lbl.textContent = label;
  const inp = document.getElementById('del-req-reason');
  if (inp) inp.value = '';
  const modal = document.getElementById('m-delete-req');
  if (modal) {
    openM('m-delete-req');
    return;
  }
  const reason = window.prompt('This deletion requires admin approval.\n\nEnter reason for:\n' + String(label || ''));
  if (!reason || !String(reason).trim()) return;
  const reqId = 'DELREQ' + Date.now();
  const req = {
    id: reqId,
    type: window._delReqType,
    itemId: window._delReqId,
    label: window._delReqLabel,
    reason: String(reason).trim(),
    requestedBy: CURRENT_USER?.name || 'Staff',
    requestedByRole: CURRENT_USER?.role || '',
    centre: CURRENT_USER?.centre || 'CHD',
    requestedAt: new Date().toISOString(),
    status: 'pending'
  };
  PENDING_DELETE_REQUESTS.push(req);
  fbSet && fbSet('deletionRequests/' + reqId, req);
  fbPush && fbPush('auditLog', { user: req.requestedBy, role: req.requestedByRole, action: 'DELETE_REQUESTED', item: req.label, reason: req.reason, timestamp: req.requestedAt });
  showToast('🔔 Deletion request sent to admin for approval', 'i');
}

function submitDeleteRequest() {
  const reason = document.getElementById('del-req-reason')?.value?.trim();
  if(!reason) { showToast('Please enter a reason for deletion','w'); return; }
  const reqId = 'DELREQ'+Date.now();
  const req = {
    id: reqId,
    type: window._delReqType,
    itemId: window._delReqId,
    label: window._delReqLabel,
    reason,
    requestedBy: CURRENT_USER?.name||'Reception',
    requestedByRole: CURRENT_USER?.role||'Reception',
    centre: CURRENT_USER?.centre||'CHD',
    requestedAt: new Date().toISOString(),
    status: 'pending'
  };
  PENDING_DELETE_REQUESTS.push(req);
  fbSet && fbSet('deletionRequests/'+reqId, req);
  fbPush && fbPush('auditLog',{user:req.requestedBy, role:req.requestedByRole, action:'DELETE_REQUESTED', item:req.label, reason, timestamp:req.requestedAt});
  showToast('🔔 Deletion request sent to admin for approval','i');
  closeM('m-delete-req');
}

