// ── Load OT Cases from Firebase on login ─────────────────────────────────────
function loadOTCasesFromFirebase() {
  const arr = window.OT_CASES || OT_CASES;
  const localRows = loadOTCasesFromLocalStorage();
  if (localRows.length) {
    arr.length = 0;
    localRows.forEach(function (row) { arr.push(normalizeOTCaseRecord(row)); });
    renderOTListSafe && renderOTListSafe();
  }
  if(!window.FBDB) return;
  window.FBDB.ref('otCases').once('value').then(snap => {
    const data = snap.val();
    const mergedById = {};
    localRows.forEach(function (row) { if (row?.id) mergedById[row.id] = normalizeOTCaseRecord(row); });
    if (data) Object.values(data).forEach(function (c) { if (c?.id) mergedById[c.id] = normalizeOTCaseRecord(c); });
    const merged = Object.values(mergedById);
    if (!merged.length) return;
    arr.length = 0;
    merged.forEach(function (row) { arr.push(row); });
    saveOTCasesToLocalStorage();
    renderOTListSafe && renderOTListSafe();
    syncPendingOTCasesToFirebase(data ? Object.values(data) : []).then(function (results) {
      if (!Array.isArray(results)) return;
      const syncedCount = results.filter(function (r) { return r.status === 'fulfilled'; }).length;
      if (!syncedCount) return;
      const freshLocal = loadOTCasesFromLocalStorage();
      if (freshLocal.length) {
        arr.length = 0;
        freshLocal.forEach(function (row) { arr.push(normalizeOTCaseRecord(row)); });
        renderOTListSafe && renderOTListSafe();
      }
      showToast(syncedCount === 1 ? '1 pending OT case synced to database ✓' : (syncedCount + ' pending OT cases synced to database ✓'), 's');
    }).catch(function (err) {
      console.warn('OT resync error:', err);
    });
  }).catch(e => console.warn('OT load error:', e));
}
// ── Load IPD Patients from Firebase on login ──────────────────────────────────
function loadIPDPatientsFromFirebase() {
  if(!window.FBDB) return;
  window.FBDB.ref('ipdPatients').once('value').then(snap => {
    const data = snap.val();
    if(!data) return;
    const arr = window.IPD_PATIENTS || IPD_PATIENTS;
    Object.values(data).forEach(p => {
      if(!p.centre) p.centre = getEffectiveCentre() || CURRENT_USER?.centre || 'CHD';
      if(!Array.isArray(p.chartRows) || !p.chartRows.length) {
        p.chartRows = ipdDeptTemplate(normalizeDeptKeyForQueue(p.dept || p.department || 'general'), { type: p.type, procedure: p.surgery, surgery: p.surgery });
      }
      const idx = arr.findIndex(x=>x.id===p.id||x.bmhId===p.bmhId);
      if(idx >= 0) arr[idx] = Object.assign({}, arr[idx], p);
      else arr.push(p);
    });
    renderIPD && renderIPD();
    renderDocQueue && renderDocQueue();
  }).catch(e => console.warn('IPD load error:', e));
}

