// ── Drug quick search: Settings DRUG_LIBRARY + built-in DRUG_LIBRARY_FULL ───────
let rxQuickPickList = [];
// Cached drug search pool — rebuilt only when DRUG_LIBRARY changes (not on every keystroke).
let _drugSearchPoolCache = null;
let _drugSearchIndexCache = null;
function invalidateDrugSearchPoolCache() { _drugSearchPoolCache = null; _drugSearchIndexCache = null; }
function promoteMergedDrugLibraryIntoLive(rows, opts) {
  const merged = Array.isArray(rows) ? rows : [];
  if (!Array.isArray(DRUG_LIBRARY) || !merged.length || merged.length <= DRUG_LIBRARY.length) return false;
  DRUG_LIBRARY.length = 0;
  merged.forEach(function (row) { DRUG_LIBRARY.push(normalizeDrugLibraryRow(Object.assign({}, row))); });
  invalidateDrugSearchPoolCache();
  if (opts && opts.persist) saveDrugLibraryToStorage();
  try { rebuildDrugGenericDatalist && rebuildDrugGenericDatalist(); } catch (e) {}
  return true;
}
function ensureDrugLibraryHydratedForSearch() {
  try {
    if (typeof loadDrugLibraryFromStorage === 'function') {
      loadDrugLibraryFromStorage({ forceRemote: !!window.FBDB && !window._bmhDrugLibraryHydratedFromFirebase });
    }
  } catch (e) { /* noop */ }
}
function getDrugLibrarySearchPool() {
  if (_drugSearchPoolCache) return _drugSearchPoolCache;
  const live = Array.isArray(DRUG_LIBRARY) ? DRUG_LIBRARY.slice() : [];
  // Include localStorage rescue so CSV drugs show even before Firebase responds
  let rescue = [];
  try { rescue = typeof readDrugLibraryRowsFromAllLocalSources === 'function' ? readDrugLibraryRowsFromAllLocalSources() : []; } catch (e) { rescue = []; }
  // DRUG_LIBRARY_FULL seeds are already merged in via buildDrugLibrarySeedRows() inside mergeDrugLibraryRows
  let merged = [];
  try {
    merged = mergeDrugLibraryRows(live.concat(rescue));
  } catch (e) {
    console.warn('Drug library quick search pool rebuild failed', e);
    merged = Array.isArray(live) ? live : [];
  }
  _drugSearchPoolCache = Array.isArray(merged) ? merged : [];
  promoteMergedDrugLibraryIntoLive(_drugSearchPoolCache, { persist: false });
  return _drugSearchPoolCache;
}
function getDrugLibrarySearchIndex() {
  if (_drugSearchIndexCache) return _drugSearchIndexCache;
  const pool = getDrugLibrarySearchPool();
  _drugSearchIndexCache = (Array.isArray(pool) ? pool : []).map(function (d) {
    const trade = String(d.trade || d.brand || d.name || '').trim();
    const generic = String(d.generic || d.name || d.trade || '').trim();
    const company = String(d.company || '').trim();
    const type = String(d.type || '').trim();
    return {
      d: d,
      trade: trade,
      generic: generic,
      company: company,
      type: type,
      tradeLower: trade.toLowerCase(),
      genericLower: generic.toLowerCase(),
      tradeCompact: normalizeDrugSearchText(trade),
      genericCompact: normalizeDrugSearchText(generic),
      companyLower: company.toLowerCase(),
      companyCompact: normalizeDrugSearchText(company),
      typeLower: type.toLowerCase(),
      typeCompact: normalizeDrugSearchText(type),
      deptKey: normalizeDrugDeptKey(d.dept || 'All')
    };
  });
  return _drugSearchIndexCache;
}
function scoreDrugLibrarySearchEntry(entry, query, deptKey, deptLabel) {
  if (!entry || !query) return 0;
  const deptMatch = rxDrugMatchesDept(entry.d, deptKey, deptLabel);
  const q = query.toLowerCase();
  const qCompact = normalizeDrugSearchText(query);
  const startsWord = function (text) {
    return String(text || '').split(/[^a-z0-9]+/).some(function (part) { return part && part.startsWith(q); });
  };
  let score = deptMatch ? 1000 : 0;
  if (entry.tradeLower === q) score += 700;
  if (entry.genericLower === q) score += 650;
  if (entry.tradeLower.startsWith(q)) score += 420;
  if (entry.genericLower.startsWith(q)) score += 380;
  if (startsWord(entry.tradeLower)) score += 260;
  if (startsWord(entry.genericLower)) score += 240;
  if (entry.tradeLower.includes(q)) score += 180;
  if (entry.genericLower.includes(q)) score += 160;
  if (qCompact && entry.tradeCompact === qCompact) score += 620;
  if (qCompact && entry.genericCompact === qCompact) score += 580;
  if (qCompact && entry.tradeCompact.startsWith(qCompact)) score += 360;
  if (qCompact && entry.genericCompact.startsWith(qCompact)) score += 320;
  if (qCompact && entry.tradeCompact.includes(qCompact)) score += 170;
  if (qCompact && entry.genericCompact.includes(qCompact)) score += 150;
  if (entry.companyLower && entry.companyLower.includes(q)) score += 45;
  if (qCompact && entry.companyCompact && entry.companyCompact.includes(qCompact)) score += 40;
  if (entry.typeLower && entry.typeLower.includes(q)) score += 25;
  if (qCompact && entry.typeCompact && entry.typeCompact.includes(qCompact)) score += 25;
  if (deptMatch && entry.deptKey !== 'all') score += 12;
  if (entry.deptKey === 'all') score += 6;
  return score;
}

// Debounced wrapper — waits 120 ms after typing stops before running search.
let _rxQuickSearchTimer = null;
function rxQuickSearchDebounced(val) {
  clearTimeout(_rxQuickSearchTimer);
  if ((val || '').trim().length < 1) { rxQuickSearch(val); return; } // hide immediately on clear
  _rxQuickSearchTimer = setTimeout(function () { rxQuickSearch(val); }, 60);
}
window.rxQuickSearchDebounced = rxQuickSearchDebounced;
function rxQuickSearch(val) {
  ensureDrugLibraryHydratedForSearch();
  val = (val || '').trim();
  const page = document.querySelector('.page.active');
  const activeRxTab = page ? page.querySelector('.tab-content.active[id$="-rx"], .tab-content.active[id="oe-rx"]') : document.querySelector('.tab-content.active[id$="-rx"], .tab-content.active[id="oe-rx"]');
  const dd = activeRxTab ? activeRxTab.querySelector('[id="rx-quick-dropdown"]') : null;
  const targetDd = dd || document.getElementById('rx-quick-dropdown');
  if (!targetDd) return;

  if (val.length < 1) { targetDd.style.display = 'none'; rxQuickPickList = []; return; }

  const v = val.toLowerCase();
  const tabId = activeRxTab?.id?.replace('-rx', '') || 'oe';
  const deptMap = { oe: 'ophtho', obg: 'obg', psych: 'psych', skin: 'skin' };
  const deptKey = deptMap[tabId] || 'ophtho';
  const deptLabel = { oe: 'Ophthalmology', obg: 'OBG', psych: 'Neuropsychiatry', skin: 'Skin' }[tabId] || '';

  const rankedMatches = getDrugLibrarySearchIndex()
    .map(function (entry) {
      return { entry: entry, score: scoreDrugLibrarySearchEntry(entry, v, deptKey, deptLabel) };
    })
    .filter(function (row) { return row.score > 0; })
    .sort(function (a, b) {
      if (b.score !== a.score) return b.score - a.score;
      if (a.entry.trade.length !== b.entry.trade.length) return a.entry.trade.length - b.entry.trade.length;
      return a.entry.trade.localeCompare(b.entry.trade);
    });
  rxQuickPickList = rankedMatches.slice(0, 80).map(function (row) {
    return { kind: 'settings', d: row.entry.d };
  });

  if (!rxQuickPickList.length) { targetDd.style.display = 'none'; return; }

  targetDd.style.display = 'block';
  targetDd.innerHTML = rxQuickPickList.map((item, i) => {
    if (item.kind === 'settings') {
      const d = item.d;
      return `<div onclick="selectRxQuickPick(${i})" style="padding:8px 12px;cursor:pointer;border-bottom:1px solid var(--g5)" onmouseover="this.style.background='var(--blue-lt)'" onmouseout="this.style.background=''">
        <div style="font-size:10px;font-weight:800;color:var(--green);text-transform:uppercase">Settings</div>
        <div style="font-size:13px;font-weight:900;color:#1A3C6E">${d.trade}</div>
        <div style="font-size:10.5px;color:var(--g1);font-style:italic">${d.generic ? '('+d.generic+')' : ''}</div>
        <div style="font-size:10.5px;color:var(--g1)">${d.type} · ${d.freq} · ${d.dur}</div>
      </div>`;
    }
  }).join('');
}

function selectRxQuickPick(i) {
  const item = rxQuickPickList[i];
  if (!item) return;
  if (item.kind === 'settings') {
    const d = item.d;
    rxQuickSelectedDrug = { _from: 'settings', trade: d.trade, generic: d.generic, type: d.type, freq: d.freq, dur: d.dur, dept: d.dept };
    const inp = getActiveRxQuickSearchInput();
    if (inp) inp.value = d.trade;
  } else {
    rxQuickSelectedDrug = Object.assign({ _from: 'full' }, item.d);
    const inp = getActiveRxQuickSearchInput();
    if (inp) inp.value = item.d.brand || item.d.name;
  }
  const page = document.querySelector('.page.active');
  const activeRxTab = page ? page.querySelector('.tab-content.active[id$="-rx"], .tab-content.active[id="oe-rx"]') : document.querySelector('.tab-content.active[id$="-rx"], .tab-content.active[id="oe-rx"]');
  const dd = activeRxTab ? activeRxTab.querySelector('[id="rx-quick-dropdown"]') : document.getElementById('rx-quick-dropdown');
  if (dd) dd.style.display = 'none';
  addRxFromQuick();
}

function selectRxQuickDrug(idx) {
  const lib = typeof DRUG_LIBRARY_FULL !== 'undefined' ? DRUG_LIBRARY_FULL : [];
  const d = lib[idx];
  if (!d) return;
  rxQuickSelectedDrug = Object.assign({ _from: 'full' }, d);
  const inp = getActiveRxQuickSearchInput();
  if (inp) inp.value = d.brand || d.name;
  const page = document.querySelector('.page.active');
  const activeRxTab = page ? page.querySelector('.tab-content.active[id$="-rx"], .tab-content.active[id="oe-rx"]') : document.querySelector('.tab-content.active[id$="-rx"], .tab-content.active[id="oe-rx"]');
  const dd = activeRxTab ? activeRxTab.querySelector('[id="rx-quick-dropdown"]') : document.getElementById('rx-quick-dropdown');
  if (dd) dd.style.display = 'none';
  addRxFromQuick();
}

