function renderSettingsPage() {
  loadDrugLibraryFromStorage && loadDrugLibraryFromStorage({ forceRemote: !!window.FBDB && !window._bmhDrugLibraryHydratedFromFirebase });
  loadPrintLetterheadFromStorage && loadPrintLetterheadFromStorage();
  loadConsentDataOverridesFromStorage && loadConsentDataOverridesFromStorage();
  loadRxTemplatesFromStorage && loadRxTemplatesFromStorage(function () {});
  initOtFollowupTemplateUi && initOtFollowupTemplateUi();
  loadConsentTemplatesFromStorage && loadConsentTemplatesFromStorage();
  loadIolCatalogFromStorage && loadIolCatalogFromStorage();
  loadInventoryFromFirebase && loadInventoryFromFirebase();
  loadHospitalSettingsFromFirebase && loadHospitalSettingsFromFirebase();
  if (window.FBDB) {
    const localPacksTs = Number(localStorage.getItem('bmh_surgery_packs_saved_at') || 0);
    window.FBDB.ref('surgeryPacksCustom').once('value').then(function (snap) {
      const v = snap.val();
      const remoteTs = Array.isArray(v) ? 0 : Number(v && v._savedAt || 0);
      const packs = Array.isArray(v) ? v : (v && Array.isArray(v.packs) ? v.packs : null);
      if (packs && packs.length && remoteTs > localPacksTs) {
        window.BMH_CUSTOM_SURGERY_PACKS = packs.slice();
        try { localStorage.setItem('bmh_surgery_packs_custom', JSON.stringify(packs)); } catch (e) { /* noop */ }
        try { localStorage.setItem('bmh_surgery_packs_saved_at', String(remoteTs)); } catch (e) { /* noop */ }
      } else if (localPacksTs > remoteTs && Array.isArray(window.BMH_CUSTOM_SURGERY_PACKS) && window.BMH_CUSTOM_SURGERY_PACKS.length) {
        window.FBDB.ref('surgeryPacksCustom').set({ packs: window.BMH_CUSTOM_SURGERY_PACKS, _savedAt: localPacksTs }).catch(function () {});
      }
      renderSetPacksList && renderSetPacksList();
    }).catch(function () { renderSetPacksList && renderSetPacksList(); });
  } else {
    renderSetPacksList && renderSetPacksList();
  }
  renderDrCredentials && renderDrCredentials();
  renderConsentForms && renderConsentForms();
  renderChargesList && renderChargesList();
  renderSettingsDrugs && renderSettingsDrugs();
  renderSetRxTplList && renderSetRxTplList();
  renderIolCatalogList && renderIolCatalogList();
  renderConsentLibrary && renderConsentLibrary('all');
  renderStructuredConsentList && renderStructuredConsentList();
  loadCustomConsentsForSettings && loadCustomConsentsForSettings();
  const sc = document.getElementById('import-status-count');
  if(sc) sc.textContent = PATIENTS.length.toLocaleString('en-IN') + ' patients in database';
  const role = String(CURRENT_USER?.role || '');
  const isReception = role === 'Reception';
  const settingsPage = document.getElementById('pg-settings');
  if (settingsPage) {
    const explicitAllowed = Array.isArray(CURRENT_USER?.access?.settings) && CURRENT_USER.access.settings.length ? CURRENT_USER.access.settings : null;
    const allowed = explicitAllowed || (isReception
      ? ['set-doctors', 'set-procedures', 'set-consents', 'set-surgery-packs']
      : null);
    Array.from(settingsPage.querySelectorAll('.ptab')).forEach(function (tab) {
      const onclick = String(tab.getAttribute('onclick') || '');
      const match = onclick.match(/'([^']+)'/);
      const tabId = match ? match[1] : '';
      tab.style.display = (!allowed || allowed.includes(tabId)) ? '' : 'none';
    });
    Array.from(settingsPage.querySelectorAll('.tab-content')).forEach(function (panel) {
      panel.style.display = '';
      panel.classList.remove('active');
      if (allowed && !allowed.includes(panel.id)) panel.style.display = 'none';
    });
    const firstVisibleTab = Array.from(settingsPage.querySelectorAll('.ptab')).find(function (tab) { return tab.style.display !== 'none'; });
    const activeVisibleTab = Array.from(settingsPage.querySelectorAll('.ptab.active')).find(function (tab) { return tab.style.display !== 'none'; });
    settingsPage.querySelectorAll('.ptab').forEach(function (tab) {
      if (tab.style.display === 'none') tab.classList.remove('active');
    });
    const tabToActivate = activeVisibleTab || firstVisibleTab;
    if (tabToActivate) {
      const onclick = String(tabToActivate.getAttribute('onclick') || '');
      const match = onclick.match(/'([^']+)'/);
      const tabId = match ? match[1] : '';
      tabToActivate.classList.add('active');
      const panel = tabId ? document.getElementById(tabId) : null;
      if (panel && panel.style.display !== 'none') panel.classList.add('active');
    }
  }
}

