// ── Phone search in reception new patient ────────
function searchPatientByPhone(val) {
  const results = document.getElementById('rc-phone-results');
  const list    = document.getElementById('rc-phone-matches-list');
  if(!results || !list) return;

  const v = (val||'').replace(/\s/g,'');
  if(v.length < 5) { results.style.display='none'; return; }

  const matches = PATIENTS.filter(p => p.mob && p.mob.replace(/\s/g,'').includes(v)).slice(0,8);
  if(!matches.length) { results.style.display='none'; return; }

  results.style.display = 'block';
  list.innerHTML = matches.map(p => `
    <div style="display:flex;align-items:center;gap:9px;padding:9px 12px;border-bottom:1px solid var(--g5)">
      <div style="width:32px;height:32px;border-radius:50%;background:${p.color||'#1A3C6E'};color:#fff;display:flex;align-items:center;justify-content:center;font-weight:900;font-size:12px;flex-shrink:0">${p.initials||p.name[0]||'?'}</div>
      <div style="flex:1;min-width:0">
        <div style="font-weight:800;font-size:13px">${p.name}</div>
        <div style="font-size:10.5px;color:var(--g1)">${p.bmhId} · ${p.age||'?'}Y/${(p.sex||'?')[0]} · ${p.mob||'—'} · Visits:${p.visitCount||1}</div>
      </div>
      <div style="display:flex;flex-direction:column;gap:3px">
        <button class="btn btn-xs btn-gold" onclick="prefillExistingPatient('${p.bmhId}');document.getElementById('rc-phone-results').style.display='none'">✏️ Prefill</button>
        <button class="btn btn-xs btn-outline" onclick="openPatient('${p.bmhId}')">👁️ View</button>
      </div>
    </div>`).join('');
}

function selectExistingPatient(bmhId) {
  const p = PATIENTS.find(x => x.bmhId === bmhId);
  if(!p) return;
  // Close dropdown
  const r = document.getElementById('rc-phone-results');
  if(r) r.style.display='none';
  // Mark as waiting for today
  p.status = 'waiting';
  p.seen   = false;
  // Show in queue
  showToast('✅ ' + p.name + ' checked in for visit', 's');
  renderReceptionPage && renderReceptionPage();
  // Close modal if open
  const m = document.getElementById('m-np');
  if(m) m.style.display='none';
}

// ── renderDashboard — admin (finance/stock) vs clinical (doctors) ────
function renderDashboard() {
  try { updateInstallAppUi && updateInstallAppUi(); } catch (e) {}
  const today = new Date().toISOString().split('T')[0];
  const adminDateEl = document.getElementById('db-admin-date');
  if (adminDateEl && !adminDateEl.value) adminDateEl.value = today;
  const selectedDate = adminDateEl?.value || today;
  const todaysVisiblePatients = PATIENTS.filter(function (p) {
    return centreMatch(p) && patientQueueDateMatchesToday(p);
  });
  const todaySeen = todaysVisiblePatients.filter(function (p) { return isPatientMarkedSeen(p); }).length;
  const waiting = todaysVisiblePatients.filter(function (p) { return !isPatientMarkedSeen(p) && !p.queueRemoved; }).length;
  const txnDay = txnIsoDate;
  const txnOk = isCollectedTxn;
  const todayCollection = TRANSACTIONS.filter(t => txnDay(t) === today && txnOk(t)).reduce((s, t) => s + getNetTransactionAmount(t), 0);
  const selectedTxn = TRANSACTIONS.filter(t => txnDay(t) === selectedDate && txnOk(t));

  const setEl = (id, v) => { const e = document.getElementById(id); if (e) e.textContent = v; };
  const setHtml = (id, v) => { const e = document.getElementById(id); if (e) e.innerHTML = v; };
  const u = window.CURRENT_USER || CURRENT_USER;
  const currentDeptKey = normalizeDeptKeyForQueue(normalizeQueueDeptForUser(u?.dept || ''));
  const isAdminDash = !!(u && (u.isAdmin || String(u.role || '').toLowerCase() === 'admin'));
  const adm = document.getElementById('dash-view-admin');
  const cln = document.getElementById('dash-view-clinical');
  if (adm) adm.style.display = isAdminDash ? 'block' : 'none';
  if (cln) cln.style.display = isAdminDash ? 'none' : 'block';
  const tbd = document.getElementById('tb-date2');
  if (tbd) tbd.textContent = new Date().toLocaleDateString('en-IN', { weekday: 'short', day: 'numeric', month: 'short', year: 'numeric' });
  const subEl = document.getElementById('dash-subtitle');
  if (subEl) subEl.textContent = (isAdminDash ? 'Admin · overdue & stock · ' : 'Clinical · ') + (document.getElementById('tb-cp')?.textContent || '') + ' · ' + new Date().toLocaleDateString('en-IN');

  setEl('db-opd', String(todaySeen + waiting));
  setEl('db-collection', '₹' + todayCollection.toLocaleString('en-IN'));

  if (isAdminDash) {
    const selectedCollection = selectedTxn.reduce((s, t) => s + getNetTransactionAmount(t), 0);
    const dateMatch = function (iso) {
      if (!iso) return false;
      const raw = String(iso);
      return raw.slice(0, 10) === selectedDate;
    };
    const displayPts = PATIENTS.filter(function (p) { return centreMatch(p); });
    const opdCount = displayPts.filter(function (p) {
      return patientQueueDateMatchesToday(p) && (!selectedDate || localDateKey(p.seenAt || p.checkinAt || p.createdAt || p.updatedAt) === selectedDate);
    }).length;
    const surgeryCases = (window.OT_CASES || OT_CASES || []).filter(function (c) {
      return centreMatch(c) && (dateMatch(c.date) || dateMatch(c.otDate) || dateMatch(c.createdAt) || dateMatch(c.surgeryDate));
    });
    const chargeByDept = {};
    Object.keys(window.BMH_PATIENT_CHARGES || {}).forEach(function (bid) {
      const patient = PATIENTS.find(function (p) { return p.bmhId === bid; });
      if (patient && !centreMatch(patient)) return;
      (window.BMH_PATIENT_CHARGES[bid] || []).forEach(function (line) {
        const ts = String(line.ts || line.date || '');
        if (!dateMatch(ts)) return;
        const deptKey = String(line.dept || patient?.dept || 'ophtho').toLowerCase();
        if (!chargeByDept[deptKey]) chargeByDept[deptKey] = [];
        chargeByDept[deptKey].push(line);
      });
    });
    const ipdCases = (window.IPD_PATIENTS || IPD_PATIENTS || []).filter(function (p) {
      const active = (p.status || 'admitted') !== 'discharged';
      return centreMatch(p) && (selectedDate === today ? active : (dateMatch(p.admittedAt) || dateMatch(p.date) || dateMatch(p.createdAt)));
    });
    setEl('db-admin-opd', String(opdCount));
    setEl('db-admin-surgeries', String(surgeryCases.length));
    setEl('db-admin-ipd', String(ipdCases.length));
    setEl('db-admin-total-collection', '₹' + selectedCollection.toLocaleString('en-IN'));
    const summaryEl = document.getElementById('dash-admin-summary-blocks');
    const dueAlertEl = document.getElementById('dash-admin-due-alerts');
    if (summaryEl) {
      const deptMeta = [
        { key: 'ophtho', label: 'Eye', cls: 'blue', icon: '👁️' },
        { key: 'obg', label: 'OBG', cls: 'red', icon: '🤰' },
        { key: 'psych', label: 'Neuropsychiatry', cls: 'orange', icon: '🧠' },
        { key: 'skin', label: 'Skin & Cosmetology', cls: 'gold', icon: '💆' }
      ];
      const deptOpdCount = function (key) {
        return displayPts.filter(function (p) {
          return String(p.dept || '').toLowerCase() === key
            && patientQueueDateMatchesToday(p)
            && (!selectedDate || localDateKey(p.seenAt || p.checkinAt || p.createdAt || p.updatedAt) === selectedDate);
        }).length;
      };
      const deptSurgeryCount = function (key) {
        return surgeryCases.filter(function (c) { return String(c.dept || '').toLowerCase() === key; }).length;
      };
      const deptProcedureCount = function (key) {
        const lines = chargeByDept[key] || [];
        return lines.filter(function (line) {
          const cat = String(line.cat || '').toLowerCase();
          const text = [line.desc, line.name, line.kind, line.parent].join(' ').toLowerCase();
          if (cat === 'diagnostic' || cat === 'investigation') return false;
          if (cat === 'surgery' || /surgery|lscs|pmics|phaco|delivery|labour room|mtp/i.test(text)) return false;
          return true;
        }).length;
      };
      const deptCollection = function (key) {
        return selectedTxn.filter(function (t) { return String(t.dept || '').toLowerCase() === key; }).reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
      };
      const deptModeText = function (key) {
        const grouped = {};
        selectedTxn.filter(function (t) { return String(t.dept || '').toLowerCase() === key; }).forEach(function (t) {
          const mode = normalizeDashboardPaymentMode(t.mode);
          grouped[mode] = (grouped[mode] || 0) + getNetTransactionAmount(t);
        });
        return Object.entries(grouped).map(function (entry) {
          return entry[0] + ': ₹' + Number(entry[1] || 0).toLocaleString('en-IN');
        }).join(' · ') || 'No collections';
      };
      const cards = deptMeta.map(function (meta) {
        return `<div class="card" style="padding:14px;min-height:180px">
          <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px">
            <div style="font-size:13px;font-weight:900;color:var(--bmh-blue)">${meta.icon} ${meta.label}</div>
          </div>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">
            <div class="sc ${meta.cls}" style="min-height:76px"><div class="sc-lbl">OPD patients</div><div class="sc-val ${meta.cls}">${deptOpdCount(meta.key)}</div></div>
            <div class="sc ${meta.cls}" style="min-height:76px"><div class="sc-lbl">Surgeries</div><div class="sc-val ${meta.cls}">${deptSurgeryCount(meta.key)}</div></div>
            <div class="sc ${meta.cls}" style="min-height:76px"><div class="sc-lbl">Procedures</div><div class="sc-val ${meta.cls}">${deptProcedureCount(meta.key)}</div></div>
            <div class="sc ${meta.cls}" style="min-height:76px"><div class="sc-lbl">Collection</div><div class="sc-val ${meta.cls}">₹${deptCollection(meta.key).toLocaleString('en-IN')}</div></div>
          </div>
          <div style="margin-top:10px;font-size:10px;font-weight:700;color:var(--g1);line-height:1.5">${deptModeText(meta.key)}</div>
        </div>`;
      });
      const totalModes = {};
      selectedTxn.forEach(function (t) {
        const mode = normalizeDashboardPaymentMode(t.mode);
        totalModes[mode] = (totalModes[mode] || 0) + getNetTransactionAmount(t);
      });
      const totalProcedures = Object.keys(chargeByDept).reduce(function (sum, key) {
        return sum + (chargeByDept[key] || []).filter(function (line) {
          const cat = String(line.cat || '').toLowerCase();
          const text = [line.desc, line.name, line.kind, line.parent].join(' ').toLowerCase();
          if (cat === 'diagnostic' || cat === 'investigation') return false;
          if (cat === 'surgery' || /surgery|lscs|pmics|phaco|delivery|labour room|mtp/i.test(text)) return false;
          return true;
        }).length;
      }, 0);
      const totalModeText = Object.entries(totalModes).map(function (entry) {
        return entry[0] + ': ₹' + Number(entry[1] || 0).toLocaleString('en-IN');
      }).join(' · ') || 'No collections';
      const totalCard = `<div class="card" style="padding:14px;min-height:180px;border:2px solid var(--bmh-gold)">
        <div style="font-size:13px;font-weight:900;color:var(--bmh-blue);margin-bottom:10px">🏥 Hospital Total</div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">
          <div class="sc green" style="min-height:76px"><div class="sc-lbl">OPD patients</div><div class="sc-val green">${opdCount}</div></div>
          <div class="sc green" style="min-height:76px"><div class="sc-lbl">Surgeries</div><div class="sc-val green">${surgeryCases.length}</div></div>
          <div class="sc green" style="min-height:76px"><div class="sc-lbl">Procedures</div><div class="sc-val green">${totalProcedures}</div></div>
          <div class="sc green" style="min-height:76px"><div class="sc-lbl">Collection</div><div class="sc-val green">₹${selectedCollection.toLocaleString('en-IN')}</div></div>
        </div>
        <div style="margin-top:10px;font-size:10px;font-weight:700;color:var(--g1);line-height:1.5">${totalModeText}</div>
      </div>`;
      summaryEl.innerHTML = cards.join('') + totalCard;
    }
    if (dueAlertEl) {
      const end = new Date(selectedDate + 'T00:00:00');
      end.setDate(end.getDate() + 7);
      const endKey = end.toISOString().slice(0, 10);
      const dueItems = [];
      (window.BMH_VENDOR_BILLS || []).forEach(function (v) {
        const due = String(v.dueDate || '').slice(0, 10);
        if (due && due >= selectedDate && due <= endKey && bmhVendorBillOutstanding(v) > 0) {
          dueItems.push({ kind: 'Vendor Bill', name: v.vendor || 'Vendor', ref: v.invoiceNo || 'No Invoice', due: due, amount: bmhVendorBillOutstanding(v) });
        }
      });
      (window.BMH_EXPENSES || []).forEach(function (e) {
        const due = String(e.dueDate || '').slice(0, 10);
        if (due && due >= selectedDate && due <= endKey) {
          dueItems.push({ kind: 'Expense', name: e.vendor || e.desc || 'Expense', ref: e.cat || '', due: due, amount: Number(e.amount || 0) });
        }
      });
      dueAlertEl.innerHTML = dueItems.length ? `<div class="card" style="margin-top:12px"><div class="card-hd"><div><div class="card-title">Upcoming Due Alerts</div><div class="card-sub">Bills and expenses due within 7 days</div></div></div>${dueItems.map(function (d) {
        return `<div style="padding:10px 0;border-bottom:1px solid var(--g5);display:flex;justify-content:space-between;gap:10px;align-items:center;font-size:12px"><div><strong>${escapeHtmlConsent(d.name)}</strong><div style="font-size:10px;color:var(--g1)">${escapeHtmlConsent(d.kind)} · ${escapeHtmlConsent(d.ref || '')} · Due ${escapeHtmlConsent(String(d.due).replace(/-/g,'/'))}</div></div><div style="font-weight:900;color:#b55a00">₹${Number(d.amount || 0).toLocaleString('en-IN')}</div></div>`;
      }).join('')}</div>` : '';
    }
    const renderBarSet = function (values, labels, colors) {
      const max = Math.max(1, ...values);
      return '<div style="display:flex;align-items:flex-end;gap:8px;height:135px;padding:4px 2px 0">'
        + values.map(function (v, idx) {
          const h = Math.max(8, Math.round((v / max) * 100));
          return '<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:6px">'
            + '<div title="' + labels[idx] + ': ' + v + '" style="width:100%;max-width:56px;height:' + h + '%;min-height:' + (v ? 10 : 3) + 'px;background:' + (colors[idx] || 'var(--bmh-blue)') + ';border-radius:8px 8px 0 0"></div>'
            + '<div style="font-size:9px;font-weight:800;color:var(--g1);text-align:center;line-height:1.25">' + labels[idx] + '</div>'
            + '<div style="font-size:10px;font-weight:900;color:var(--tx)">' + Number(v || 0).toLocaleString('en-IN') + '</div>'
            + '</div>';
        }).join('')
        + '</div>';
    };
    const collChartEl = document.getElementById('dash-admin-chart-collection');
    const surgChartEl = document.getElementById('dash-admin-chart-surgery');
    if (collChartEl) collChartEl.innerHTML = '<div style="padding:24px 12px;color:var(--g1);font-size:12px;text-align:center">Loading collection trends…</div>';
    if (surgChartEl) surgChartEl.innerHTML = '<div style="padding:24px 12px;color:var(--g1);font-size:12px;text-align:center">Loading surgery trends…</div>';
    if (window._dashAdminChartsTimer) clearTimeout(window._dashAdminChartsTimer);
    window._dashAdminChartsTimer = setTimeout(function () {
      if (getActivePageId() !== 'pg-dashboard') return;
      const collTarget = document.getElementById('dash-admin-chart-collection');
      if (collTarget) {
        const days = Array.from({ length: 7 }).map(function (_, idx) {
          const d = new Date();
          d.setDate(d.getDate() - (6 - idx));
          const ds = d.toISOString().slice(0, 10);
          const total = TRANSACTIONS.filter(function (t) { return txnDay(t) === ds && txnOk(t) && centreMatch(t); }).reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
          return { label: d.toLocaleDateString('en-IN', { day: '2-digit', month: 'short' }), value: total };
        });
        const weeks = Array.from({ length: 6 }).map(function (_, idx) {
          const end = new Date();
          end.setDate(end.getDate() - ((5 - idx) * 7));
          const weekDates = Array.from({ length: 7 }).map(function (__unused, wd) {
            const d = new Date(end);
            d.setDate(end.getDate() - wd);
            return d.toISOString().slice(0, 10);
          });
          const total = TRANSACTIONS.filter(function (t) { return weekDates.includes(txnDay(t)) && txnOk(t) && centreMatch(t); }).reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
          return { label: 'W' + (idx + 1), value: total };
        });
        const months = Array.from({ length: 4 }).map(function (_, idx) {
          const d = new Date();
          d.setMonth(d.getMonth() - (3 - idx), 1);
          const ym = d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0');
          const total = TRANSACTIONS.filter(function (t) { return String(txnDay(t) || '').startsWith(ym) && txnOk(t) && centreMatch(t); }).reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
          return { label: d.toLocaleDateString('en-IN', { month: 'short' }), value: total };
        });
        collTarget.innerHTML = '<div style="display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:14px">'
          + '<div><div style="font-size:10px;font-weight:900;color:var(--g1);text-transform:uppercase;margin-bottom:6px">Daily</div>' + renderBarSet(days.map(function (x) { return x.value; }), days.map(function (x) { return x.label; }), days.map(function () { return 'var(--bmh-blue)'; })) + '</div>'
          + '<div><div style="font-size:10px;font-weight:900;color:var(--g1);text-transform:uppercase;margin-bottom:6px">Weekly</div>' + renderBarSet(weeks.map(function (x) { return x.value; }), weeks.map(function (x) { return x.label; }), weeks.map(function () { return 'var(--bmh-gold)'; })) + '</div>'
          + '<div><div style="font-size:10px;font-weight:900;color:var(--g1);text-transform:uppercase;margin-bottom:6px">Monthly</div>' + renderBarSet(months.map(function (x) { return x.value; }), months.map(function (x) { return x.label; }), months.map(function () { return 'var(--bmh-teal)'; })) + '</div>'
          + '</div>';
      }
      const surgTarget = document.getElementById('dash-admin-chart-surgery');
      if (surgTarget) {
        const days = Array.from({ length: 7 }).map(function (_, idx) {
          const d = new Date();
          d.setDate(d.getDate() - (6 - idx));
          const ds = d.toISOString().slice(0, 10);
          const total = (window.OT_CASES || OT_CASES || []).filter(function (c) {
            return centreMatch(c) && [c.date, c.otDate, c.createdAt, c.surgeryDate].some(function (v) { return String(v || '').slice(0, 10) === ds; });
          }).length;
          return { label: d.toLocaleDateString('en-IN', { day: '2-digit', month: 'short' }), value: total };
        });
        surgTarget.innerHTML = renderBarSet(days.map(function (x) { return x.value; }), days.map(function (x) { return x.label; }), days.map(function () { return 'var(--orange)'; }));
      }
    }, 180);
  } else {
    const todayPts = PATIENTS.filter(function (p) {
      return centreMatch(p) && normalizeDeptKeyForQueue(p.dept || '') === currentDeptKey && patientQueueDateMatchesToday(p);
    });
    const checkedIn = todayPts.filter(function (p) { return !isPatientMarkedSeen(p); }).length;
    const newPts = todayPts.filter(function (p) { return localDateKey(p.createdAt || p.registeredAt || p.checkinAt) === today; }).length;
    const oldPts = Math.max(0, todayPts.length - newPts);
    let diagToday = 0;
    let surgeryCollection = 0;
    try {
      Object.keys(window.BMH_PATIENT_CHARGES || {}).forEach(bid => {
        const pt = PATIENTS.find(function (p) { return p.bmhId === bid; });
        if (!pt || !centreMatch(pt) || normalizeDeptKeyForQueue(pt.dept || '') !== currentDeptKey) return;
        (window.BMH_PATIENT_CHARGES[bid] || []).forEach(function (l) {
          const cat = String(l.cat || '').toLowerCase();
          const txt = [l.desc, l.name, l.kind, l.parent].join(' ').toLowerCase();
          if ((cat === 'diagnostic' || cat === 'investigation') && String(l.ts || '').startsWith(today)) diagToday++;
          if ((cat === 'surgery' || /surgery|pmics|phaco|delivery|lscs|labour room|mtp|iol/.test(txt)) && String(l.ts || '').startsWith(today)) {
            surgeryCollection += Number(l.amount || l.rate || 0);
          }
        });
      });
    } catch (e) { /* noop */ }
    const todaySurgeries = (window.OT_CASES || OT_CASES || []).filter(function (c) {
      return centreMatch(c) && normalizeDeptKeyForQueue(c.dept || '') === currentDeptKey && [c.date, c.otDate, c.createdAt, c.surgeryDate].some(function (v) {
        return String(v || '').slice(0, 10) === today;
      });
    }).length;
    const deptTxnsToday = TRANSACTIONS.filter(function (t) {
      return txnDay(t) === today && txnOk(t) && centreMatch(t) && normalizeDeptKeyForQueue(t.dept || '') === currentDeptKey;
    });
    const deptSurgeryTxnsToday = deptTxnsToday.filter(function (t) { return transactionHasChargeCategory(t, 'surgery'); });

    setEl('db-cl-opd', String(todayPts.length));
    setEl('db-cl-ipd', String(newPts));
    setEl('db-cl-diag', String(oldPts));
    setEl('db-apts', String(diagToday));
    setEl('db-cl-checked', String(todaySurgeries));
    setEl('db-cl-collection', '₹' + deptTxnsToday.reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0).toLocaleString('en-IN'));
    setEl('db-pending', '₹' + deptSurgeryTxnsToday.reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0).toLocaleString('en-IN'));
    setEl('db-stock-dup', String((window.IPD_PATIENTS || IPD_PATIENTS || []).filter(function (p) {
      return centreMatch(p) && normalizeDeptKeyForQueue(p.dept || '') === currentDeptKey && (p.status || 'admitted') !== 'discharged';
    }).length));

    const modes = {};
    deptTxnsToday.forEach(function (t) {
      const m = t.mode || 'Cash';
      modes[m] = (modes[m] || 0) + getNetTransactionAmount(t);
    });
    const modeEl = document.getElementById('dash-cl-modes');
    if (modeEl) {
      modeEl.innerHTML = Object.keys(modes).length ? Object.entries(modes).map(([k, v]) => `<div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid var(--g5);font-size:12px"><span>${k}</span><strong>₹${v.toLocaleString('en-IN')}</strong></div>`).join('') : '<div style="color:var(--g1);font-size:12px">No collections recorded today</div>';
    }

    const chart = document.getElementById('dash-cl-chart-week');
    if (chart) {
      const dayTotal = (daysAgo) => {
        const d = new Date();
        d.setDate(d.getDate() - daysAgo);
        const ds = d.toISOString().slice(0, 10);
        return TRANSACTIONS.filter(t => txnDay(t) === ds && txnOk(t)).reduce((s, t) => s + getNetTransactionAmount(t), 0);
      };
      let mx = 1;
      for (let i = 0; i < 14; i++) mx = Math.max(mx, dayTotal(i));
      let html = '<div style="display:flex;align-items:flex-end;justify-content:space-between;height:120px;gap:3px">';
      for (let i = 6; i >= 0; i--) {
        const a = dayTotal(i);
        const b = dayTotal(i + 7);
        const ha = mx > 0 ? Math.round((a / mx) * 100) : 0;
        const hb = mx > 0 ? Math.round((b / mx) * 100) : 0;
        html += `<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:2px"><div style="display:flex;align-items:flex-end;justify-content:center;gap:1px;height:88px;width:100%"><div title="This week" style="flex:1;background:var(--bmh-blue);height:${Math.max(ha, 2)}%;min-height:${a ? 4 : 0}px;border-radius:3px 3px 0 0"></div><div title="Prev week" style="flex:1;background:var(--g4);height:${Math.max(hb, 2)}%;min-height:${b ? 3 : 0}px;border-radius:3px 3px 0 0;opacity:.55"></div></div><div style="font-size:8px;color:var(--g1)">-${6 - i}d</div></div>`;
      }
      html += '</div>';
      chart.innerHTML = html;
    }
    const payHtml = PAY_REQUESTS.filter(r => r.status === 'pending').slice(0, 8).map(pr => `<div style="font-size:12px;padding:7px;border-bottom:1px solid var(--g5)"><strong>${pr.patient}</strong> · ₹${(pr.amount || 0).toLocaleString('en-IN')}<div style="font-size:10px;color:var(--g1)">${pr.for || ''}</div></div>`).join('') || '<div style="color:var(--g1);font-size:12px;padding:8px">No pending payment requests</div>';
    const dp = document.getElementById('dash-pay'); if (dp) dp.innerHTML = payHtml;
    const dpc = document.getElementById('dash-pay-clinical'); if (dpc) dpc.innerHTML = payHtml;

    const todayApts = APPOINTMENTS.filter(function (a) {
      return a.date === today && centreMatch(a) && (!currentDeptKey || normalizeDeptKeyForQueue(a.dept || '') === currentDeptKey);
    });
    setEl('db-apts-lbl', 'Diagnostics');
    setEl('db-cl-opd-lbl', 'OPD today');
    setEl('db-cl-ipd-lbl', 'New patients');
    setEl('db-cl-diag-lbl', 'Old patients');
    setEl('db-cl-checked-lbl', 'Surgeries');
    setEl('db-cl-collection-lbl', 'Collection today');
    setEl('db-pending-lbl', 'Surgery collection');
    setEl('db-stock-dup-lbl', 'IPD');
    const aptList = document.getElementById('dash-apts');
    if (aptList) {
      aptList.innerHTML = todayApts.slice(0, 8).map(a => `<div style="font-size:12px;padding:5px 0;border-bottom:1px solid var(--g5)"><span style="font-weight:700">${a.patient || ''}</span> · ${a.time || ''} · ${a.doctor || ''}</div>`).join('') || '<div style="color:var(--g1);font-size:12px">No appointments today</div>';
    }
  }
}
function normalizeDashboardPaymentMode(mode) {
  const raw = String(mode || '').trim();
  const low = raw.toLowerCase();
  if (!raw) return 'Cash';
  if (/(insurance|tpa|cashless|pmjay|ayushman|cghs|echs)/i.test(low)) return 'Insurance / TPA';
  if (/upi/i.test(low)) return 'UPI';
  if (/credit/i.test(low)) return 'Credit Card';
  if (/debit/i.test(low)) return 'Debit Card';
  if (/cash/i.test(low)) return 'Cash';
  if (/card/i.test(low)) return 'Card';
  return raw;
}
function patientHasSurgeryDue(bmhId) {
  const lines = (window.BMH_PATIENT_CHARGES && window.BMH_PATIENT_CHARGES[bmhId]) || [];
  const pendingPRs = (PAY_REQUESTS || []).filter(function (r) { return r.bmhId === bmhId && r.status === 'pending'; });
  return lines.some(function (l) {
    const text = [l.cat, l.kind, l.parent, l.name, l.desc].join(' ').toLowerCase();
    return /surgery|procedure|lscs|pmics|phaco|delivery|labour room|mtp|laser|iol/.test(text);
  }) || pendingPRs.some(function (r) {
    const text = [r.for, r.service, r.mode, r.desc].join(' ').toLowerCase();
    return /surgery|procedure|lscs|pmics|phaco|delivery|labour room|mtp|laser|iol/.test(text);
  });
}
function clearAdminPatientDue(bmhId) {
  if (!CURRENT_USER?.isAdmin) { showToast('Admin access required', 'w'); return; }
  const patient = PATIENTS.find(function (p) { return p.bmhId === bmhId; });
  if (!patient) { showToast('Patient not found', 'w'); return; }
  const summary = bmhGetPatientFinancialSummary ? bmhGetPatientFinancialSummary(bmhId) : null;
  const due = Math.max(Number(patient.balance) || 0, Number(summary?.balance || 0), Number(summary?.pendingTotal || 0));
  if (due <= 0) { showToast('No due found for this patient', 'i'); return; }
  if (!confirm('Clear the due for ' + (patient.name || bmhId) + '?\n₹' + due.toLocaleString('en-IN') + '\nThis is an admin correction action.')) return;
  patient.balance = 0;
  try { if (window.firebase && firebase.database) firebase.database().ref('patients/' + bmhId + '/balance').set(0); } catch (e) {}
  (PAY_REQUESTS || []).filter(function (r) { return r.bmhId === bmhId && r.status === 'pending'; }).forEach(function (pr) {
    pr.status = 'cancelled';
    try { if (window.firebase && firebase.database) firebase.database().ref('payRequests/' + pr.id).update({ status: 'cancelled', clearedBy: CURRENT_USER?.name || 'Admin', clearedAt: new Date().toISOString() }); } catch (e) {}
  });
  fbPush && fbPush('auditLog', { user: CURRENT_USER?.name || 'Admin', role: 'Admin', action: 'CLEAR_DUE', item: (patient.name || bmhId) + ' ' + bmhId + ' ₹' + due, timestamp: new Date().toISOString() });
  showToast('Due cleared for ' + (patient.name || bmhId), 's');
  renderDashboard && renderDashboard();
  renderReceptionPage && renderReceptionPage();
}
function showAdminDashboardDetail(type, value) {
  window._adminDashDetail = { type: type, value: value || '' };
  renderDashboard && renderDashboard();
}
function renderAdminDashboardBreakdowns(selectedDate, selectedTxn, overduePts, surgeryCases, ipdCases, displayPts) {
  const fmt = function (n) { return '₹' + Number(n || 0).toLocaleString('en-IN'); };
  const modeEl = document.getElementById('dash-admin-mode-blocks');
  const deptEl = document.getElementById('dash-admin-dept-blocks');
  const groupedModes = {};
  selectedTxn.forEach(function (t) {
    const mode = normalizeDashboardPaymentMode(t.mode);
    if (!groupedModes[mode]) groupedModes[mode] = { total: 0, count: 0 };
    groupedModes[mode].total += getNetTransactionAmount(t);
    groupedModes[mode].count += 1;
  });
  if (modeEl) {
    const entries = Object.entries(groupedModes);
    modeEl.innerHTML = entries.length ? entries.map(function (entry) {
      const mode = entry[0], data = entry[1];
      return `<div class="sc blue" style="cursor:pointer" onclick="showAdminDashboardDetail('mode','${String(mode).replace(/'/g, "\\'")}')"><div class="sc-lbl">${mode}</div><div class="sc-val blue">${fmt(data.total)}</div><div class="sc-icon">${data.count}</div></div>`;
    }).join('') : '<div style="padding:12px;color:var(--g1);font-size:12px">No payments found for this date.</div>';
  }
  if (deptEl) {
    const deptMeta = [
      { key: 'ophtho', label: 'Eye', cls: 'blue' },
      { key: 'obg', label: 'OBG', cls: 'red' },
      { key: 'psych', label: 'Neuropsychiatry', cls: 'orange' },
      { key: 'skin', label: 'Skin & Cosmetology', cls: 'gold' }
    ];
    deptEl.innerHTML = deptMeta.map(function (meta) {
      const txns = selectedTxn.filter(function (t) { return String(t.dept || '').toLowerCase() === meta.key; });
      const total = txns.reduce(function (s, t) { return s + getNetTransactionAmount(t); }, 0);
      const modes = {};
      txns.forEach(function (t) {
        const m = normalizeDashboardPaymentMode(t.mode);
        modes[m] = (modes[m] || 0) + getNetTransactionAmount(t);
      });
      const modeText = Object.entries(modes).slice(0, 3).map(function (entry) {
        return entry[0] + ' ' + fmt(entry[1]);
      }).join(' · ') || 'No payments';
      return `<div class="sc ${meta.cls}" style="cursor:pointer;min-height:124px" onclick="showAdminDashboardDetail('dept','${meta.key}')"><div class="sc-lbl">${meta.label}</div><div class="sc-val ${meta.cls}">${fmt(total)}</div><div style="font-size:10px;color:var(--g1);font-weight:700;line-height:1.45">${modeText}</div></div>`;
    }).join('');
  }
}
function renderAdminDashboardDetail(selectedDate, selectedTxn, overduePts, surgeryCases, ipdCases, displayPts) {
  const titleEl = document.getElementById('dash-admin-detail-title');
  const listEl = document.getElementById('dash-admin-detail-list');
  if (!titleEl || !listEl) return;
  const detail = window._adminDashDetail || { type: 'dues' };
  const fmt = function (n) { return '₹' + Number(n || 0).toLocaleString('en-IN'); };
  const rowHtml = function (label, meta, amount, extra) {
    return `<div style="display:flex;justify-content:space-between;gap:10px;padding:8px 0;border-bottom:1px solid var(--g5)"><div style="flex:1;min-width:0"><div style="font-size:12px;font-weight:800">${label}</div><div style="font-size:10.5px;color:var(--g1)">${meta || ''}</div>${extra || ''}</div>${amount ? `<div style="font-size:12px;font-weight:900;color:var(--bmh-blue)">${amount}</div>` : ''}</div>`;
  };
  if (detail.type === 'dues') {
    titleEl.textContent = 'Outstanding dues';
    listEl.innerHTML = overduePts.length ? overduePts.map(function (p) {
      const summary = bmhGetPatientFinancialSummary ? bmhGetPatientFinancialSummary(p.bmhId) : null;
      const due = Math.max(Number(p.balance) || 0, Number(summary?.balance || 0), Number(summary?.pendingTotal || 0));
      return rowHtml(p.name + ' · ' + p.bmhId, [p.dept || '—', p.mob || p.mobile || '—'].join(' · '), fmt(due), `<div style="margin-top:6px"><button class="btn btn-red btn-xs" onclick="clearAdminPatientDue('${p.bmhId}')">Clear Due</button></div>`);
    }).join('') : '<div style="padding:14px;color:var(--g1);font-size:12px">No dues for this selection.</div>';
    return;
  }
  if (detail.type === 'mode') {
    const mode = detail.value || '';
    titleEl.textContent = mode + ' payments on ' + formatDateIN(selectedDate);
    const rows = selectedTxn.filter(function (t) { return normalizeDashboardPaymentMode(t.mode) === mode; });
    listEl.innerHTML = rows.length ? rows.map(function (t) {
      return rowHtml((t.patient || 'Patient') + ' · ' + (t.bmhId || '—'), [t.service || '—', t.dept || '—', t.time || '—'].join(' · '), fmt(getNetTransactionAmount(t)));
    }).join('') : '<div style="padding:14px;color:var(--g1);font-size:12px">No transactions for this mode.</div>';
    return;
  }
  if (detail.type === 'dept') {
    const dept = detail.value || '';
    titleEl.textContent = dept.toUpperCase() + ' collections on ' + formatDateIN(selectedDate);
    const rows = selectedTxn.filter(function (t) { return String(t.dept || '').toLowerCase() === dept; });
    listEl.innerHTML = rows.length ? rows.map(function (t) {
      return rowHtml((t.patient || 'Patient') + ' · ' + (t.bmhId || '—'), [normalizeDashboardPaymentMode(t.mode), t.service || '—', t.time || '—'].join(' · '), fmt(getNetTransactionAmount(t)));
    }).join('') : '<div style="padding:14px;color:var(--g1);font-size:12px">No transactions for this department.</div>';
    return;
  }
  if (detail.type === 'opd') {
    titleEl.textContent = 'OPD patients on ' + formatDateIN(selectedDate);
    const rows = displayPts.filter(function (p) {
      return [p.checkinAt, p.createdAt, p.seenAt].some(function (iso) { return String(iso || '').slice(0, 10) === selectedDate; });
    });
    listEl.innerHTML = rows.length ? rows.map(function (p) {
      return rowHtml(p.name + ' · ' + p.bmhId, [p.doctor || '—', p.dept || '—', p.mob || p.mobile || '—'].join(' · '), '');
    }).join('') : '<div style="padding:14px;color:var(--g1);font-size:12px">No OPD patients for this date.</div>';
    return;
  }
  if (detail.type === 'surgeries') {
    titleEl.textContent = 'Surgeries on ' + formatDateIN(selectedDate);
    listEl.innerHTML = surgeryCases.length ? surgeryCases.map(function (c) {
      return rowHtml((c.patient || c.name || 'Patient') + ' · ' + (c.bmhId || '—'), [c.procedure || c.procedureMain || '—', c.site || c.eye || '—', c.otRoom || c.room || '—'].join(' · '), '');
    }).join('') : '<div style="padding:14px;color:var(--g1);font-size:12px">No surgeries for this date.</div>';
    return;
  }
  if (detail.type === 'ipd') {
    titleEl.textContent = 'IPD patients';
    listEl.innerHTML = ipdCases.length ? ipdCases.map(function (p) {
      return rowHtml((p.name || 'Patient') + ' · ' + (p.bmhId || '—'), [p.dept || '—', p.ward || p.room || p.bed || '—', p.procedure || p.surgery || '—'].join(' · '), '');
    }).join('') : '<div style="padding:14px;color:var(--g1);font-size:12px">No IPD patients in this view.</div>';
    return;
  }
  titleEl.textContent = 'Transactions on ' + formatDateIN(selectedDate);
  listEl.innerHTML = selectedTxn.length ? selectedTxn.map(function (t) {
    return rowHtml((t.patient || 'Patient') + ' · ' + (t.bmhId || '—'), [normalizeDashboardPaymentMode(t.mode), t.service || '—', t.dept || '—'].join(' · '), fmt(getNetTransactionAmount(t)));
  }).join('') : '<div style="padding:14px;color:var(--g1);font-size:12px">No transactions for this date.</div>';
}

// ── Today's reception queue (dept filter, no sub-tab) ─────────
function getReceptionBasePts() {
  const df = window._rcDeptFilter || 'all';
  // Start with today's base patients
  let basePts = getTodayQueueBasePatients();

  // Augment with cross-referred patients for the selected dept (or all depts)
  // so reception sees the patient in every dept they've been cross-referred to
  const seen = new Set(basePts.map(function(p) { return p.bmhId; }));
  const todayKeyLocal = localDateKey(new Date());
  const xrefEntries = [];

  (PATIENTS || []).forEach(function(p) {
    if (!p || p.queueRemoved || String(p.status || '').toLowerCase() === 'removed') return;
    if (!centreMatch(p)) return;
    const xrefs = getActiveCrossRefsForPatient(p).filter(function(xr) {
      // Only include active (not yet fully seen) cross-refs
      return !xr.seenAt;
    });
    if (!xrefs.length) return;

    xrefs.forEach(function(xref) {
      const toKey = normalizeDeptKeyForQueue(xref.toDept || '');
      if (df !== 'all' && toKey !== df) return;
      const dedupeKey = String(p.bmhId || '') + '::xref::' + String(toKey || '');
      if (seen.has(dedupeKey)) return;
      seen.add(dedupeKey);
      const pendingPay = !!(xref.fee && xref.paid === false);
      xrefEntries.push(Object.assign({}, p, {
        dept: xref.toDept,
        doctor: xref.toDoctor || p.doctor,
        seen: false,
        status: pendingPay ? 'waiting' : 'waiting',
        purpose: (xref.reason ? xref.reason + ' — ' : '') + (p.purpose || ''),
        _xrefEntry: true,
        _xrefId: String(xref.id || ''),
        _xrefFromDept: xref.fromDept || '',
        _xrefFeeRequired: !!xref.fee,
        _xrefFeeAmount: Number(xref.amount || xref.feeAmount || 0) || 0,
        _xrefPendingPay: pendingPay,
        _queueKey: dedupeKey
      }));
    });
  });

  // Filter base patients by dept
  if (df !== 'all') basePts = basePts.filter(function(p) { return p.dept === df; });

  return basePts.concat(xrefEntries);
}

function computeReceptionQueuePts() {
  let pts = getReceptionBasePts();
  const sub = window._rcQueueSubtab || 'waiting';
  if(sub === 'seen') pts = pts.filter(p=>isPatientMarkedSeen(p));
  else if(sub === 'waiting') pts = pts.filter(p=>!isPatientMarkedSeen(p));
  const queueStamp = function (p) {
    const raw = p?.checkinAt || p?.createdAt || p?.registeredAt || p?.queueDate || p?.date || p?.updatedAt || '';
    if (typeof raw === 'number' && Number.isFinite(raw)) return raw;
    const text = String(raw || '').trim();
    if (!text) return 0;
    if (/^\d+$/.test(text)) return Number(text);
    const parsed = Date.parse(text);
    return Number.isFinite(parsed) ? parsed : 0;
  };
  return pts.slice().sort(function (a, b) {
    const byTime = queueStamp(a) - queueStamp(b);
    if (byTime !== 0) return byTime;
    return String(a.bmhId || '').localeCompare(String(b.bmhId || ''));
  });
}

// ── renderReceptionPage — live computed ──────────
let _renderReceptionPageTimer;
function renderReceptionPage() {
  clearTimeout(_renderReceptionPageTimer);
  _renderReceptionPageTimer = setTimeout(_renderReceptionPageImpl, 100);
}
function _renderReceptionPageImpl() {
  ensureDailyReceptionReset && ensureDailyReceptionReset();
  syncReceptionConsultationFee && syncReceptionConsultationFee();

  const list = document.getElementById('rc-exist-list');
  if(list) {
    const basePts = getReceptionBasePts();
    const summaryEl = document.getElementById('rc-queue-summary');
    if(summaryEl) {
      const depts = [{k:'all',l:'All',icon:'🏥'},{k:'ophtho',l:'Eye',icon:'👁️'},{k:'obg',l:'OBG',icon:'🤰'},{k:'psych',l:'Psych',icon:'🧠'},{k:'skin',l:'Skin',icon:'💆'}];
      summaryEl.innerHTML = depts.map(d=>{
        const cnt = d.k==='all' ? basePts.length : basePts.filter(p=>p.dept===d.k).length;
        const waiting = d.k==='all' ? basePts.filter(p=>!isPatientMarkedSeen(p)).length : basePts.filter(p=>p.dept===d.k&&!isPatientMarkedSeen(p)).length;
        return `<button onclick="filterRcByDept('${d.k}')" style="flex:1;min-width:60px;background:#fff;border:1.5px solid var(--g4);border-radius:8px;padding:6px 8px;cursor:pointer;text-align:center">
          <div style="font-size:13px">${d.icon}</div>
          <div style="font-size:11px;font-weight:800">${cnt}</div>
          <div style="font-size:9px;color:var(--g1)">${d.l}</div>
          ${waiting>0?`<div style="font-size:8px;color:var(--orange);font-weight:800">${waiting} wait</div>`:''}
        </button>`;
      }).join('');
    }
    const pts = computeReceptionQueuePts();
    if(!pts.length) {
      list.innerHTML = '<tr><td colspan="10" style="text-align:center;padding:20px;color:var(--g1);font-size:13px">No patients in this view</td></tr>';
    } else {
      list.innerHTML = pts.map((p,i)=>buildQTableRow(p,i+1,{receptionQueue:true})).join('');
    }
  }

  const prEl = document.getElementById('rc-pay-list');
  const visiblePayRequests = PAY_REQUESTS.filter(r => (r.centre || 'CHD') === getEffectiveCentre());
  if(prEl) {
    if(!visiblePayRequests.length) {
      prEl.innerHTML = '<div style="padding:16px;text-align:center;color:var(--g1);font-size:12px">No payment requests</div>';
    } else {
      prEl.innerHTML = visiblePayRequests.map(pr => payCardHtml(pr)).join('');
    }
  }

  const badge = document.getElementById('rc-pr-ct');
  if(badge) {
    const pending = visiblePayRequests.filter(r=>r.status==='pending').length;
    badge.textContent = pending + ' pending';
  }

  updateReceptionDeptSummaryTabBadge && updateReceptionDeptSummaryTabBadge();
  renderRcDeptDues && renderRcDeptDues();
  renderCollectionDashboard && renderCollectionDashboard();

  if(document.getElementById('rc-dept-summary')?.classList.contains('active')) renderDeptSummary && renderDeptSummary();
  if(document.getElementById('rc-insurance')?.classList.contains('active')) renderInsuranceTab && renderInsuranceTab();
}

